def create_sandbox(config: CreateSandboxConfig):
    env ="prd" if 'PRD' in get_app_deployment() else 'uat'
    sandbox = Sandbox.beta_create(
        template=config.template,
        metadata={
            "user_id": config.user_id,
            "user_name": config.user_name,
            "user_email": config.user_email,
            "env": env
        },
        envs={
            'SANDBOX_TIME_OUT': str(config.timeout), # for reference
        },
        timeout=config.timeout,
        auto_pause=config.auto_pause
    )

    return sandbox

async def create_sandbox_api(config: CreateSandboxConfig):
    sandbox = create_sandbox(config=config)
    return {"sandbox_id": sandbox.sandbox_id}

def list_user_sandbox(
    user_id: str
):
    env = "prd" if 'PRD' in get_app_deployment() else 'uat'
    sandboxes: list[SandboxInfo] = []

    # List running user sandboxes.
    paginator = Sandbox.list(
        limit=100,
        query=SandboxQuery(
            state=[SandboxState.RUNNING, SandboxState.PAUSED],
            metadata={
                "user_id": user_id,
                "env": env
            }
        ),
    )
    while paginator.has_next:
        items = paginator.next_items()
        sandboxes.extend(items)
    print(f'Total {len(sandboxes)}, Sandboxes {sandboxes}')
    return sandboxes

async def list_user_sandbox_api(
    user_id: str = Path(..., description='user_id')
):
    sandboxes = list_user_sandbox(user_id=user_id)
    return {"status": 'success', "sandboxes": sandboxes}

class SandboxBaseConfig(BaseModel):
    sandbox_id: str
    timeout: int = 600

class RunCommandConfig(SandboxBaseConfig):
    command: str
    request_timeout: float | None = None

def set_timeout(config: SandboxBaseConfig):
    Sandbox.set_timeout(sandbox_id=config.sandbox_id, timeout=config.timeout)
    r = Sandbox.connect(sandbox_id=config.sandbox_id).commands.run(
        cmd='echo $SANDBOX_TIME_OUT',request_timeout=config.request_timeout,
        envs={
            'SANDBOX_TIME_OUT': str(config.timeout), # for reference
        }
    )
    output = f"{r.stdout.strip()}"
    print(output)
    return output

class ConnectSandboxesConfig(BaseModel):
    sandbox_ids : list[str] = None
    timeout: int = 1800

def connect_sandboxes(config:ConnectSandboxesConfig):
    processed_list = []
    if config.sandbox_ids:
        for sandbox_id in config.sandbox_ids:
            try:
                info = Sandbox.get_info(sandbox_id=sandbox_id)
                if info.state == SandboxState.RUNNING:
                    Sandbox.connect(sandbox_id=sandbox_id, timeout=config.timeout)
                    processed_list.append({"sandbox_id": sandbox_id, "status": 'success', 'msg': f"Extend timeout for the sandbox in {config.timeout} seconds"})
                elif info.state == SandboxState.PAUSED:
                    processed_list.append({"sandbox_id": sandbox_id, "status": 'success', 'msg': f"Skip for the paused sandbox in {config.timeout} seconds"})
            except Exception as e:
                processed_list.append({"sandbox_id": sandbox_id, "status": 'failed', 'msg': f"error {e}"})
    return {'data': processed_list}

def delete_sandbox(
    sandbox_id: str = Path(..., description='sandbox_id')
):
    Sandbox.kill(sandbox_id)
    return True

async def delete_sandbox_api(
    sandbox_id: str = Path(..., description='sandbox_id')
):
    if delete_sandbox(sandbox_id=sandbox_id):
        return {"status": 'success', "delete_sandbox_id": sandbox_id}
    else:
        return {"status": 'failed'}

