def decrypt(cipher_text):
    decoded = base64.b64decode(cipher_text)
    cipher = AES.new(secret.encode("utf8"), AES.MODE_CBC, iv.encode("utf8"))
    original_bytes = cipher.decrypt(base64.b64decode(decoded))
    original_bytes = unpad(original_bytes, IV_LENGTH)
    return original_bytes.decode("utf-8")

