def check_client_timezone():
    if 'timezone_offset' not in st.session_state:
        st.session_state.timezone_offset = None
    if 'js_timezone_offset' not in st.session_state:
        st.session_state.js_timezone_offset = None
    if st.session_state.timezone_offset is None:
        try:
            # use js to get timezone_offset
            key_js_timezone_offset = 'js_timezone_offset'
            timezone_offset = get_cache_user_timezone(_key_js_timezone_offset=key_js_timezone_offset, user_id=st.session_state.userId)
            if timezone_offset is not None:
                st.session_state.timezone_offset = int(timezone_offset)
            else:
                get_cache_user_timezone.clear(_key_js_timezone_offset=key_js_timezone_offset, user_id=st.session_state.userId)
                # streamlit_js_eval(
                #     js_expressions='new Date().getTimezoneOffset()',
                #     want_output=True,
                #     key=key_js_timezone_offset
                # )

                # change to get from st.context
                st.session_state.js_timezone_offset=str(st.context.timezone_offset)
                timezone_offset = get_cache_user_timezone(_key_js_timezone_offset=key_js_timezone_offset, user_id=st.session_state.userId)
                if timezone_offset is not None:
                    st.session_state.timezone_offset = int(timezone_offset)
        except Exception as error:
            print(f"Skip extracting timezone offset, error: {error}")

