def localize_datetime(in_datetime: datetime) -> datetime:
    out_dt = in_datetime
    if in_datetime:
        if 'timezone_offset' in st.session_state and st.session_state.timezone_offset:
            offset = timezone(timedelta(minutes=-(int(st.session_state.timezone_offset))))
            in_datetime_tzinfo = in_datetime.tzinfo if in_datetime.tzinfo else timezone.utc
            out_dt = in_datetime.replace(tzinfo=in_datetime_tzinfo).astimezone(offset)
    return out_dt

