def cache_group_access_control(assistant_id):
    """
    缓存指定assistant的用户组成员映射
    返回格式: {user_id: [group_ids], ...}
    """
    from database.repository.custom_bot import retrieve_assistant_access_user_list

    # 获取assistant的访问控制列表
    access_list = retrieve_assistant_access_user_list(assistant_id)

    # 提取所有用户组
    group_ids = []
    for item in access_list:
        if item["Access_Type"] == "group":
            group_ids.append(item["Access_By_Id"])

    if not group_ids:
        return {}

    # 获取每个组的成员
    group_member_mapping = {}
    for group_id in group_ids:
        try:
            group_members = aad_get_group_members(group_id)
            for member in group_members:
                user_id = member.get('id')
                if user_id:
                    if user_id not in group_member_mapping:
                        group_member_mapping[user_id] = []
                    group_member_mapping[user_id].append(group_id)
        except Exception as e:
            print(f"Failed to get members for group {group_id}: {e}")
            continue

    return group_member_mapping

