def setup_token_auto_refresh():
    """Inject frontend JS to periodically call /.auth/refresh, keeping the Azure EasyAuth session alive."""
    import streamlit.components.v1 as components

    components.html("""
    <script>
        const REFRESH_INTERVAL_MS = 50 * 60 * 1000; // 50 minutes

        async function refreshAuthToken() {
            try {
                const resp = await fetch('/.auth/refresh');
                if (resp.ok) {
                    console.log('[Auth] Token refreshed successfully:', new Date().toLocaleString());
                } else if (resp.status === 401 || resp.status === 403) {
                    console.warn('[Auth] Token refresh unauthorized, session may have expired:', resp.status);
                } else {
                    console.warn('[Auth] Token refresh returned:', resp.status);
                }
            } catch (err) {
                console.error('[Auth] Token refresh network error:', err);
            }
        }

        // Refresh immediately on page load, then every 50 minutes
        refreshAuthToken();
        setInterval(refreshAuthToken, REFRESH_INTERVAL_MS);
    </script>
    """, height=0)

