    return [p for p in parts if p]

def custom_bot_retrieve_normal_access_for_user(user_id: str) -> list[CustomBotChat]:
    """
    返回当前用户可访问（普通聊天权限）的助手列表。
    规则：
    1. 用户权限：用户ID在 chat_access_list 中（Owner ∪ User_Admin ∪ User_Chat_Only ∪ User_Unrestricted）
    2. 组权限：用户所属组ID在受限助手的组权限中，通过现有逻辑补充
    """
    all_bots = custom_bot_retrieve_all_active_assistants_normal_access()

    try:
        # 1. 先筛选用户直接权限
        user_visible = []
        for bot in all_bots:
            if bot.chat_access_list and str(user_id) in bot.chat_access_list:
                user_visible.append(bot)

        # 2. 获取用户组权限的受限助手（沿用现有逻辑）
        group_visible = get_user_group_access_assistants(user_id)

        # 3. 合并去重
        user_visible_ids = {bot.assistant_id for bot in user_visible}
        for group_bot in group_visible:
            if group_bot.assistant_id not in user_visible_ids:
                user_visible.append(group_bot)

        return user_visible
    except Exception:
        # 兜底：若出现异常，返回空列表而不是报错
        return []

