def get_assistant_file_upload_config(assistant_id: str) -> dict:

    conn = init_connection()
    result = {
        "enable_chat_file": False,
        "chat_accepted_files_type": []
    }

    try:
        with conn:
            with conn.cursor() as cursor:
                cursor.execute(
                    "SELECT Enable_Chat_File, Chat_Accepted_Files_Type FROM Table_LFAIPortal_Assistant WHERE Assistant_Id = ?", 
                    (assistant_id,)
                )
                row = cursor.fetchone()

                if row:
                    result["enable_chat_file"] = bool(row[0]) if row[0] is not None else False

                    if row[1]:
                        result["chat_accepted_files_type"] = row[1].split(",")

        return result
    except Exception as e:
        print(f"Error getting file upload config: {str(e)}")
        return result

