        TECHPACK_INSTRUCTION_V2
    ]
    INSTRUCTION_DICT = {
        "ask_file": ASK_FILE_INSTRUCTION,
        "techpack": TECHPACK_INSTRUCTION
    }

    def __init__(self, model, instruction_option: Literal["ask_file", "techpack"]="ask_file"):
        self.CHAT_MODEL = GenerativeModel(
            model,
            system_instruction= self.INSTRUCTION_DICT.get(instruction_option)
        )
        self.CHAT_SESSION = None
        self.TEMP_CONTENT = []
        self.func_group = "LF Ask File" if instruction_option == "ask_file" else "Google Gemini"

    def create_chat_session(self, history: list[Content]):
        self.CHAT_SESSION = self.CHAT_MODEL.start_chat(history=history)

    def add_to_temp_content(self, prompt: str, files: list[UploadedFile] = None):
        temp_content = [prompt]
        if files:
            for file in files:
                document = Part.from_data(
                    mime_type=file.type,
                    data=file.getvalue())
                temp_content.append(document)
        if len(self.TEMP_CONTENT) > 0:
            self.TEMP_CONTENT = self.TEMP_CONTENT.extend(temp_content)
        else:
            self.TEMP_CONTENT = temp_content

    def get_chat_response(self, prompt: str, files: list[UploadedFile] = None):
        if not self.CHAT_SESSION:
            self.create_chat_session([])
        content: list = self.TEMP_CONTENT
        content.append(prompt)
        if files:
            for file in files:
                document = Part.from_data(
                    mime_type=file.type,
                    data=file.getvalue())
                content.append(document)
        text_response = ""
        with st.chat_message("assistant"):
            message_placeholder = st.empty()
        responses = self.CHAT_SESSION.send_message(
            content=content,
            generation_config=self.GENERATION_CONFIG,
            safety_settings=self.SAFETY_SETTINGS,
            stream=True
        )
        self.TEMP_CONTENT = []
        for chunk in responses:
            text_response += chunk.text
            message_placeholder.markdown(custom_markdown_text(text_response + "▌"))
        message_placeholder.markdown(custom_markdown_text(text_response))

    def get_chat_response_techpack(self, prompt: str, files: list[UploadedFile], techpack_images: list):
        if not self.CHAT_SESSION:
            self.create_chat_session([])
        content: list = self.TEMP_CONTENT
        content.append(prompt)
        if files:
            for file in files:
                document = Part.from_data(
                    mime_type=file.type,
                    data=file.getvalue())
                content.append(document)
        text_response = ""
        time.sleep(1)
        with st.chat_message("assistant"):
            if techpack_images:
                grid = st.columns(2)
                with grid[0]:
                    st.image(techpack_images[0])
                with grid[1]:
                    if len(techpack_images)>=2:
                        st.image(techpack_images[1])
            message_placeholder = st.empty()
        responses = self.CHAT_SESSION.send_message(
            content=content,
            generation_config=self.GENERATION_CONFIG,
            safety_settings=self.SAFETY_SETTINGS,
            stream=True
        )
        self.TEMP_CONTENT = []
        for chunk in responses:
            text_response += chunk.text
            message_placeholder.markdown(custom_markdown_text(text_response + "▌"))
        message_placeholder.markdown(custom_markdown_text(text_response))

    def get_chat_history(self):
        history = []
        if self.CHAT_SESSION:
            history = self.CHAT_SESSION.history
        return history

    def write_chat_history(self):
        from utils.chatbot_utils import st_chat_message_advanced_and_feedback
        history: list[Content] = self.get_chat_history()
        # PRINT LOG
        # f = open("demofile3.txt", "w", encoding='utf-8')
        # f.write(str(history))
        # f.close()
        log_user_input_text = ""
        for message_index, message in enumerate(history):
            # print(message.to_dict())
            if message.role == "user":
                with st.chat_message("user"):
                    # print(str(message.parts))
                    # print(len(message.parts))
                    for part in message.parts:
                        try:
                            if part.text:
                                st.markdown(custom_markdown_text(part.text))
                                log_user_input_text = str(part.text)
                                continue
                        except Exception as error:
                            len(message.parts)
                        try:
                            if part.inline_data:
                                if part.inline_data.mime_type.lower().startswith("image"):
                                    image = Image.open(io.BytesIO(part.inline_data.data))
                                    st.image(image)
                                # else:
                                    # input prompt need to contain 'File uploaded:' and in part 1 of content
                                    # try:
                                    #     file_name = message.parts[0].text.replace("File uploaded:", '').strip(' ')
                                    # except Exception as file_name_error:
                                    #     print(file_name_error)
                                    #     file_name = mimetypes.guess_extension(type=part.inline_data.mime_type, strict=True)
                                    #     if file_name:
                                    #         file_name = "temp_file"
                                    #     else:
                                    #         file_name = "temp_file" + str(file_name)
                                    # if part.inline_data.mime_type.lower() == "application/pdf":
                                    #         pdf_viewer(input=part.inline_data.data, width=400, height=500)
                                    # st.download_button("download file", data=part.inline_data.data, mime=part.inline_data.mime_type, file_name=file_name)
                                continue
                        except Exception as error:
                            print(error)
            elif message.role == "model":
                with st.chat_message("assistant"):
                    # print(str(message.parts))
                    # print("model" + str(len(message.parts)))
                    try:
                        st.markdown(custom_markdown_text(message.parts[0].text))
                        st_chat_message_advanced_and_feedback(
                            key='chatbot_message_adv_' + str(message_index),
                            text=message.parts[0].text,
                            funct_group=self.func_group,
                            funct_name="Gemini Response",
                            log_input=log_user_input_text
                        )
                    except Exception as error:
                        st.error(error)
        if len(self.TEMP_CONTENT) > 0:
            with st.chat_message("user"):
                for content_item in self.TEMP_CONTENT:
                    if isinstance(content_item, str):
                        st.markdown(content_item)
                    elif isinstance(content_item, Part):
                        content_part: Part = content_item
                        if content_part.inline_data:
                            if content_part.inline_data.mime_type.lower().startswith("image"):
                                st.image(content_part.inline_data.data)

