def get_openai_api_keys():
    """
    从数据库获取所有活跃助手的 OpenAI API Key
    """
    conn = init_connection()
    api_keys = set()  # 使用集合去重
    try:
        with conn:
            with conn.cursor() as cursor:
                cursor.execute(
                    "SELECT DISTINCT Openai_API_Key FROM Table_LFAIPortal_Assistant WHERE Assistant_Status = 'Active' AND Openai_API_Key IS NOT NULL AND Openai_API_Key != ''"
                )
                row = cursor.fetchone()
                while row:
                    api_key = row[0]
                    # 只收集以 'sk-' 开头的标准 OpenAI API key
                    if api_key and api_key.startswith('sk-'):
                        api_keys.add(api_key)
                    row = cursor.fetchone()
    except Exception as error:
        print(traceback.format_exc())
        print("Error occurred while retrieving API Key, please check the logs.")
    finally:
        conn.close()

    if not api_keys:
        print("Warning: No valid OpenAI API Key found in database (starting with 'sk-').")
        print("API Keys in database may be from other services or have incorrect format.")
        # Provide manual input option as fallback
        manual_input = input("Do you want to manually input OpenAI API Key? (y/N): ")
        if manual_input.lower() == 'y':
            manual_key = input("Please enter OpenAI API Key (starting with sk-): ").strip()
            if manual_key and manual_key.startswith('sk-'):
                api_keys.add(manual_key)
            else:
                print("Invalid API Key format, should start with 'sk-'.")

    return list(api_keys)

def list_and_delete_openai_assistants_with_bing_search():
    """
    List OpenAI assistants that contain 'bing_search' tools (including built-in tools and custom functions)
    and provide option to delete 'bing_search' tools
    """
    api_keys = get_openai_api_keys()
    if not api_keys:
        print("No available OpenAI API Key found.")
        return

    all_bing_search_assistants = []

    for api_key in api_keys:
        try:
            client = OpenAI(api_key=api_key)

            # 分页获取所有助手
            all_assistants_data = []
            after = None
            while True:
                if after:
                    assistants = client.beta.assistants.list(limit=100, after=after)
                else:
                    assistants = client.beta.assistants.list(limit=100)

                all_assistants_data.extend(assistants.data)

                # 检查是否还有更多数据
                if not assistants.has_more:
                    break

                # 获取最后一个助手的ID作为下一页的起始点
                after = assistants.data[-1].id

            print(f"Using API Key {api_key[:10]}... retrieved {len(all_assistants_data)} assistants")

            # Filter assistants that contain bing_search tools (built-in tools and custom functions)
            for assistant in all_assistants_data:
                has_bing_search = False
                tools_list = []
                function_tools = []
                matching_bing_functions = []  # Record custom functions that match bing_search

                for tool in assistant.tools:
                    if hasattr(tool, 'type'):
                        if tool.type == 'function' and hasattr(tool, 'function'):
                            # Custom function tool, record function name
                            function_name = tool.function.name
                            tools_list.append(f"function:{function_name}")
                            function_tools.append({
                                'name': function_name,
                                'description': getattr(tool.function, 'description', 'No description')
                            })
                            # Check if contains bing_search
                            if 'bing_search' in function_name.lower():
                                has_bing_search = True
                                matching_bing_functions.append({
                                    'name': function_name,
                                    'description': getattr(tool.function, 'description', 'No description')
                                })
                        else:
                            # Built-in tool
                            tools_list.append(tool.type)
                            if tool.type == 'bing_search':
                                has_bing_search = True

                if has_bing_search:
                    all_bing_search_assistants.append({
                        'id': assistant.id,
                        'name': assistant.name,
                        'model': assistant.model,
                        'tools': tools_list,
                        'function_tools': function_tools,
                        'matching_bing_functions': matching_bing_functions,  # Matching bing-related functions
                        'api_key': api_key  # Record the API Key used
                    })
        except Exception as error:
            print(f"Error occurred while querying with API Key {api_key[:10]}...: {str(error)}")
            continue

    if all_bing_search_assistants:
        print(f"Found {len(all_bing_search_assistants)} OpenAI assistants containing bing_search related tools:")
        print("-" * 100)
        for assistant in all_bing_search_assistants:
            print(f"ID: {assistant['id']}")
            print(f"Name: {assistant['name']}")
            print(f"Model: {assistant['model']}")
            print(f"Current Tools: {', '.join(assistant['tools'])}")

            # Highlight matching bing-related functions
            if assistant['matching_bing_functions']:
                print("Matching bing_search related functions:")
                for func_tool in assistant['matching_bing_functions']:
                    print(f"{func_tool['name']}: {func_tool['description']}")

            # Show other custom function tools
            other_functions = []
            for func_tool in assistant['function_tools']:
                if func_tool not in assistant['matching_bing_functions']:
                    other_functions.append(func_tool)

            if other_functions:
                print("Other custom functions:")
                for func_tool in other_functions:
                    print(f"  - {func_tool['name']}: {func_tool['description']}")

            # Calculate tool list after removal (excluding tools containing bing_search)
            remaining_tools = []
            for tool in assistant['tools']:
                if (tool != 'bing_search' and 
                    'bing_search' not in tool.lower()):
                    remaining_tools.append(tool)

            print(f"Tools After Removal: {', '.join(remaining_tools) if remaining_tools else 'No tools'}")
            print("-" * 100)

        # Ask if user wants to delete 'bing_search'
        confirm = input(f"Do you want to remove 'bing_search' tools from these {len(all_bing_search_assistants)} OpenAI assistants? (y/N): ")

        if confirm.lower() == 'y':
            update_count = 0
            for assistant_data in all_bing_search_assistants:
                try:
                    assistant_id = assistant_data['id']
                    api_key = assistant_data['api_key']
                    client = OpenAI(api_key=api_key)

                    # Get original assistant configuration to preserve complete tool definitions
                    original_assistant = client.beta.assistants.retrieve(assistant_id)

                    # Create new tool list, excluding bing-related tools
                    new_tools = []
                    removed_tools = []  # Record deleted tools

                    for tool in original_assistant.tools:
                        should_keep = True

                        if hasattr(tool, 'type'):
                            if tool.type == 'bing_search':
                                should_keep = False
                                removed_tools.append(f"Built-in tool: {tool.type}")
                            elif tool.type == 'function' and hasattr(tool, 'function'):
                                # Check if custom function name contains bing_search
                                if 'bing_search' in tool.function.name.lower():
                                    should_keep = False
                                    removed_tools.append(f"Custom function: {tool.function.name}")

                        if should_keep:
                            new_tools.append(tool)

                    if removed_tools:
                        print(f"  Removed tools: {', '.join(removed_tools)}")

                    # Update assistant
                    client.beta.assistants.update(
                        assistant_id=assistant_id,
                        tools=new_tools
                    )
                    update_count += 1
                    print(f"Updated assistant: {assistant_id} - {assistant_data['name']}")
                except Exception as error:
                    print(f"Error occurred while updating assistant {assistant_id}: {str(error)}")
                    continue

            print(f"Successfully removed 'bing_search' tools from {update_count} OpenAI assistants.")
        else:
            print("Deletion operation cancelled.")
    else:
        print("No OpenAI assistants found containing 'bing_search' tools.")

