def get_openai_assistant_files(assistant_id: str):
    url = f'https://api.openai.com/v1/assistants/{assistant_id}/files?limit=100'
    response = requests.get(url=url,  headers=headers)
    files = []
    if response.json().get("data"):
        for file_data in response.json()['data']:
            if file_data.get("id"):
                files.append(file_data['id'])
    return files

