def write_chat_history_techpack(techpack_extract_gemini_client: GoogleVertexaiChat):
    history: list[Content] = techpack_extract_gemini_client.get_chat_history()
    techpachk_pdfs = st.session_state.techpack_extract_pdf_image_dict.keys()
    techpack_img_flag = ''
    for message in history:
        if message.role == "user":
            with st.chat_message("user"):
                for part in message.parts:
                    try:
                        if part.text:
                            st.markdown(custom_markdown_text(part.text))
                            for pdf in techpachk_pdfs:
                                if pdf in part.text:
                                    techpack_img_flag = pdf
                                    break
                            continue
                    except Exception as error:
                        len(message.parts)
                    try:
                        if part.inline_data:
                            if part.inline_data.mime_type.lower().startswith("image"):
                                image = Image.open(io.BytesIO(part.inline_data.data))
                                st.image(image)
                            continue
                    except Exception as error:
                        print(error)
        elif message.role == "model":
            with st.chat_message("assistant"):
                try:
                    if techpack_img_flag:
                        techpack_imgs = st.session_state.techpack_extract_pdf_image_dict[techpack_img_flag]
                        if techpack_imgs:
                            grid = st.columns(2)
                            with grid[0]:
                                st.image(techpack_imgs[0])
                            with grid[1]:
                                if len(techpack_imgs) >= 2:
                                    st.image(techpack_imgs[1])
                    techpack_img_flag = ''
                    st.markdown(custom_markdown_text(message.parts[0].text))
                except Exception as error:
                    st.error(error)

