def _create_or_get_thread() -> str:
    """Create or get thread for the session"""
    if not st.session_state.ppt_generator_thread_id:
        thread = OPENAI_CLIENT.beta.threads.create()
        st.session_state.ppt_generator_thread_id = thread.id
    return st.session_state.ppt_generator_thread_id

def _extract_first_json(text: str) -> str | None:
    """Extract first balanced JSON object from text. Returns None if not found."""
    if not text:
        return None
    start = text.find('{')
    if start == -1:
        return None
    depth = 0
    for i in range(start, len(text)):
        ch = text[i]
        if ch == '{':
            depth += 1
        elif ch == '}':
            depth -= 1
            if depth == 0:
                return text[start:i+1]
    return None

def _default_outline_json(topic_text: str, pages: int, style: str, add_refs: bool) -> str:
    sections = [
        {"title": "Introduction", "bullets": ["Objective", "Scope", "Methodology"]},
    ]
    remaining = max(2, pages - 2)
    for idx in range(1, remaining):
        sections.append({
            "title": f"Key Insights {idx}",
            "bullets": ["Insight A", "Insight B", "Evidence/Example", "Implication"]
        })
    sections.append({"title": "Conclusion", "bullets": ["Summary", "Takeaways", "Next Steps"]})
    if add_refs:
        sections.append({"title": "References", "bullets": ["Source 1", "Source 2", "Source 3"]})
    return json.dumps({"sections": sections}, ensure_ascii=False, indent=2)

