        created_chat_thread = ChatThread(
            thread_id=thread_created.id,
            assistant_id=BOT_ASSISTANT_ID,
            user_id=st.session_state.userId,
            thread_name=None,
            thread_created_at=datetime.utcfromtimestamp(thread_created.created_at)
        )
        st.session_state[PAGE_THREAD_ID_ST_KEY] = thread_created.id
        if st.session_state[PAGE_CACHE_USER_THREAD_DIC_ST_KEY]:
            updated_dict = {created_chat_thread.thread_id:created_chat_thread}
            current_dict = st.session_state[PAGE_CACHE_USER_THREAD_DIC_ST_KEY]
            st.session_state[PAGE_CACHE_USER_THREAD_DIC_ST_KEY] = {**updated_dict, **current_dict}
        else:
