def run_streaming(in_user_message_content=None, in_model=NOT_GIVEN, tools=NOT_GIVEN, reasoning_effort: Literal["low", "medium", "high"] | None | NotGiven = NOT_GIVEN):
    # empty_help_info.empty()
    # empty_expander.empty()
    run_stream = None
    print(f"thread: {st.session_state[PAGE_THREAD_ID_ST_KEY]} ,in_user_message_content: {in_user_message_content}, model: {in_model}, tools: {tools}")
    try:
        in_messages = None
        if in_user_message_content:
            in_messages = [
                {
                    "role": "user",
                    "content": in_user_message_content,
                    "metadata" : {
                        "user_id": openai_client.user_id,
                        "user_name": openai_client.user_name,
                        "message_action": "user prompt",
                    }
                }
            ]
        run_stream = openai_client.create_run_stream(
            thread_id=st.session_state[PAGE_THREAD_ID_ST_KEY],
            model=in_model,
            additional_messages=in_messages,
            tools=tools,
            reasoning_effort=reasoning_effort
        )
        st.session_state[PAGE_MESSAGES_ST_KEY].extend(run_stream.chat_messages)
        st.session_state[PAGE_GPT_CHATBOT_RESTART_STREAMING_ST_KEY] = False
    except Exception as error:
        errMsg = str(error)
        if "Vector store" in errMsg and "is expired." in errMsg:
            if st.session_state[PAGE_GPT_CHATBOT_RESTART_STREAMING_ST_KEY]:
                raise error
            else:
                st.session_state[PAGE_GPT_CHATBOT_RESTART_STREAMING_ST_KEY] = True
                openai_client.reset_thread_vector_store(thread_id=st.session_state[PAGE_THREAD_ID_ST_KEY])
                run_streaming(in_user_message_content, in_model, tools, reasoning_effort)
                return
        # turn to run processing without streaming
        if run_stream and run_stream.current_run:
            current_run_id = run_stream.current_run.id
            with st.chat_message("assistant"):
                st.markdown("streaming response failed, try to run without streaming")
            run_processing(current_run_id, "🔄 GPT processing...", False, 3, 30)
        else:
            raise error

