def processor_batch_status_handler():
    if st.button("Refresh Status", key="btn_smart_extraction_refresh_status", width="stretch"):
        reset_data_smart_extraction_batch_list()
    if st.session_state.userName == "" or st.session_state.userId == "":
        auth.initUserState()
    if st.session_state.data_smart_extraction_batch_list == None:
        st.session_state.data_smart_extraction_batch_list = retrieve_processer_batch(user_id=st.session_state.userId, processer_type="Entity_Extraction")
        # print("retrieve_processer_batch")
    entity_processer_batch_nested_dict = st.session_state.data_smart_extraction_batch_list
    if len(entity_processer_batch_nested_dict.keys())==0:
        st.markdown("No processor batch submitted!")
    else:
        # Convert the dictionary into a DataFrame and reset the index.
        df = pd.DataFrame.from_dict(entity_processer_batch_nested_dict, orient='index').reset_index().rename(columns={'index': 'Batch ID'})
        # st.dataframe(df.set_index(df.columns[0]),use_container_width=True)
        #st.write(entity_processer_batch_nested_dict)
        # localize Requested Date Time from UTC to user's timezone
        if 'Requested Date Time' in df.columns:
            def _localize_requested(ts: str):
                try:
                    if ts is None or ts == "":
                        return ""
                    dt = datetime.strptime(ts, '%Y-%m-%d %H:%M:%S')
                    return auth.localize_datetime(dt).strftime('%Y-%m-%d %H:%M:%S')
                except Exception:
                    return ts
            df['Requested Date Time'] = df['Requested Date Time'].apply(_localize_requested)
        # localize Completed Date Time from UTC to user's timezone
        if 'Completed Date Time' in df.columns:
            def _localize_completed(ts: str):
                try:
                    if ts is None or ts == "":
                        return ""
                    dt = datetime.strptime(ts, '%Y-%m-%d %H:%M:%S')
                    return auth.localize_datetime(dt).strftime('%Y-%m-%d %H:%M:%S')
                except Exception:
                    return ts
            df['Completed Date Time'] = df['Completed Date Time'].apply(_localize_completed)
        st.dataframe(
            df,
            column_config={
                "Processer Folder": st.column_config.LinkColumn(
                    "Folder", display_text="📂", width="small"
                ),
                "Processer Name": st.column_config.TextColumn(
                    "Processor Name", width="large"
                ),
                "Email To": st.column_config.TextColumn(
                    width="medium"
                ),
                "Email Cc": st.column_config.TextColumn(
                    width="medium"
                ),
            },
            hide_index=True,
        )

def _localize_requested(ts: str):
    try:
        if ts is None or ts == "":
            return ""
        dt = datetime.strptime(ts, '%Y-%m-%d %H:%M:%S')
        return auth.localize_datetime(dt).strftime('%Y-%m-%d %H:%M:%S')
    except Exception:
        return ts

def _localize_completed(ts: str):
    try:
        if ts is None or ts == "":
            return ""
        dt = datetime.strptime(ts, '%Y-%m-%d %H:%M:%S')
        return auth.localize_datetime(dt).strftime('%Y-%m-%d %H:%M:%S')
    except Exception:
        return ts

