def check_user_access(ref_id):
    """检查用户是坦有权陝访问该Agent"""
    return ref_id in user_accessible_bot_ids

def get_access_info(ref_id, agent_name, author_id):
    """获坖访问状思和相应的显示内容"""
    try:
        if check_user_access(ref_id):
            # 生戝邮件链接
            subject = f"[{ref_id}] LF AI Portal UAT - Get Started with Agent"
            body = f"Hi Agents,\n\n"

            import urllib.parse
            mail_url = f"mailto:AIAgents@lifung.com?subject={urllib.parse.quote(subject)}&body={urllib.parse.quote(body)}"
            return {"status": "Request Access", "link": mail_url}
        else:
            # 生戝邮件链接
            subject = "LF AI Portal - Request for Agent Access"
            body = f"Hi {author_id},\n\nI would like to request access to your AI Agent:\n\nAgent Name: {agent_name}\nAgent ID: {ref_id}\n\nPurpose:  \n\nBest Regards,\n{st.session_state.userName}"

            import urllib.parse
            mail_url = f"mailto:lfaicopilot@lifung.com?subject={urllib.parse.quote(subject)}&body={urllib.parse.quote(body)}&cc=lfaicopilot@lifung.com"
            return {"status": "Request Access", "link": mail_url}
    except Exception as e:
        print(f"Error in get_access_info: {e}")
        return {"status": "Request Access", "link": ""}

def has_access_to_agent(ref_id, chat_access_control):
    """检查用户是否有权限访问该Agent"""
    # 如果chat_access_control = 'Anyone' or None，就算有access
    if chat_access_control == 'Anyone' or chat_access_control is None:
        return True
    else:
        # 如果不是Anyone，检查用户访问权限
        return check_user_access(ref_id)

def process_thumbnail_image(row):
    """处睆缩略图数杮，转杢为Streamlit ImageColumn坯以使用的格弝"""
    try:
        thumbnail_data = row.get('Thumbnail_Image')
        thumbnail_url = row.get('Thumbnail_Image_Url')
        if thumbnail_url:
            return get_azure_blob_sas_url(thumbnail_url)
        elif thumbnail_data and isinstance(thumbnail_data, bytes):
            # 将bytes数杮转杢为base64编砝的data URI
            encoded_image = base64.b64encode(thumbnail_data).decode('utf-8')
            return f"data:image/png;base64,{encoded_image}"
        else:
            # 如果没有缩略图，使用默认图片
            return None
    except Exception as e:
        print(f"Error in process_thumbnail_image: {e}")
        return None

