def func_get_user_thread():
    st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID] = retrieve_user_thread_dict(
        st.session_state.userId, st.session_state.client_assistantID)

def _reset_chat_data():
    st.session_state['thread_' + st.session_state.client_assistantID] = "-"
    st.session_state['messages_' + st.session_state.client_assistantID] = []

    # 重置Dify conversation_id（如果存在）
    conversation_id_key = 'dify_conversation_id_' + st.session_state.client_assistantID
    if conversation_id_key in st.session_state:
        st.session_state[conversation_id_key] = None

    # 重置Agent Sessions特定的客户端
    if 'agent_session_dify_client' in st.session_state:
        st.session_state.agent_session_dify_client = None
    if 'agent_session_generic_client' in st.session_state:
        st.session_state.agent_session_generic_client = None

def agent_session_create_thread_if_empty():
    auth.initUserState(redirect_url_path=agent_session_redirect_url)

    # 检查是否是 Dify 类型的助手
    if agent_session_chat and agent_session_chat.agent_type == 'dify':
        # 对于 Dify，我们使用 conversation_id 而不是 thread_id
        conversation_id_key = 'dify_conversation_id_' + st.session_state.client_assistantID
        thread_id_key = 'thread_' + st.session_state.client_assistantID

        # 如果不存在 conversation_id，我们创建一个新的会话
        if conversation_id_key not in st.session_state or not st.session_state[conversation_id_key]:
            # 初始化 Dify 客户端
            if 'agent_session_dify_client' not in st.session_state or st.session_state.agent_session_dify_client is None:
                dify_api_key = agent_session_chat.openai_api_key  # 使用 openai_api_key 字段保存 Dify API 密钥
                st.session_state.agent_session_dify_client = DifyClient(
                    api_key=dify_api_key,
                    user_id=st.session_state.userId,
                    user_name=st.session_state.userName,
                    user_email=st.session_state.userEmail if hasattr(st.session_state, 'userEmail') else None
                )

            # 创建新的 Dify 会话
            dify_client = st.session_state.agent_session_dify_client
            conversation_id = dify_client.create_conversation()
            StLogging_agent_session.append_log(log_text=f"Dify Conversation Created -> conversation_id: {conversation_id}")

            # 存储会话 ID
            st.session_state[conversation_id_key] = conversation_id
            dify_client.conversation_id = conversation_id

            # 为了兼容性，我们也设置 thread_id
            thread_id = f"sess_{str(uuid.uuid1())[:8]}"
            st.session_state[thread_id_key] = thread_id

            # 创建并存储聊天线程记录
            insert_user_thread(thread_id, datetime.now(), "Active", st.session_state.userId, st.session_state.userName, st.session_state.client_assistantID, "Agent Session")
            created_chat_thread = ChatThread(
                thread_id=thread_id,
                assistant_id=st.session_state.client_assistantID,
                user_id=st.session_state.userId,
                thread_name=None,
                thread_created_at=datetime.now()
            )

            StLogging_agent_session.append_log(log_text=f"Insert created thread into DB -> thread_id: {thread_id}")

            # 初始化消息历史
            if 'messages_' + st.session_state.client_assistantID not in st.session_state:
                st.session_state['messages_' + st.session_state.client_assistantID] = []

            # 初始化线程缓存
            if 'agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID not in st.session_state:
                st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID] = {}

            if st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID]:
                updated_dict = {created_chat_thread.thread_id:created_chat_thread}
                current_dict = st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID]
                st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID] = {**updated_dict, **current_dict}
            else:
                st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID] = {created_chat_thread.thread_id: created_chat_thread}
    elif agent_session_chat and agent_session_chat.agent_type in ['n8n','generic_api']:
        # 对于 N8n & generic_api，我们使用 thread_id
        thread_id_key = 'thread_' + st.session_state.client_assistantID

        # 如果不存在 thread_id，我们创建一个新的会话
        if thread_id_key not in st.session_state or not st.session_state[thread_id_key] or st.session_state[thread_id_key] == "-":
            # 创建新的 N8n 会话 thread_id
            thread_id = f"sess_{str(uuid.uuid1()).replace('-','')[:16]}"
            st.session_state[thread_id_key] = thread_id

            # 创建并存储聊天线程记录
            insert_user_thread(thread_id, datetime.now(), "Active", st.session_state.userId, st.session_state.userName, st.session_state.client_assistantID, "Agent Session")
            created_chat_thread = ChatThread(
                thread_id=thread_id,
                assistant_id=st.session_state.client_assistantID,
                user_id=st.session_state.userId,
                thread_name=None,
                thread_created_at=datetime.now()
            )

            StLogging_agent_session.append_log(log_text=f"Thread Created -> thread_id: {thread_id}")

            StLogging_agent_session.append_log(log_text=f"Insert created thread into DB -> thread_id: {thread_id}")

            # 初始化消息历史
            if 'messages_' + st.session_state.client_assistantID not in st.session_state:
                st.session_state['messages_' + st.session_state.client_assistantID] = []

            # 初始化线程缓存
            if 'agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID not in st.session_state:
                st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID] = {}

            if st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID]:
                updated_dict = {created_chat_thread.thread_id:created_chat_thread}
                current_dict = st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID]
                st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID] = {**updated_dict, **current_dict}
            else:
                st.session_state['agent_session_cache_user_thread_dic_' + st.session_state.client_assistantID] = {created_chat_thread.thread_id: created_chat_thread}

