                        width: 100% !important;
                    }
                    </style>
                    <div class="agent-prefix-display">agent_</div>
                """, unsafe_allow_html=True)

            with input_col:
                # 使用 value 参数来设置输入框的值，而不是尝试修改 session state
                suffix_value = st.text_input(
                    label="nickname_suffix",
                    value=st.session_state.nickname_to_fill,
                    key='edit_agent_assistant_nick_name_suffix_input',
                    placeholder="Nickname",
                    help="Only input the part after agent_",
                    label_visibility="collapsed"
                )

                # 自动将完整的昵称保存到原来的session state中
                if suffix_value is not None:
                    st.session_state.edit_agent_assistant_nick_name_input = f"agent_{suffix_value}"

                    # 实时检查昵称是否已存在（当用户手动输入时）
                    if suffix_value.strip():  # 只有当有值时才检查
                        full_nickname = f"agent_{suffix_value.strip()}"
                        nick_name_exists = check_nick_name_exists(
                            full_nickname,
                            st.session_state.selected_assistant_id
                        )

                        if nick_name_exists:
                            st.session_state.nickname_conflict_warning = f"⚠️ Nickname '{full_nickname}' already exists in database. Please choose another one."
                        else:
                            st.session_state.nickname_conflict_warning = ""
                    else:
                        # 输入框为空时，清除警告
                        st.session_state.nickname_conflict_warning = ""

        # 显示昵称冲突警告
        if st.session_state.nickname_conflict_warning:
            st.warning(st.session_state.nickname_conflict_warning)

    # 显示 AI 生成的昵称候选项 - 使用全宽显示，避免换行
    if st.session_state.generated_nickname_candidates:
        st.markdown("**AI Generated Suggestions:**")

        # 使用 st.pills 显示候选项（单选）
        selected = st.pills(
            "Select a nickname:",
            options=st.session_state.generated_nickname_candidates,
            selection_mode="single",
            key="nickname_pills_selection",
            label_visibility="collapsed"
        )

        # 当用户选择了一个候选项时
        if selected and selected != st.session_state.selected_nickname_candidate:
            st.session_state.selected_nickname_candidate = selected

            # 将选中的昵称存储到中间变量，不直接修改 text_input 的 session state
            st.session_state.nickname_to_fill = selected
            st.session_state.edit_agent_assistant_nick_name_input = f"agent_{selected}"

            # 检查数据库中是否已存在该昵称
            full_nickname = f"agent_{selected}"
            nick_name_exists = check_nick_name_exists(
                full_nickname,
                st.session_state.selected_assistant_id
            )

            if nick_name_exists:
                st.session_state.nickname_conflict_warning = f"⚠️ Nickname '{full_nickname}' already exists in database. Please choose another one."
            else:
                st.session_state.nickname_conflict_warning = ""

            st.rerun(scope="fragment")

    with col2:
        # 仅针对操作区域的按钮样式
        with st.container(key='nickname_actions'):
            st.markdown("""
                <style>
                div[class*='st-key-nickname_actions'] {
                    display: flex;
                    flex-direction: column;
                    gap: 0.5rem;
                }
                div[class*='st-key-nickname_actions'] [data-testid="stButton"] button {
                    margin-top: 15px;
                    white-space: normal;
                    line-height: 1.2;
                }
                </style>
                """, unsafe_allow_html=True)

            # 如果有昵称冲突警告，禁用 update 按钮
            is_disabled = bool(st.session_state.nickname_conflict_warning)

            # AI 生成昵称按钮
            if st.button("🤖 AI Generate", key='generate_nickname_btn', use_container_width=True, type="secondary"):
                with st.spinner("Generating..."):
                    # 获取 Agent Name 和 Description
                    agent_name = st.session_state.assistant_name
                    agent_description = st.session_state.assistant_desc

                    # 获取已有的昵称列表（去除"agent_"前缀）
                    existing_nicknames = [nick for nick in st.session_state.generated_nickname_candidates]

                    # 调用 AI 生成昵称候选项，传入已有昵称避免重复
                    candidates = generate_nickname_candidates(agent_name, agent_description, existing_nicknames)

                    if candidates:
                        # 追加新生成的昵称到现有列表
                        st.session_state.generated_nickname_candidates.extend(candidates)
                        st.session_state.selected_nickname_candidate = None
                        st.session_state.nickname_conflict_warning = ""
                        st.rerun(scope="fragment")
                    else:
                        st.error("Failed to generate nickname candidates. Please try again.")

            # Check and Update 按钮
            if st.button("Check and Update", key='check_update_nick_name_btn', use_container_width=True, disabled=is_disabled):
                # 检查昵称是否为空
                if not st.session_state.edit_agent_assistant_nick_name_input or st.session_state.edit_agent_assistant_nick_name_input.strip() == "":
                    st.session_state.nick_name_validation_status = "error"
                    st.session_state.nick_name_validation_message = "Nickname cannot be empty"
                # 检查昵称是否只是 "agent_"（后缀为空）
                elif st.session_state.edit_agent_assistant_nick_name_input.strip() == "agent_":
                    st.session_state.nick_name_validation_status = "error"
                    st.session_state.nick_name_validation_message = "Please enter a nickname after 'agent_'"
                else:
                    # 检查昵称是否已存在（排除当前助手）
                    nick_name_exists = check_nick_name_exists(
                        st.session_state.edit_agent_assistant_nick_name_input.strip(),
                        st.session_state.selected_assistant_id
                    )

                    if nick_name_exists:
                        st.session_state.nick_name_validation_status = "error"
                        st.session_state.nick_name_validation_message = "The nickname already exists, please use another nickname"
                    else:
                        # 更新昵称
                        st.session_state.assistant_nick_name = st.session_state.edit_agent_assistant_nick_name_input.strip()
                        update_assistant_nick_name_with_assistant_id(
                            st.session_state.selected_assistant_id,
                            st.session_state.edit_agent_assistant_nick_name_input.strip(),
                            st.session_state.userName,
                            st.session_state.userId
                        )
                        # 直接更新缓存中的对象
                        safe_cache_update(
                            handle_assistant_nick_name_update,
                            st.session_state.selected_assistant_id,
                            st.session_state.edit_agent_assistant_nick_name_input.strip()
                        )
                        clear_agent_dictionary_cache()  # 清除Agent Dictionary缓存
                        # 重新加载最新数据
                        st.session_state.data_assistants_dict_with_admin_access = retrieve_assistants_with_admin_access(
                            st.session_state.userId)

                        st.session_state.nick_name_validation_status = "success"
                        st.session_state.nick_name_validation_message = "Nickname updated successfully"

                        # 清空生成的候选项
                        st.session_state.generated_nickname_candidates = []
                        st.session_state.selected_nickname_candidate = None
                        st.session_state.nickname_conflict_warning = ""


    with col3:
        # 仅陝消杯区域的杝示样弝
        with st.container(key='nickname_alerts'):
            st.markdown("""
                <style>
                div[class*='st-key-nickname_alerts'] [data-testid="stAlert"] {
                    margin-top: 15px;
                }
                </style>
                """, unsafe_allow_html=True)
            # 显示验话消杯
            if st.session_state.nick_name_validation_status == "success":
                st.success(st.session_state.nick_name_validation_message)
            elif st.session_state.nick_name_validation_status == "error":
                st.error(st.session_state.nick_name_validation_message)

