def process_thumbnail_image(thumbnail_data):
    """处理缩略图数据，转换为Streamlit ImageColumn可以使用的格式"""
    if thumbnail_data and isinstance(thumbnail_data, bytes):
        # 将bytes数据转换为base64编码的data URI
        encoded_image = base64.b64encode(thumbnail_data).decode('utf-8')
        return f"data:image/png;base64,{encoded_image}"
    else:
        # 如果没有缩略图，使用默认图片
        return "./app/static/app_icon.png"

