def delete_google_file_search_document_if_needed(file_record: File):
    if getattr(file_record, 'destination', None) != 'google_file_search_store':
        return

    document_name = getattr(file_record, 'destination_path', None)
    if not document_name:
        raise Exception(
            f"Cannot delete Google File Search document for {file_record.file_name}: Destination_Path is empty"
        )

    from utils.tools.google_file_search_tool import GoogleFileSearchTool

    google_tool = GoogleFileSearchTool()
    google_tool.delete_document(document_name=document_name)
    print(f"[GoogleFileSearch] Deleted remote document for {file_record.file_id}: {document_name}")

