def check_config_changes():
    """检查配置是否有变化"""
    changes = {}

    # Name
    if 'assistant_name_input' in st.session_state and st.session_state.assistant_name_input != st.session_state.assistant_name:
        changes['name'] = st.session_state.assistant_name_input

    # Model
    if 'assistant_model_input' in st.session_state and st.session_state.assistant_model_input != st.session_state.assistant_model:
        changes['model'] = st.session_state.assistant_model_input

    # Temperature (only check when current model supports temperature)
    current_model_check = st.session_state.get('assistant_model_input', '') or ''
    if re.match(r'^gpt-4\.1', current_model_check):
        if 'assistant_temperature_input' in st.session_state and st.session_state.assistant_temperature_input != st.session_state.assistant_temperature:
            changes['temperature'] = st.session_state.assistant_temperature_input

    # Description
    if 'assistant_desc_input' in st.session_state and st.session_state.assistant_desc_input != st.session_state.assistant_desc:
        changes['description'] = st.session_state.assistant_desc_input

