            vector_store_id = custom_bot_selected.openai_vector_store_id
            if not vector_store_id:
                # 首次启用 File Search，自动创建 Vector Store
                try:
                    print("Creating Vector Store for first file search enable...")
                    created_vector_store = openai_client.create_vector_store()
                    vector_store_id = created_vector_store.id
                    # 更新数据库
                    from database.repository.custom_bot import update_vector_store_id
                    update_vector_store_id(st.session_state.selected_assistant_id, vector_store_id)
                    # 更新内存中的对象
                    custom_bot_selected.openai_vector_store_id = vector_store_id
                    print(f"Vector Store created: {vector_store_id}")
                except Exception as create_vs_error:
                    print(f"Failed to create Vector Store: {create_vs_error}")
                    print(traceback.format_exc())
                    raise

            if vector_store_id:
                try:
                    # 单文件直接用 files.create（不走 batch API，避免 SDK batch_id bug）
                    openai_client.openai_client.vector_stores.files.create(
                        vector_store_id=vector_store_id,
                        file_id=file_id,
                    )
                except Exception as vs_error:
                    print(f"Failed to add file to vector store: {vs_error}")
            # 防御性检查：确保 vector_store_files_ids 已初始化
            if custom_bot_selected.vector_store_files_ids is None:
                custom_bot_selected.vector_store_files_ids = []
            custom_bot_selected.vector_store_files_ids.append(file_id)
        else:
            # 从Vector Store移除文件
            vector_store_id = custom_bot_selected.openai_vector_store_id
            if vector_store_id:
                try:
                    openai_client.delete_vector_store_file(vector_store_id=vector_store_id, file_id=file_id)
                except Exception as vs_error:
                    print(f"Failed to remove file from vector store: {vs_error}")
            custom_bot_selected.vector_store_files_ids.remove(file_id)
    except Exception as on_change_file_search_error:
        print(traceback.format_exc())
        st.error(on_change_file_search_error)
        time.sleep(2)

def on_change_assistant_file_enable_code_interpreter(file_id: str, enable_code_interpreter: bool):
    try:
        print(f"on_change_assistant_file_enable_code_interpreter: {file_id} - {enable_code_interpreter}")
        # POC迁移：只更新本地状态和数据库，不调用OpenAI API关联到Assistant
