def check_image_url_validity(url):
    if not url or not str(url).startswith(('http://', 'https://')):
        return False

    try:
        # Only get the headers, do not need to download the body
        response = requests.head(url, timeout=3, allow_redirects=True)

        # Check if this url can be access
        if response.status_code != 200:
            return False

        # Check if it is an image in this url
        content_type = response.headers.get('Content-Type', '').lower()
        return content_type.startswith('image/')

    except Exception:
        # Any network errors (timeouts, connection failures, etc.) are regarded as invalid
        return False

class AgentRouterChat:
    def __init__(self, enable_zep: bool = False):
        self.func_group = 'Agent Router'
        self.user_id = st.session_state.userId
        self.user_name = st.session_state.userName
        self.user_email = st.session_state.userEmail
        self._chat_sessions: list[BaseChatSession] = []
        self.current_chat_session: BaseChatSession|None = None
        self.user_agents = None
        self.config_list = []
        self.agent_map = {}
        self.default_icon = "./app/static/app_icon.png"
        self.agent_ids_without_icon = []
        self.enable_zep = enable_zep
        self.zep_api_key = ""
        self.zep_user_threads = None
        self.zep_thread_messages = []
        self.current_zep_thread_id = None
        self.loading_timers = {}

    # 通用异步处理函数
    def _ensure_data_loaded(self, task_key: str, data_attr: str, worker_func):
        """
        task_key: 任务唯一标识 (如 'agent_list')
        data_attr: 要检查的数据属性名 (如 'user_agents')
        worker_func: 后台执行的数据获取函数
        """
        # 1. 如果数据已经存在 (不为 None)，说明加载完了，直接返回供界面使用
        if getattr(self, data_attr) is not None:
            # 如果计时器里还有这个key，清理掉（防止下次重置为None后立即超时）
            if task_key in self.loading_timers:
                del self.loading_timers[task_key]
                st.rerun()
            return

        # 2. 如果还没开始加载 (计时器里没有 key)，启动后台线程
        if task_key not in self.loading_timers:
            self.loading_timers[task_key] = 0
            # 使用 utils 中写好的工具启动线程
            streamlit_utils.call_func_in_st_background(worker_func)

        # 3. 启动 Fragment 进行轮询 (每2秒检查一次)
        @st.fragment(run_every=2)
        def _monitor_loading():
            # A. 检查数据是否回来了
            if getattr(self, data_attr) is not None:
                st.rerun()  # 数据有了，刷新全页

            # B. 数据还没来，更新计时
            self.loading_timers[task_key] += 2

            # C. 超时检查
            if self.loading_timers[task_key] > 7:
                # 超时强制设为空列表，停止加载
                setattr(self, data_attr, [])
                st.rerun()  # 刷新全页，显示空状态或错误

            st.info(f"Loading {task_key.replace('_', ' ')}... Please wait.", icon="⏳")

        # 在界面上显示 Spinner 并运行监控器
        #with st.spinner(f"Loading {task_key.replace('_', ' ')}..."):
        _monitor_loading()


    def get_agent_list(self):
        try:
            json = {
                "upn": self.user_email
            }

            headers = {
                "Content-Type": "application/json",
                "Ocp-Apim-Subscription-Key": os.environ.get("APIM_SUBSCRIPTION_KEY")
            }

            response = requests.post(
                url=agent_list_api_url,
                headers=headers,
                json=json,
                timeout=600
            )

            self.user_agents = response.json().get('data',[])
            # agent_list = response.json().get('data',[])
            # if agent_list:
            #     self.user_agents = self.process_agent_images_concurrently(agent_list)

        except Exception:
            print("ERROR -> get_agent_list")
            print(traceback.format_exc())
            self.user_agents = []


    def async_get_agent_list(self):
        self._ensure_data_loaded('agent_list', 'user_agents', self.get_agent_list)


    def update_config_list(self, user_id, config_list):
        update_list = []
        # construct agent map, key is agent id and value is agent object
        if self.user_agents and not self.agent_map:
            for agent in self.user_agents:
                self.agent_map[agent.get('Ref_Id')] = agent

        if config_list:
            # if agents allow route have been changed, append the agent to update list
            for agent in config_list:
                agent_id = agent.get('Agent_Id')
                if agent.get('Allow_Route') != self.agent_map[agent_id].get('Allow_Route'):
                    update_list.append(agent)

        if update_list:
            try:
                json = {
                    "upn": self.user_id,
                    "config_list": update_list
                }

                headers = {
                    "Content-Type": "application/json",
                    "Ocp-Apim-Subscription-Key": os.environ.get("APIM_SUBSCRIPTION_KEY")
                }

                response = requests.post(
                    url=config_router_api_url,
                    headers=headers,
                    json=json,
                    timeout=600
                )

                if response.status_code == 200:
                    self.config_list = response.json().get('new_config_list', [])
                    self.user_agents = response.json().get('new_agent_list')
                    for agent in update_list:
                        agent_id = agent.get('Agent_Id')
                        self.agent_map[agent_id]['Allow_Route'] = agent.get('Allow_Route')
                    # for agent in self.user_agents:
                    #     if agent.get('Ref_Id') in self.agent_ids_without_icon:
                    #         agent['Thumbnail_Image_Url'] = self.default_icon

                return response
            except Exception:
                print("ERROR -> update_config_list")
                print(traceback.format_exc())
                self.config_list = []
                return False
        else:
            return {"status_code": 304}


    def process_agent_images_concurrently(self, agents):
        """
        Concurrently verify the image urls of all agents. If it is a valid image, keep the original URL. Otherwise, replace it with the default icon.
        """
        # Define a single processing function
        def validate_single_agent(agent):
            original_url = agent.get('Thumbnail_Image_Url')
            # If it is a valid image, keep the original URL. Otherwise, replace it with the default icon.
            if original_url and check_image_url_validity(original_url):
                pass
            else:
                agent['Thumbnail_Image_Url'] = self.default_icon
                self.agent_ids_without_icon.append(agent['Ref_Id'])
            return agent

        # Use the thread pool for concurrent processing (it is recommended that max_workers be set to 10-20, depending on network conditions)
        with concurrent.futures.ThreadPoolExecutor(max_workers=10) as executor:
            # The map will maintain the order of the input list
            processed_agents = list(executor.map(validate_single_agent, agents))

        return processed_agents


    def write_chat_history(self):
        if self.current_chat_session and self.current_chat_session.chat_history:
            for message in self.current_chat_session.chat_history:
                # print(f"message format: {message}")
