    def generate_content(self, prompt: str, files: list[UploadedFile] = None):
        if not self.current_chat_session:
            self.current_chat_session = BaseChatSession()
            self._chat_sessions.append(self.current_chat_session)

        if not prompt:
            prompt = 'Upload file(s)'
        attachments = []
        if files:
            for file in files:
                file_id = uuid.uuid1()
                attachments.append(
                    {
                        "id": file_id,
