                    }
                )
                self.current_chat_session.temp_files.append(
                    {
                        "id": file_id,
                        "file_name": file.name,
                        "mime_type": file.type,
                        "file_data": file.getvalue()
                    }
                )

        self.current_chat_session.chat_history.append(
            {
