    def convert_zep_message_format(self, zep_msg):
        role = zep_msg.get('role', '')
        content = zep_msg.get('content', '')
        zep_uuid = zep_msg.get('uuid', '')
        current_role = "user" if role == "user" else "agent"

        return {
            "uuid": zep_uuid,
            "role": current_role,
            "message_body":{
                "contentType": "markdown",
                "content": content
            },
            "attachments": []
        }


    def zep_get_user_threads(self):
        try:
            json = {
                "upn": self.user_email,
                "action": "zep_get_user_threads"
            }

            headers = {
                "Content-Type": "application/json",
                "Ocp-Apim-Subscription-Key": os.environ.get("APIM_SUBSCRIPTION_KEY")
            }

            response = requests.post(
                url=aiportal_api_url,
                headers=headers,
                json=json,
                timeout=600
            )

            if response.status_code == 200:
                self.zep_user_threads = response.json().get('response_body',[])
                # print(f"Zep threads: {self.zep_user_threads}")

        except Exception:
            print("ERROR -> zep_get_user_threads")
            print(traceback.format_exc())
            self.zep_user_threads = []


    def zep_get_thread_messages(self, thread_id):
        try:
            json = {
                "upn": self.user_email,
                "action": "zep_get_thread_messages",
                "thread_id": thread_id
            }

            headers = {
                "Content-Type": "application/json",
                "Ocp-Apim-Subscription-Key": os.environ.get("APIM_SUBSCRIPTION_KEY")
            }

            response = requests.post(
                url=aiportal_api_url,
                headers=headers,
                json=json,
                timeout=600
            )

            if response.status_code == 200:
                self.zep_thread_messages = response.json().get('response_body', []).get('messages', [])
                raw_messages = response.json().get('response_body', []).get('messages', [])

                zep_session = BaseChatSession(session_name=f"{thread_id}", zep_thread_id=thread_id)

                # 转换数据
                for msg in raw_messages:
                    current_msg = self.convert_zep_message_format(msg)
                    zep_session.chat_history.append(current_msg)

                # 设置为当前会话
                self.current_chat_session = zep_session
                # print(f"Zep current chat session: {self.current_chat_session.chat_history}")

        except Exception:
            print("ERROR -> zep_get_thread_messages")
            print(traceback.format_exc())
            self.zep_thread_messages = []

