class SearchStoreItem:

    def __init__(self, user_id, user_name):
        self.user_id = user_id
        self.user_name = user_name
        self.user_store_items_react = get_cache_data_user_store_item_react(user_id=user_id)

    @staticmethod
    def get_store_items_custom_bot():
        return get_cache_resource_store_items_custom_bot()

    @staticmethod
    def get_store_items_artifact():
        return get_cache_resource_store_items_artifact()

    @staticmethod
    def search_cache_resource_store_items(input_store_items: list[StoreItem], search_keyword: str):
        output_store_items = [e for e in input_store_items if search_keyword in str(e.name).lower()]
        return output_store_items

    @staticmethod
    def filter_store_items(input_store_items:list[StoreItem], category_list: list[str], og_list: list[str] = None, order: LITERAL_ORDERS = None, reverse: bool = False):
        def func_order_store_items_name(store_item: StoreItem):
            return store_item.name

        def func_order_store_items_recently_updated(store_item: StoreItem):
            return store_item.updated_on

        def func_order_store_items_recently_released(store_item: StoreItem):
            return store_item.released_on

        def func_order_store_items_react_count(store_item: StoreItem):
            return store_item.react_count

        category_filter_result = [e for e in input_store_items if e.category in category_list] if category_list else input_store_items
        # type_filter_result = [e for e in category_filter_result if e.type in types] if types else category_filter_result

        output_store_items = [e for e in input_store_items if e.operating_group in og_list] if og_list else category_filter_result
        match order:
            case "Name":
                output_store_items.sort(key=func_order_store_items_name, reverse=reverse)
            case "Recently updated":
                output_store_items.sort(key=func_order_store_items_recently_updated, reverse=False if reverse else True)
            case "Recently released":
                output_store_items.sort(key=func_order_store_items_recently_released, reverse=False if reverse else True)
            case "Popularity":
                output_store_items.sort(key=func_order_store_items_react_count, reverse=False if reverse else True)
            case _:
                output_store_items.sort(key=func_order_store_items_recently_released, reverse=False if reverse else True)

        return output_store_items

    def add_store_item_react(self, store_item: StoreItem, react_type: LITERAL_REACT_TYPE):
        '''
        :return: temp created store_item_react
        '''
        created_react_id = insert_store_item_react(
            store_item_id=store_item.id,
            react_type=react_type,
            react_by_id=self.user_id,
            react_by=self.user_name
        )

        get_cache_data_user_store_item_react.clear()
        temp_created_store_item_react = UserStoreItemReact(
            react_id=created_react_id,
            store_item_id=store_item.id,
            react_type=react_type,
            react_on=datetime.utcnow()
        )
        self.user_store_items_react.append(temp_created_store_item_react)
        store_item.react_count = store_item.react_count + 1

    def remove_store_item_react(self, user_store_item_react: UserStoreItemReact, store_item: StoreItem):
        delete_store_item_react(react_id=user_store_item_react.react_id)
        print(f"Unlike - store_item_id {user_store_item_react.store_item_id} by {self.user_name}")
        get_cache_data_user_store_item_react.clear()
        self.user_store_items_react.remove(user_store_item_react)
        store_item.react_count = store_item.react_count - 1

