class APIMUtils:
    def __init__(self):
        self.base_url = os.environ.get("APIM_BASE_URL", "")
        self.subscription_id = os.environ.get("APIM_SUBSCRIPTION_ID", "")
        self.resource_group = os.environ.get("APIM_RESOURCE_GROUP", "")
        self.service_name = os.environ.get("APIM_SERVICE_NAME", "")
        self.product_name = os.environ.get("APIM_PRODUCT_NAME", "")
        self.api_version = os.environ.get("APIM_API_VERSION", "")
        self.access_token = self._get_apim_access_token()

    def _get_apim_access_token(self) -> str:
        tenant_id = os.environ.get("AAD_Tenant_ID", "")
        client_id = os.environ.get("AAD_Client_ID", "")
        client_secret = os.environ.get("AAD_Client_Secret", "")
        return get_apim_access_token(tenant_id, client_id, client_secret)

    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None, headers: Optional[dict] = None) -> Dict[str, Any]:
        """发送HTTP请求到APIM管理API，支持自定义headers"""
        url = f"{self.base_url}{endpoint}"
        auth_header = self.access_token
        if auth_header and not auth_header.startswith("Bearer "):
            auth_header = f"Bearer {auth_header}"
        default_headers = {
            "Authorization": auth_header,
            "Content-Type": "application/json"
        }
        if headers:
            default_headers.update(headers)
        headers = default_headers
        try:
            if method.upper() == "GET":
                response = requests.get(url, headers=headers)
            elif method.upper() == "PUT":
                response = requests.put(url, headers=headers, json=data)
            elif method.upper() == "POST":
                response = requests.post(url, headers=headers, json=data)
            elif method.upper() == "DELETE":
                response = requests.delete(url, headers=headers)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")

            response.raise_for_status()
            return response.json() if response.content else {}

        except requests.exceptions.RequestException as e:
            raise Exception(f"APIM API request failed: {str(e)}")

    def list_users(self) -> List[Dict[str, Any]]:
        """列出APIM中的所有用户"""
        endpoint = f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/users?api-version={self.api_version}"
        response = self._make_request("GET", endpoint)
        return response.get("value", [])

    def get_user_by_email(self, email: str) -> Optional[Dict[str, Any]]:
        """根据邮箱地址查找APIM用户"""
        users = self.list_users()
        # 首先尝试原始邮箱
        for user in users:
            if user.get("properties", {}).get("email") == email:
                return user

        # 如果没查到，将邮箱转换为小写再试一次
        email_lower = email.lower()
        for user in users:
            if user.get("properties", {}).get("email").lower() == email_lower:
                return user

        return None

    def create_user(self, user_id: str, first_name: str, last_name: str, email: str) -> Dict[str, Any]:
        """在APIM中创建用户"""
        endpoint = f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/users/{user_id}?notify=false&api-version={self.api_version}"

        data = {
            "properties": {
                "firstName": first_name,
                "lastName": last_name,
                "email": email,
                "confirmation": "signup"
            }
        }

        return self._make_request("PUT", endpoint, data)

    def create_subscription(self, subscription_id: str, user_id: str, display_name: str) -> Dict[str, Any]:
        """创建APIM订阅"""
        endpoint = f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/subscriptions/{subscription_id}?notify=false&api-version={self.api_version}"

        data = {
            "properties": {
                "ownerId": f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/users/{user_id}",
                "scope": f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/products/{self.product_name}",
                "displayName": display_name
            }
        }

        return self._make_request("PUT", endpoint, data)

    def list_subscription_secrets(self, subscription_id: str) -> Dict[str, Any]:
        """获取订阅的密钥"""
        endpoint = f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/subscriptions/{subscription_id}/listSecrets?api-version={self.api_version}"

        return self._make_request("POST", endpoint)

    def delete_subscription(self, subscription_id: str) -> None:
        """删除APIM订阅"""
        endpoint = f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/subscriptions/{subscription_id}?api-version={self.api_version}"

        self._make_request("DELETE", endpoint)

    def regenerate_primary_key(self, subscription_id: str) -> Dict[str, Any]:
        """单独重置主密钥"""
        endpoint = f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/subscriptions/{subscription_id}/regeneratePrimaryKey?api-version={self.api_version}"
        return self._make_request("POST", endpoint)

    def regenerate_secondary_key(self, subscription_id: str) -> Dict[str, Any]:
        """单独重置副密钥"""
        endpoint = f"/subscriptions/{self.subscription_id}/resourceGroups/{self.resource_group}/providers/Microsoft.ApiManagement/service/{self.service_name}/subscriptions/{subscription_id}/regenerateSecondaryKey?api-version={self.api_version}"
        return self._make_request("POST", endpoint)


    def generate_subscription_id(self, user_name: str) -> str:
        """生成订阅ID，使用动态产品组名称"""
        # 将用户名转换为小写，用连字符替换空格和下划线
        formatted_name = user_name.lower().replace(" ", "-").replace("_", "-")
        # 使用环境变量中的产品名称，如果没有则使用默认值
        product_name = self.product_name

        return f"{product_name}-{formatted_name}"

