def delete_blob_from_url(blob_url: str) -> bool:
    """
    Deletes a blob given its full URL.
    """
    if not blob_url:
        return False

    account_name = os.environ.get("AZURE_BLOB_ACCOUNT_NAME")
    container_name = os.environ.get("AZURE_BLOB_CONTAINER_NAME")
    sas_token = os.environ.get("AZURE_BLOB_SAS_TOKEN")

    if not all([account_name, container_name, sas_token]):
        print("Azure Blob configuration missing for delete")
        return False

    # Extract blob path from URL
    # URL format: https://{account_name}.blob.core.windows.net/{container_name}/{blob_path}
    base_url = f"https://{account_name}.blob.core.windows.net/{container_name}/"

    if not blob_url.startswith(base_url):
        # Try to handle cases where URL might have SAS token or different format if possible,
        # but for now assume standard format generated by this app.
        # If it doesn't match, we might need to parse it more robustly.
        try:
            from urllib.parse import urlparse
            parsed = urlparse(blob_url)
            if parsed.netloc == f"{account_name}.blob.core.windows.net":
                # path is /container_name/blob_path
                path_parts = parsed.path.lstrip('/').split('/', 1)
                if len(path_parts) == 2 and path_parts[0] == container_name:
                    blob_path = path_parts[1]
                else:
                    print(f"Could not extract blob path from URL: {blob_url}")
                    return False
            else:
                print(f"URL does not match account: {blob_url}")
                return False
        except Exception as e:
            print(f"Error parsing URL {blob_url}: {e}")
            return False
    else:
        blob_path = blob_url[len(base_url):]
        # Remove query parameters if any (though clean URL shouldn't have them)
        if "?" in blob_path:
            blob_path = blob_path.split("?")[0]

    url = f"https://{account_name}.blob.core.windows.net/{container_name}/{blob_path}?{sas_token}"

    try:
        resp = requests.delete(url)
        if resp.status_code in (200, 202):
            print(f"Successfully deleted blob: {blob_path}")
            return True
        elif resp.status_code == 404:
            print(f"Blob not found (already deleted?): {blob_path}")
            return True
        else:
            print(f"Delete failed: {resp.status_code} {resp.text}")
            return False
    except Exception as e:
        print(f"Delete exception: {e}")
        return False

