def get_azure_blob_sas_url(blob_url: str) -> str:
    """
    Appends SAS token to the blob URL for access if needed.
    """
    sas_token = os.environ.get("AZURE_BLOB_SAS_TOKEN")
    if not sas_token:
        return blob_url

    # Check if URL already has query parameters
    if "?" in blob_url:
        # Check if SAS token is already present (simple check)
        if "sig=" in blob_url:
            return blob_url
        return f"{blob_url}&{sas_token}"
    else:
        return f"{blob_url}?{sas_token}"

