def handle_assistant_deletion(assistant_id: str) -> bool:
    """
    处理助手删除或状态变为非活跃
    """
    return remove_custombot_from_cache(assistant_id)

def handle_assistant_status_update(assistant_id: str, new_status: str) -> bool:
    """
    处理助手状态更新
    如果状态变为非活跃，需要从缓存中移除
    """
    if new_status != 'Active':
        return remove_custombot_from_cache(assistant_id)
    else:
        # 重新激活时，仅就地刷新该 assistant 的缓存
        try:
            cached_bots = get_cache_resource_all_active_custombot_normal_access()
            from database.repository.custom_bot import custom_bot_retrieve_all_active_assistants_normal_access
            fresh_all = custom_bot_retrieve_all_active_assistants_normal_access()
            fresh_for_assistant = [b for b in fresh_all if getattr(b, 'assistant_id', None) == assistant_id]

            # 先移除缓存中该 assistant 的所有条目
            i = 0
            while i < len(cached_bots):
                if getattr(cached_bots[i], 'assistant_id', None) == assistant_id:
                    cached_bots.pop(i)
                else:
                    i += 1

            # 再把该 assistant 的最新条目就地插入缓存
            cached_bots.extend(fresh_for_assistant)
            return True
        except Exception as e:
            print(f"重新激活助手时更新缓存失败: {e}")
            return False

def handle_assistant_batch_update(assistant_id: str, updates: Dict[str, Any]) -> bool:
    """
    处理助手的批量更新

    参数:
    - assistant_id: 助手ID
    - updates: 要更新的属性字典
    """
    # 检查是否有需要特殊处理的字段
    if 'assistant_status' in updates and updates['assistant_status'] != 'Active':
        return handle_assistant_status_update(assistant_id, updates['assistant_status'])

    # 如果涉及访问权限变更，需要重新加载缓存
    if any(key in updates for key in ['chat_access_control', 'user_access_id']):
        return handle_assistant_access_update(assistant_id)

    # 其他字段可以直接批量更新
    return batch_update_cached_custombot(assistant_id, updates)

