class BaseChat:
    DEFAULT_PROMPT_FOR_FILE_PROCESSING = """Identify new uploaded file"""
    def __init__(self, model: str, func_group = 'LF AI Lab', system_instruction: str | None | Omit = omit):
        self._chat_history = []
        self.model = model
        self.system_instruction = system_instruction
        self.func_group = func_group
        self.user_id = st.session_state.userId
        self.user_name = st.session_state.userName
        self.user_email = st.session_state.userEmail

    def create_new_chat(self):
        self._chat_history = []

    def get_chat_history(self):
        return self._chat_history

    def write_chat_history(self):
        history = self._chat_history
        for message_index, message in enumerate(history):
            if message["role"] == "system":
                continue
            with st.chat_message(message["role"]):
                # for thingking
                if message.get('reasoning_content', None):
                    st.markdown(
                        # f"<details><summary>Thinking</summary>{message['reasoning_content']}</details>",
                        f"<details open style='color:gray;background-color:#f8f8f8;padding:8px;border-radius:4px;font-style:italic;'><summary style='cursor:pointer;outline:none;'>Thinking</summary>{message['reasoning_content']}</details>",
                        unsafe_allow_html=True
                    )
                for content in message["content"]:
                    match content["type"]:
                        case "thoughts":
                            st.markdown(
                                f"<details style='color:gray;background-color:#f8f8f8;padding:8px;border-radius:4px;font-style:italic;'><summary style='cursor:pointer;outline:none;'>Thoughts</summary>\n\n{content['thoughts']}</details>",
                                unsafe_allow_html=True
                            )
                        case "text":
                            st.markdown(custom_markdown_text(content["text"]))
                        case "image_url":
                            image_base64_data = content["image_url"]["url"].split('base64,')[1]
                            image = Image.open(io.BytesIO(base64.b64decode(image_base64_data)))
                            st.image(image)
                        case "file":
                            if content["file"].get("filename"):
                                st.markdown(f"[Uploaded file: {content['file']['filename']}]")
                        # For Claude images and files
                        case "image":
                            image_base64_data = content["source"]["data"]
                            try:
                                image = Image.open(io.BytesIO(base64.b64decode(image_base64_data)))
                                st.image(image)
                                if content.get("filename"):
                                    st.caption(f"Image: {content['filename']}")
                            except Exception:
                                st.error("Failed to load image from history")
                        case "document":
                            file_name = content.get("filename", "PDF Document")
                            st.markdown(f"📄 **[Uploaded PDF: {file_name}]**")

    def _append_user_content(self, prompt: str, files: list[UploadedFile] = None):
        user_content = []
        if files:
            for file in files:
                if file.type.lower().startswith("image"):
                    if not validate_streamlit_uploaded_file_size(uploaded_file=file, file_size_limitation=10):
                        raise Exception("Limit 10 MB for image file")
                    user_file_content = {
                        "type": "image_url",
                        "image_url": {
                            "url": f"data:{file.type.lower()};base64,{base64.b64encode(file.getvalue()).decode('utf-8')}",
                            "detail": "high"
                        }
                    }
                else:
                    if not validate_streamlit_uploaded_file_size(uploaded_file=file, file_size_limitation=30):
                        raise Exception("Limit 30 MB")
                    user_file_content = {
                        "type": "file",
                        "file": {
                            "file_data": f"data:{file.type.lower()};base64,{base64.b64encode(file.getvalue()).decode('utf-8')}",
                            "filename": file.name
                        }
                    }
                user_content.append(user_file_content)

        # prompt = prompt if prompt else "What's in the file"
        if prompt:
            user_text_content = {
                "type": "text",
                "text": prompt
            }
            user_content.append(user_text_content)

        self._chat_history.append(
            {
                "role": "user",
                "content": user_content
            }
        )

    def generate_content(self, prompt: str, files: list[UploadedFile] = None):
        """Base generate_content method for all chat client"""
        raise NotImplementedError

    def conversation_management(self, func_reset_chat_data=lambda: None):
        def _func_reset_chat_data():
            self._chat_history = []
            func_reset_chat_data()

        if st.button('✚ Create New Chat', key='chatbot_create_new_chat', width='stretch'):
            _func_reset_chat_data()
            st.rerun()

