class OpenaiChat(BaseChat):
    def __init__(self, model: str = 'gpt-4.1-mini', api_key: str=OPENAI_PROJECT_API_KEY, base_url=None):
        super().__init__(model=model)
        self.client = OpenAI(
            api_key=api_key,
            base_url=base_url
        )

    def _chat_completion_stream(self):
        # reasoning_effort only available under in openai official request
        if_openai_reasoning_model = True if re.match(r'^o\d+', str(self.model)) else False
        reasoning_effort = 'medium' if if_openai_reasoning_model else NOT_GIVEN

        assistant_contents = []
        reasoning_placeholder = None
        message_placeholder = None

        # messages=self._chat_history
        # remove reasoning_content to submit messages
        messages = [
            {k: v for k, v in copy.deepcopy(message).items() if k != "reasoning_content"}
            for message in self._chat_history
        ]

        stream = self.client.chat.completions.create(
            model=self.model,
            messages=messages,
            stream=True,  # Set streaming here
            reasoning_effort=reasoning_effort
        )
        text_response = ""
        reasoning_content = ""

        for chunk in stream:
            # thinking streaming
            if getattr(chunk.choices[0].delta, 'reasoning_content', None) and chunk.choices[0].delta.reasoning_content:
                reasoning_content += str(chunk.choices[0].delta.reasoning_content)
                reasoning_placeholder = reasoning_placeholder if reasoning_placeholder else st.empty()
                reasoning_placeholder.markdown(
                    f"<details open style='color:gray;background-color:#f8f8f8;padding:8px;border-radius:4px;font-style:italic;'><summary style='cursor:pointer;outline:none;'>Thinking</summary>{reasoning_content}</details>",
                    # f"<div style='color:gray;background-color:#f8f8f8;padding:8px;border-radius:4px;font-style:italic;'><summary>Thinking</summary>{reasoning_content}</div>",
                    unsafe_allow_html=True
                )

            if chunk.choices[0].delta.content is not None:
                word = str(chunk.choices[0].delta.content)
                text_response += word
                message_placeholder = message_placeholder if message_placeholder else st.empty()
                message_placeholder.markdown(custom_markdown_text(text_response + "▌"))
        if text_response:
            assistant_text_content = {
                "type": "text",
                "text": text_response
            }
            assistant_contents.append(assistant_text_content)
            print(f"message completed: {text_response}")
        self._chat_history.append(
            {
                "role": "assistant",
                "content": assistant_contents,
                "reasoning_content": reasoning_content
            }
        )

    def generate_content(self, prompt: str, files: list[UploadedFile] = None):
        self._append_user_content(prompt, files)
        self._chat_completion_stream()

