class GrokChat(OpenaiChat):
    def __init__(self, model: str = 'grok-4'):
        super().__init__(model=model, api_key=XAI_API_KEY, base_url="https://api.x.ai/v1")

    def generate_content(self, prompt: str, files: list[UploadedFile] = None, enable_code_execution: bool = False,
                         enable_web_search: bool = False, enable_x_search: bool = False, enable_collections_search: bool = False):
        # 1. 处理用户输入（复用父类逻辑）
        self._append_user_content(prompt, files)

        # 2. 定义 xAI/OpenAI 兼容的 Tools Schema
        tools = []

        if enable_web_search:
            tools.append({
                "type": "function",
                "function": {
                    "name": "web_search",
                    "description": "Search the web for current news, facts, or information not in your training data.",
                    "parameters": {
                        "type": "object",
                        "properties": {
                            "query": {
                                "type": "string",
                                "description": "The search query keywords."
                            },
                            "search_type": {
                                "type": "string",
                                "enum": ["news", "general"],
                                "description": "Type of search."
                            }
                        },
                        "required": ["query"]
                    }
                }
            })

        if enable_code_execution:
            tools.append({
                "type": "function",
                "function": {
                    "name": "code_interpreter",
                    "description": "Execute Python code to perform calculations, data analysis, or visualizations.",
                    "parameters": {
                        "type": "object",
                        "properties": {
                            "code": {
                                "type": "string",
                                "description": "The python code snippet to run."
                            }
                        },
                        "required": ["code"]
                    }
                }
            })

        if enable_x_search:
            tools.append({
                "type": "function",
                "function": {
                    "name": "x_search",
                    "description": "Search specifically on X (formerly Twitter) for posts, trends, or user sentiments.",
                    "parameters": {
                        "type": "object",
                        "properties": {
                            "query": {"type": "string", "description": "Keywords to search on X platform."},
                            "time_range": {"type": "string", "enum": ["latest", "top"],
                                           "description": "Sort by latest or top tweets."}
                        },
                        "required": ["query"]
                    }
                }
            })

        if enable_collections_search:
            tools.append({
                "type": "function",
                "function": {
                    "name": "collections_search",
                    "description": "Search within the user's saved collections or knowledge base documents.",
                    "parameters": {
                        "type": "object",
                        "properties": {
                            "query": {"type": "string", "description": "The semantic search query for the documents."},
                            "collection_ids": {
                                "type": "array",
                                "items": {"type": "string"},
                                "description": "Optional list of specific collection IDs to search in."
                            }
                        },
                        "required": ["query"]
                    }
                }
            })

        # 4. 执行带有 Tools 参数的请求
        # 如果没有启用任何工具，tools 为 NotGiven
        api_tools = tools if tools else NOT_GIVEN
        api_tool_choice = "auto" if tools else NOT_GIVEN

        self._chat_completion_stream_grok(tools=api_tools, tool_choice=api_tool_choice)

    def _chat_completion_stream_grok(self, tools, tool_choice):
        """
        专门为 Grok 定制的流式处理，支持传入 tools 参数
        """
        # xAI 目前可能不支持 reasoning_content 字段回传，这里过滤掉历史记录中的 reasoning
        messages = [
            {k: v for k, v in copy.deepcopy(message).items() if k != "reasoning_content"}
            for message in self._chat_history
        ]

        # 移除 system role 中不支持的字段（如果有的话），防止报错
        # 很多兼容层不支持 system 消息带 name 等额外参数

        try:
            print(f"\n--- Starting Grok Request [Model: {self.model}] ---")
            stream = self.client.chat.completions.create(
                model=self.model,
                messages=messages,
                stream=True,
                tools=tools,
                tool_choice=tool_choice,
                temperature=0.7  # Grok 推荐可以在这里设置
            )

            assistant_contents = []
            text_response = ""
            message_placeholder = None

            # 用于处理 Grok 返回的工具调用意图
            tool_call_chunks = []
            # 用于收集完整的工具调用数据 (处理流式分块)
            tool_calls_buffer = {}  # Key: index, Value: {id, name, arguments_str}

            for chunk in stream:
                # 打印实际模型名，解决您的版本疑惑
                # if chunk.model: print(f"DEBUG: Serving Model: {chunk.model}")
                # 1. 【打印整个 Output】: 打印原始 Chunk 方便调试
                print(f"DEBUG CHUNK: {chunk.choices[0].delta}")

                delta = chunk.choices[0].delta

                # 1. 处理文本流
                if delta.content:
                    text_response += delta.content
                    message_placeholder = message_placeholder if message_placeholder else st.empty()
                    message_placeholder.markdown(custom_markdown_text(text_response + "▌"))

                # 2. 处理工具调用流 (Grok 可能会分块返回 JSON)
                if delta.tool_calls:
                    for tc in delta.tool_calls:
                        # 简单的 UI 提示，告知用户模型意图
                        # if tc.function and tc.function.name:
                        #     action_name = tc.function.name
                        #     with st.chat_message("assistant"):
                        #         st.status(f"🛠️ Grok request to use tool: **{action_name}**", state="running")
                        # 初始化 Buffer
                        if tc.index not in tool_calls_buffer:
                            tool_calls_buffer[tc.index] = {
                                "id": "",
                                "name": "",
                                "arguments": ""
                            }

                        # 累积数据
                        if tc.id:
                            tool_calls_buffer[tc.index]["id"] += tc.id
                        if tc.function and tc.function.name:
                            tool_calls_buffer[tc.index]["name"] += tc.function.name
                        if tc.function and tc.function.arguments:
                            tool_calls_buffer[tc.index]["arguments"] += tc.function.arguments

            # 3. 结果保存
            if text_response:
                assistant_contents.append({
                    "type": "text",
                    "text": text_response
                })

            # # 如果文本为空但有工具调用，添加一条提示信息到历史记录
            # if not text_response and not assistant_contents:
            #     assistant_contents.append({
            #         "type": "text",
            #         "text": "*[Model generated a tool call request, but automatic execution is not configured in this frontend yet]*"
            #     })

            # 2. 如果有工具调用，解析并在前端展示，并在后台打印
            if tool_calls_buffer:
                print("\n--- Model Final Tool Calls ---")
                tool_calls_list = []

                for idx, tc_data in tool_calls_buffer.items():
                    func_name = tc_data["name"]
                    func_args = tc_data["arguments"]
                    call_id = tc_data["id"]

                    # 打印到控制台
                    print(f"Tool[{idx}]: {func_name} | Args: {func_args}")

                    # 尝试格式化 JSON 以便前端显示
                    try:
                        args_json = json.loads(func_args)
                        pretty_args = json.dumps(args_json, indent=2)
                    except:
                        pretty_args = func_args

                    # 前端显示：不再显示错误，而是显示工具调用详情
                    with st.chat_message("assistant"):
                        st.info(f"⚙️ **Requesting Tool:** `{func_name}`")
                        with st.expander("View Parameters", expanded=True):
                            st.code(pretty_args, language="json")

                    # 存入历史记录 (OpenAI 格式要求)
                    # 注意：在真实的循环中，这里需要将 tool_calls 添加到 messages 并再次调用 API
                    # 但为了前端展示，我们这里先存入结构化数据
                    tool_calls_list.append({
                        "id": call_id,
                        "type": "function",
                        "function": {
                            "name": func_name,
                            "arguments": func_args
                        }
                    })

                # 将工具调用存入 assistant_contents (作为 text 或 自定义类型)
                # 这里为了兼容 BaseChat UI 逻辑，加一段解释文本
                if not text_response:
                    assistant_contents.append({
                        "type": "text",
                        "text": f"**[System]** The model requested to use tools: `{', '.join([t['name'] for t in tool_calls_buffer.values()])}`. \n\n*Note: Automatic tool execution backend logic is required to see the final search results.*"
                    })

            self._chat_history.append({
                "role": "assistant",
                "content": assistant_contents,
                "reasoning_content": ""
            })

        except Exception as error:
            print(traceback.format_exc())
            st.error(f"Grok API Error: {error}")
            # 将错误记录进历史以便调试
            self._chat_history.append({
                "role": "assistant",
                "content": [{"type": "text", "text": f"Error: {str(error)}"}],
            })

