class ClaudeChat(BaseChat):
    def __init__(self, model: str = 'claude-sonnet-4-5-20250929'):
        import anthropic
        super().__init__(model=model)
        self.client = anthropic.Anthropic(
            api_key=ANTHROPIC_API_KEY
        )

    def generate_content(self, prompt: str, files: list[UploadedFile] = None):
        # self._append_user_content(prompt, files)
        assistant_contents = []
        user_contents = []

        if prompt:
            user_contents.append({
                "type": "text",
                "text": prompt
            })

        if files:
            if not validate_streamlit_uploaded_files_size(uploaded_files=files, total_file_size_limitation=32):
                raise Exception("Limit 32 MB for all image files")
            file_count = len(files)
            if file_count > 100:
                raise Exception("No more than 100 images")
            pdf_page_num = 0

            for file in files:
                file_bytes = file.getvalue()
                b64 = base64.b64encode(file_bytes).decode("utf-8")
                mime_type = file.type.lower()
                source_struct = {
                    "type": "base64",
                    "media_type": mime_type,
                    "data": b64
                }

                if mime_type.startswith("image"):
                    image = Image.open(io.BytesIO(file_bytes))
                    width, height = image.size
                    if width > 2000 or height > 2000:
                        if not validate_streamlit_uploaded_file_size(uploaded_file=file, file_size_limitation=2):
                            raise Exception("Limit 2000px for width or height of each image")
                    user_contents.append({
                        "type": "image",
                        "source": source_struct,
                        "filename": file.name
                    })

                elif mime_type == "application/pdf":
                    pdf_reader = PdfReader(io.BytesIO(file_bytes))
                    pdf_page_num += len(pdf_reader.pages)
                    if pdf_page_num > 100:
                        raise Exception("No more than 100 pages for all PDF")
                    # if not validate_streamlit_uploaded_file_size(uploaded_file=file, file_size_limitation=32):
                    #     raise Exception("Limit 32 MB for each PDF")
                    user_contents.append({
                        "type": "document",
                        "source": source_struct,
                        "filename": file.name
                    })

                else:
                    if not validate_streamlit_uploaded_file_size(uploaded_file=file, file_size_limitation=32):
                        raise Exception("Limit 32 MB for document")
                    user_contents.append({
                        "type": "document",
                        "source": source_struct,
                        "filename": file.name
                    })

        # Append user content to chat history for UI display
        self._chat_history.append({
            "role": "user",
            "content": user_contents
        })

        # Delete thoughts in message to make it available for API request
        api_messages = []
        for msg in self._chat_history:
            # Claude API does not allow 'system' role inside the messages list (it uses top-level system param)
            if msg.get("role") == "system":
                continue

            # 1. Init Clean Message
            api_msg = {
                "role": msg["role"],
                "content": []
            }

            # 2. Process Content List
            raw_content = msg.get("content", [])
            if isinstance(raw_content, list):
                for item in raw_content:
                    item_type = item.get("type")

                    # Filter: Skip thoughts types
                    if item_type in ["thoughts"]:
                        continue

                    clean_item = {"type": item_type}
                    if item_type == "text":
                        clean_item["text"] = item.get("text", "")
                    elif item_type in ["image", "document"]:
                        if "source" in item:
                            clean_item["source"] = item["source"]
                        else:
                            continue  # Skip invalid items

                    # Optional: Pass prompt caching control
                    # if "cache_control" in item:
                    #     clean_item["cache_control"] = item["cache_control"]

                    api_msg["content"].append(clean_item)

            api_messages.append(api_msg)

        thinking_config = None
        models_with_thinking = ["claude-sonnet-4-5-20250929", "claude-sonnet-4-20250514", "claude-opus-4-6", "claude-sonnet-4-6"]
        if self.model in models_with_thinking:
            thinking_config = {"type": "enabled", "budget_tokens": 10000}
        # message_placeholder = st.empty()
        message = self.client.beta.messages.create(
            model=self.model,
            # max_tokens=128000,
            max_tokens=64000,
            temperature=1,
            messages=api_messages,
            # thinking={"type": "enabled", "budget_tokens": 10000},
            thinking=thinking_config,
            # betas=["output-128k-2025-02-19"],
            stream=True
        )

        text_response = ""
        assistant_thoughts = ""
        message_placeholder = None
        thoughts_message_placeholder = None

        for chunk in message:
            if chunk.type == "content_block_start":
                # A new content block is starting
                print(f"\n[New content block: {chunk.content_block.type}]", end="\n\n")

            elif chunk.type == "content_block_delta":
                delta = getattr(chunk, "delta", None)
                if delta:
                    if getattr(delta, "type", "") == "thinking_delta":
                        thought_piece = getattr(delta, "thinking", "") or ""
                        if thought_piece:
                            assistant_thoughts += thought_piece
                            thoughts_message_placeholder = thoughts_message_placeholder if thoughts_message_placeholder else st.empty()
                            thoughts_message_placeholder.markdown(
                                f"<details open style='color:gray;background-color:#f8f8f8;padding:8px;border-radius:4px;font-style:italic;'><summary style='cursor:pointer;outline:none;'>Thoughts</summary>{assistant_thoughts}</details>",
                                unsafe_allow_html=True
                            )
                        continue
                # Content is streaming in
                delta_text = getattr(delta, "text", None)
                if delta_text:
                    message_placeholder = message_placeholder if message_placeholder else st.empty()
                    print(delta_text, end="", flush=True)
                    text_response += delta_text
                    message_placeholder.markdown(custom_markdown_text(text_response + "▌"))

            elif chunk.type == "content_block_stop":
                # Content block completed
                print("\n\n[Content block complete]")

            elif chunk.type == "message_stop":
                # Entire message completed
                print("\n\n[Stream complete]")

        if assistant_thoughts:
            assistant_contents.append(
                {
                    "type": "thoughts",
                    "thoughts": assistant_thoughts
                }
            )

        if text_response:
            assistant_text_content = {
                "type": "text",
                "text": text_response
            }
            assistant_contents.append(assistant_text_content)
            print(f"message completed: {text_response}")

        self._chat_history.append(
            {
                "role": "assistant",
                "content": assistant_contents,
                "thoughts": assistant_thoughts
            }
        )

