class OpenaiResponseChat(BaseChat):
    LITERAL_SIZE = Literal["auto", "1024x1024", "1536x1024", "1024x1536"]
    SIZE_LIST = list(get_args(LITERAL_SIZE))

    LITERAL_QUALITY = Literal["auto", "high", "medium", "low"]
    QUALITY_LIST = list(get_args(LITERAL_QUALITY))
    DEFAULT_PROMPT_FOR_FILE_PROCESSING = """Identify new uploaded file and respond by file type:  
        - CSV/XLSX: show column names & first 10 rows; suggest analysis methods and visualizations.  
        - JPG/PNG/JPEG/GIF: Identify image.  
        - Other types: summarize each file; offer sample questions you could answer with its content."""

    def __init__(self, model: str = 'gpt-4.1-mini', prompt_id: str = "",
                 api_key: str=OPENAI_PROJECT_API_KEY, base_url=None,
                 system_instructions: str | None | Omit = omit,
                 func_group: Literal["LF AI Lab", "GPT Chatbot", "LF Image Creator", "PPT Creator", "AI Artifacts"] = "LF AI Lab",
                 enable_conversation: bool = False
                 ):
        """
        suggest provide system instruction if no prompt_id create on OpenAI playground
        """
        super().__init__(model=model, func_group=func_group, system_instruction=system_instructions)
        self.client = OpenAI(
            api_key=api_key,
            base_url=base_url
        )
        self.OpenaiClient = OpenaiClient(
            api_key=api_key,
            funct_group=func_group,
            user_id=self.user_id,
            user_name=self.user_name,
            user_email=self.user_email
        )
        self.enable_conversation = enable_conversation
        self.runtime_compat_version = OPENAI_RESPONSE_CHAT_RUNTIME_VERSION
        self.current_conversation_id: str | None = None
        self.current_response_id = NOT_GIVEN
        self.file_search_file_ids: list[str] = []
        self.code_interpreter_file_ids: list[str] = []
        self.file_ids: list[str] = []
        self.current_vector_store_id = ''
        self.current_vector_store_files = None
        self.current_bot_vector_store_files = None
        self.current_container_id = None
        self.current_container_files = []
        self.prompt_id = prompt_id
        self.user_conversations = None
        self.is_get_user_conversations_running = False
        self.seconds_get_user_assistant_thread = -1
        self.is_generating = False  # Flag to prevent fragment auto-rerun during generate_content

        # Bot level file storage (loaded from DB on init, immutable during chat)
        self.bot_vector_store_id: str = ''
        self.bot_code_interpreter_file_ids: list[str] = []

        # Thread level file storage (mutable, per-conversation)
        self.thread_vector_store_id: str = ''
        self.thread_code_interpreter_file_ids: list[str] = []

        # file_id -> filename 映射，用于前端显示文件名
        self._file_id_name_map: dict[str, str] = {}

        # Initialize custom tools (each import + init wrapped individually)
        self.custom_tools = {}
        try:
            from utils.tools.google_search import GoogleSearchTool
            self.custom_tools['google_search'] = GoogleSearchTool()
            print("[OpenaiResponseChat] GoogleSearchTool initialized successfully")
        except Exception as e:
            print(f"[OpenaiResponseChat] Failed to initialize GoogleSearchTool: {str(e)}")

        # Firecrawl: migrated to MCP tool (no local initialization needed)

        try:
            from utils.tools.deep_research_tool import DeepResearchTool
            self.custom_tools['deep_research'] = DeepResearchTool()
            print("[OpenaiResponseChat] DeepResearchTool initialized successfully")
        except Exception as e:
            print(f"[OpenaiResponseChat] Failed to initialize DeepResearchTool: {str(e)}")

        try:
            from utils.tools.file_search_pro_tool import FileSearchProTool
            self.custom_tools['file_search_pro'] = FileSearchProTool()
            print("[OpenaiResponseChat] FileSearchProTool initialized successfully")
        except Exception as e:
            print(f"[OpenaiResponseChat] Failed to initialize FileSearchProTool: {str(e)}")

        try:
            from utils.tools.google_file_search_tool import GoogleFileSearchTool
            self.custom_tools['google_file_search'] = GoogleFileSearchTool()
            print("[OpenaiResponseChat] GoogleFileSearchTool initialized successfully")
        except Exception as e:
            print(f"[OpenaiResponseChat] Failed to initialize GoogleFileSearchTool: {str(e)}")

    def _append_user_content(self, prompt: str, files: list[UploadedFile] = None, enable_code_interpreter: bool = False, enable_file_search: bool = False):
        # for api input
        user_content = []
        # for message display
        user_message_content_items = []
        content_items = []
        if files:
            with st.empty():
                files_status = st.status("Upload files to openAI storage...", expanded=True)
                with files_status:
                    total_files_count = len(files)
                    success_files_count = 0
                    temp_conversation_file_ids = []
                    temp_code_interpreter_file_ids = []
                    temp_file_search_file_ids = []
                    for file in files:
                        st.write(f"Uploading {file.name}")
                        try:
                            # openai vision purpose for image
                            if file.type.lower().startswith("image"):
                                if not validate_streamlit_uploaded_file_size(uploaded_file=file, file_size_limitation=10):
                                    st.warning(f"Limit 10 MB for image file, skip {file.name}")
                                    # raise Exception("Limit 10 MB for image file")
                                if self.enable_conversation:
                                    if enable_code_interpreter:
                                        created_file = self.OpenaiClient.create_file(uploaded_file=file,purpose="user_data")
                                        temp_conversation_file_ids.append(created_file.id)
                                        temp_code_interpreter_file_ids.append(created_file.id)
                                        if self.current_container_id:
                                            self.OpenaiClient.create_container_file(container_id=self.current_container_id,file_id=created_file.id,file_name=file.name)
                                    # https://community.openai.com/t/conversations-api-bug-cannot-post-messages-with-images-to-the-endpoint/1363272/7
                                    # user_file_content = {
                                    #     "type": "input_image",
                                    #     "file_id": created_file.id
                                    # }

                                    user_file_content = {
                                        "type": "input_image",
                                        "image_url": f"data:{file.type.lower()};base64,{base64.b64encode(file.getvalue()).decode('utf-8')}",
                                        "detail": "high"
                                    }

                                else:
                                    # raw data input for non-conversation
                                    user_file_content = {
                                        "type": "input_image",
                                        "image_url": f"data:{file.type.lower()};base64,{base64.b64encode(file.getvalue()).decode('utf-8')}",
                                        "detail": "high"
                                    }

                                content_items.append(user_file_content)

                                user_content.append(user_file_content)
                                success_files_count += 1
                                st.write(f"Upload {file.name} successfully")

                            # openai vision purpose for PDF
                            elif file.type.lower() == "application/pdf":
                                if not validate_streamlit_uploaded_file_size(uploaded_file=file, file_size_limitation=10):
                                    st.warning(f"Limit 10 MB for pdf file, skip {file.name}")
                                    # raise Exception("Limit 10 MB")
                                if self.enable_conversation:
                                    created_file = self.OpenaiClient.create_file(uploaded_file=file, purpose="user_data")
                                    temp_conversation_file_ids.append(created_file.id)
                                    if enable_code_interpreter:
                                        temp_code_interpreter_file_ids.append(created_file.id)
                                        if self.current_container_id:
                                            self.OpenaiClient.create_container_file(container_id=self.current_container_id,file_id=created_file.id,file_name=file.name)
                                    if enable_file_search:
                                        temp_file_search_file_ids.append(created_file.id)
                                    user_file_content = {
                                        "type": "input_file",
                                        "file_id": created_file.id
                                    }
                                    self._file_id_name_map[created_file.id] = file.name
                                else:
                                    user_file_content = {
                                        "type": "input_file",
                                        "filename": file.name,
                                        "file_data": f"data:{file.type.lower()};base64,{base64.b64encode(file.getvalue()).decode('utf-8')}"
                                    }
                                content_items.append(user_file_content)
                                user_content.append(user_file_content)
                                success_files_count += 1
                                st.write(f"Upload {file.name} successfully")
                            else:
                                # 其他文件类型（txt, docx, csv 等）
                                # 这些文件不能作为 base64 内联输入，但可以上传到 OpenAI 用于 file_search
                                created_file = self.OpenaiClient.create_file(uploaded_file=file, purpose="user_data")
                                file_type = str(file.name).lower().split('.')[-1]

                                if self.enable_conversation:
                                    temp_conversation_file_ids.append(created_file.id)

                                if enable_code_interpreter:
                                    temp_code_interpreter_file_ids.append(created_file.id)
                                    if self.current_container_id:
                                        self.OpenaiClient.create_container_file(container_id=self.current_container_id, file_id=created_file.id, file_name=file.name)

                                if enable_file_search:
                                    if file_type not in CODE_INTERPRETER_FILES_TYPE_DIFF:
                                        temp_file_search_file_ids.append(created_file.id)

                                self._file_id_name_map[created_file.id] = file.name

                                if file_type in RESPONSES_UNSUPPORTED_INPUT_FILE_EXTENSIONS:
                                    user_file_content = {
                                        "type": "input_text",
                                        "text": f"Uploaded file: {file.name}"
                                    }
                                else:
                                    # 将文件引用写入对话历史，确保刷新后仍可见
                                    user_file_content = {
                                        "type": "input_file",
                                        "file_id": created_file.id
                                    }

                                content_items.append(user_file_content)
                                user_content.append(user_file_content)

                                success_files_count += 1
                                st.write(f"Upload {file.name} successfully")

                        except Exception as openai_upload_file_error:
                            print(traceback.format_exc())

                    if temp_file_search_file_ids:
                        self.file_search_file_ids.extend(temp_file_search_file_ids)
                    if temp_code_interpreter_file_ids:
                        self.code_interpreter_file_ids.extend(temp_code_interpreter_file_ids)
                        self.thread_code_interpreter_file_ids.extend(temp_code_interpreter_file_ids)
                    if temp_conversation_file_ids:
                        self.file_ids.extend(temp_conversation_file_ids)

                    # Thread 级别 vector store 创建/更新（7天过期）
                    # NOTE: ui_markdown=False to avoid StopException in nested st.spinner→st.chat_message→st.status context
                    if not self.thread_vector_store_id and temp_file_search_file_ids:
                        created_vector_store = self.OpenaiClient.create_vector_store(expires_after_days=7)
                        self.thread_vector_store_id = created_vector_store.id
                        self.OpenaiClient.create_vector_store_file_batch(vector_store_id=self.thread_vector_store_id, file_ids=temp_file_search_file_ids)
                    elif self.thread_vector_store_id and temp_file_search_file_ids:
                        self.OpenaiClient.create_vector_store_file_batch(vector_store_id=self.thread_vector_store_id, file_ids=temp_file_search_file_ids)
                    # fallback: 兼容其他页面仍使用 current_vector_store_id 的场景
                    elif not self.thread_vector_store_id and not self.current_vector_store_id and self.file_search_file_ids:
                        created_vector_store = self.OpenaiClient.create_vector_store()
                        self.current_vector_store_id = created_vector_store.id
                        self.OpenaiClient.create_vector_store_file_batch(vector_store_id=self.current_vector_store_id, file_ids=self.file_search_file_ids)
                    elif self.current_vector_store_id and not self.thread_vector_store_id and temp_file_search_file_ids:
                        self.OpenaiClient.create_vector_store_file_batch(vector_store_id=self.current_vector_store_id, file_ids=temp_file_search_file_ids)

                    print(f"self.enable_conversation: {self.enable_conversation}, self.current_conversation_id: {self.current_conversation_id}, temp_conversation_file_ids: {temp_conversation_file_ids}")
                    if temp_conversation_file_ids:
                        self._update_conversation_metadata()

                    files_status.update(label=f"Upload {success_files_count} of {total_files_count} files completed", state="complete", expanded=False)


        if prompt:
            user_text_content = {
                "type": "input_text",
                "text": prompt
            }
            user_content.append(user_text_content)
            content_items.append(
                {
                    "type": "input_text",
                    "text": prompt
                }
            )

        user_message_content_items.append(
            {
                "type": "message",
                "content": content_items,
                "role": "user"
            }
        )

        input_user_content =[
            {
                "role": "user",
                "content": user_content
            }
        ]

        # create conversation items and omit input for response when enable conversation
        if self.enable_conversation and self.current_conversation_id:
            created_items = self.client.conversations.items.create(
                conversation_id=self.current_conversation_id,
                items=user_message_content_items,
                include=["code_interpreter_call.outputs", "web_search_call.action.sources", "web_search_call.results","file_search_call.results", "message.input_image.image_url"]
            )
            user_message_content_items = self.digest_conversation_items(created_items.data)
            input_user_content = []

        self._chat_history.extend(user_message_content_items)
        return input_user_content

    def _get_tool_display_name(self, tool_name: str) -> str:
        """Get friendly display name for tool"""
        tool_names = {
            'google_search': '🔍 Google Search',
            'firecrawl': '🔥 Firecrawl',
            'deep_research': '📚 Deep Research',
            'file_search_pro': '📁 File Search Pro',
            'google_file_search': '📁 Google File Search'
        }
        return tool_names.get(tool_name, tool_name)

    def _execute_custom_tool(self, function_name: str, arguments: dict) -> str:
        """
        Execute a custom tool and return the result

        Args:
            function_name: Name of the tool to execute
            arguments: Tool arguments as a dictionary

        Returns:
            Tool execution result as a JSON string
        """
        import json

        try:
            print(f"[Custom Tool Execution] Starting {function_name} with arguments: {arguments}")

            if function_name == "google_search":
                if 'google_search' in self.custom_tools:
                    result = self.custom_tools['google_search'].execute(arguments)
                    print(f"[Custom Tool Execution] {function_name} completed successfully")
                    return json.dumps(result, ensure_ascii=False)
                else:
                    error_msg = "Google Search tool not initialized - check logs above for initialization errors"
                    print(f"[Custom Tool Execution] Error: {error_msg}")
                    return json.dumps({"error": error_msg})

            # Firecrawl: migrated to MCP tool (no local execution needed)

            elif function_name == "deep_research":
                if 'deep_research' in self.custom_tools:
                    result = self.custom_tools['deep_research'].execute(arguments)
                    print(f"[Custom Tool Execution] {function_name} completed successfully")
                    return json.dumps(result, ensure_ascii=False)
                else:
                    error_msg = "Deep Research tool not initialized - check logs above for initialization errors"
                    print(f"[Custom Tool Execution] Error: {error_msg}")
                    return json.dumps({"error": error_msg})

            elif function_name == "file_search_pro":
                if 'file_search_pro' in self.custom_tools:
                    # 注入 assistant_id，使 FileSearchProTool 在 Responses API 路径下也能获取到
                    if self.prompt_id:
                        arguments['assistant_id'] = self.prompt_id
                    result = self.custom_tools['file_search_pro'].execute(arguments)
                    print(f"[Custom Tool Execution] {function_name} completed successfully")
                    return json.dumps(result, ensure_ascii=False)
                else:
                    error_msg = "File Search Pro tool not initialized - check logs above for initialization errors"
                    print(f"[Custom Tool Execution] Error: {error_msg}")
                    return json.dumps({"error": error_msg})

            elif function_name == "google_file_search":
                if 'google_file_search' in self.custom_tools:
                    # 注入 assistant_id，使 GoogleFileSearchTool 在 Responses API 路径下也能获取到
                    if self.prompt_id:
                        arguments['assistant_id'] = self.prompt_id
                    result = self.custom_tools['google_file_search'].execute(arguments)
                    print(f"[Custom Tool Execution] {function_name} completed successfully")
                    return json.dumps(result, ensure_ascii=False)
                else:
                    error_msg = "Google File Search tool not initialized - check logs above for initialization errors"
                    print(f"[Custom Tool Execution] Error: {error_msg}")
                    return json.dumps({"error": error_msg})

            else:
                error_msg = f"Unknown custom tool: {function_name}"
                print(f"[Custom Tool Execution] Error: {error_msg}")
                return json.dumps({"error": error_msg})

        except Exception as e:
            error_msg = f"Tool execution error: {str(e)}"
            print(f"[Custom Tool Execution] {error_msg}")
            import traceback
            traceback.print_exc()
            return json.dumps({"error": error_msg})


    def _response_chat_stream(self, input_user_content, tools = omit, reasoning = omit, service_tier = omit, instructions: str | None | Omit = omit):
        """
        完整的函数调用循环流程：
        1. 第一次请求：获取函数调用
        2. 执行函数（显示进度条）
        3. 第二次请求：发送函数结果
        4. 获得最终回复
        """
        import json
        from typing import Any, List

        # 维护输入列表（用于多轮请求）
        input_list: List[Any] = list(input_user_content) if isinstance(input_user_content, list) else [input_user_content]

        # 跟踪是否有未处理的函数调用
        max_iterations = 5  # 防止无限循环
        iteration = 0

        assistant_content_items = []

        while iteration < max_iterations:
            iteration += 1
            print(f"\n[Tool Call Loop] Iteration {iteration}")

            # 发送请求到 API（带重试机制，处理网络不稳定情况）
            max_retries = 3
            retry_count = 0
            stream = None

            while retry_count < max_retries:
                try:
                    stream = self.client.responses.create(
                        model=self.model,
                        prompt=omit,
                        instructions=instructions if instructions else self.system_instruction,
                        conversation=self.current_conversation_id if self.current_conversation_id else omit,
                        previous_response_id=omit if self.current_conversation_id else self.current_response_id,
                        input=input_list,
                        stream=True,
                        tools=tools,
                        prompt_cache_key=self.user_name if self.user_name else omit,
                        reasoning=reasoning,
                        service_tier=service_tier,
                        include=["code_interpreter_call.outputs", "web_search_call.action.sources", "web_search_call.results", "file_search_call.results", "message.input_image.image_url"]
                    )
                    break  # 成功，跳出重试循环
                except Exception as e:
                    retry_count += 1
                    if retry_count >= max_retries:
                        raise  # 重试次数用尽，抛出异常
                    else:
                        print(f"[Retry] API 连接失败 (尝试 {retry_count}/{max_retries}): {str(e)}")
                        import time
                        time.sleep(2)  # 等待 2 秒后重试

            # 初始化显示变量
            temp_output_empty = None
            message_placeholder = None
            message_placeholder_text = ""
            current_message_item_id = None  # 新增：记录当前 message 的 item_id
            image_placeholder = None
            reasoning_summary_placeholder = None
            reasoning_summary_placeholder_text = ""
            code_interpreter_placeholder = None
            code_interpreter_placeholder_code = ""
            function_call_placeholder = None
            function_call_progress_bar = None
            current_function_name = None
            web_search_placeholder = None
            web_search_status = None  # 新增：保存 status 对象
            file_search_placeholder = None
            file_search_status = None  # 新增：保存 status 对象
            mcp_placeholder = None
            mcp_status = None  # MCP 工具调用状态

            # 收集此轮的输出项和函数调用
            response_output_items = []
            function_calls: dict[str, Any] = {}  # call_id -> function call info

            # 处理流
            for event in stream:
                match event.type:
                    case "response.created":
                        self.current_response_id = event.response.id
                        print(f"[Response] actual model: {getattr(event.response, 'model', 'unknown')}")

                    case "response.failed":
                        error_msg = event.response.error.message
                        assistant_content_items.append({
                            "type": "error_message",
                            "text": error_msg,
                            "role": "assistant"
                        })
                        print(f"[API Error] {error_msg}")

                    case "response.output_item.added":
                        print(f"[Stream] output_item.added: {event.item.type}, str type: '{str(event.item.type)}'")
                        response_output_items.append(event.item)

                        # 直接检查 item 是否有 name 属性（对于 function_call）
                        if hasattr(event.item, 'name') and event.item.name:
                            current_function_name = event.item.name
                            print(f"[Tool Call] Saved function name from item: {current_function_name}")

                        match str(event.item.type):
                            case "message":
                                # 直接创建 chat_message，不用 st.empty() 包裹
                                # （st.empty().chat_message() 在 column 内会导致 Bad delta path）
                                temp_output_empty = None
                                with st.chat_message("assistant"):
                                    message_placeholder = st.empty()
                                    message_placeholder_text = ""
                                    current_message_item_id = event.item.id if hasattr(event.item, 'id') else None

                            case "image_generation_call":
                                temp_output_empty = None
                                with st.chat_message("assistant"):
                                    image_cols = st.columns([2, 1])
                                    image_placeholder = image_cols[0].empty()

                            case "reasoning":
                                temp_output_empty = None
                                with st.chat_message("assistant"):
                                    reasoning_summary_placeholder = st.empty()
                                    reasoning_summary_placeholder_text = ""

                            case "code_interpreter_call":
                                temp_output_empty = None
                                with st.chat_message("assistant"):
                                    code_interpreter_placeholder = st.empty()
                                    code_interpreter_placeholder_code = ""

                            case "function_call":
                                print(f"[Stream] Matched function_call case!")
                                with st.chat_message("assistant"):
                                    function_call_placeholder = st.empty()
                                    function_call_progress_bar = function_call_placeholder.progress(0, text="🔄 Preparing to call custom tool...")

                            case "web_search_call":
                                print(f"[Stream] web_search_call added event triggered")
                                with st.chat_message("assistant"):
                                    web_search_placeholder = st.empty()
                                    web_search_status = web_search_placeholder.status("🔍 Web Search", state="running", expanded=False)

                            case "file_search_call":
                                print(f"[Stream] file_search_call added event triggered")
                                with st.chat_message("assistant"):
                                    file_search_placeholder = st.empty()
                                    file_search_status = file_search_placeholder.status("📂 File Search", state="running", expanded=False)

                            case "mcp_list_tools":
                                print(f"[Stream] mcp_list_tools added event triggered")
                                with st.chat_message("assistant"):
                                    mcp_placeholder = st.empty()
                                    mcp_status = mcp_placeholder.status(f"🔥 Firecrawl connecting...", state="running", expanded=False)

                            case "mcp_call":
                                print(f"[Stream] mcp_call added event triggered")
                                tool_name = event.item.name if hasattr(event.item, 'name') else "tool"
                                with st.chat_message("assistant"):
                                    mcp_placeholder = st.empty()
                                    mcp_status = mcp_placeholder.status(f"🔥 Firecrawl: {tool_name}", state="running", expanded=False)

                            case _:
                                print(f"[Stream] Unmatched item type: '{str(event.item.type)}'")


                    case "response.output_item.done":
                        print(f"[Stream] output_item.done: {event.item.type}")
                        match str(event.item.type):
                            case "message":
                                # 如果收集到了文本，手动构建完整的 message 对象
                                if message_placeholder_text:
                                    print(f"[Stream] Manually building message with text length: {len(message_placeholder_text)}")
                                    # 创建一个类似 ResponseOutputMessage 的字典结构
                                    class MessageItem:
                                        def __init__(self, item_id, text):
                                            self.type = "message"
                                            self.id = item_id
                                            self.role = "assistant"
                                            self.content = [type('obj', (object,), {'type': 'output_text', 'text': text})]

                                    assistant_content_items.append(MessageItem(current_message_item_id, message_placeholder_text))

                                message_placeholder = None
                                message_placeholder_text = ""
                                current_message_item_id = None
                            case "image_generation_call":
                                image_placeholder = None
                            case "reasoning":
                                if not (hasattr(event.item, 'summary') and event.item.summary):
                                    if reasoning_summary_placeholder:
                                        reasoning_summary_placeholder.empty()
                                reasoning_summary_placeholder = None
                                reasoning_summary_placeholder_text = ""
                            case "code_interpreter_call":
                                code_interpreter_placeholder = None
                                code_interpreter_placeholder_code = ""
                            case "web_search_call":
                                # 清空 web search 状态显示（完成后隐藏）
                                print(f"[Stream] web_search_call done event triggered, placeholder exists: {web_search_placeholder is not None}")
                                if web_search_placeholder:
                                    print(f"[Stream] Clearing web_search_placeholder")
                                    web_search_placeholder.empty()
                                else:
                                    print(f"[Stream] Warning: web_search_placeholder is None!")
                                web_search_placeholder = None
                                web_search_status = None
                            case "file_search_call":
                                # 清空 file search 状态显示（完成后隐藏）
                                print(f"[Stream] file_search_call done event triggered, placeholder exists: {file_search_placeholder is not None}")
                                if file_search_placeholder:
                                    print(f"[Stream] Clearing file_search_placeholder")
                                    file_search_placeholder.empty()
                                else:
                                    print(f"[Stream] Warning: file_search_placeholder is None!")
                                file_search_placeholder = None
                                file_search_status = None

                    case "response.output_text.delta":
                        message_placeholder = message_placeholder if message_placeholder else st.empty()
                        message_placeholder_text += event.delta
                        message_placeholder.markdown(custom_markdown_text(message_placeholder_text + "▌"))

                    case "response.image_generation_call.partial_image":
                        image_base64 = event.partial_image_b64
                        image_bytes = base64.b64decode(image_base64)
                        img = Image.open(io.BytesIO(image_bytes))
                        image_placeholder = image_placeholder if image_placeholder else st.columns([2, 1])[0].empty()
                        with image_placeholder:
                            st.image(img, use_container_width=True)

                    case "response.reasoning_summary_text.delta":
                        reasoning_summary_placeholder = reasoning_summary_placeholder if reasoning_summary_placeholder else st.empty()
                        reasoning_summary_placeholder_text += event.delta
                        reasoning_summary_placeholder.markdown(f"<details open style='color:gray;background-color:#f8f8f8;padding:8px;border-radius:4px;font-style:italic;'><summary style='cursor:pointer;outline:none;'>Reasoning summary</summary>{reasoning_summary_placeholder_text}</details>", unsafe_allow_html=True)

                    case "response.code_interpreter_call_code.delta":
                        if code_interpreter_placeholder:
                            with code_interpreter_placeholder.expander("code_interpreter_call code", expanded=False):
                                code_interpreter_placeholder_code += str(event.delta)
                                st.code(code_interpreter_placeholder_code)

                    case "response.function_call_arguments.delta":
                        # 参数流增量（只用于日志）
                        pass

                    case "response.function_call_arguments.done":
                        # 函数调用完成，保存信息供后续处理
                        function_name = current_function_name if current_function_name else event.name
                        arguments_str = event.arguments
                        item_id = event.item_id

                        if not function_name:
                            print(f"[Tool Call] Warning: function_name is None")
                            continue

                        # 查找对应的 call_id（需要从 response_output_items 中获取）
                        call_id = None
                        for item in response_output_items:
                            if hasattr(item, 'id') and item.id == item_id and hasattr(item, 'call_id'):
                                call_id = item.call_id
                                break

                        if not call_id:
                            print(f"[Tool Call] Warning: call_id not found for item_id {item_id}")
                            continue

                        print(f"[Tool Call] Function arguments done: {function_name}, call_id: {call_id}")

                        # 保存函数调用信息
                        function_calls[call_id] = {
                            "call_id": call_id,
                            "name": function_name,
                            "arguments": arguments_str,
                            "item_id": item_id
                        }

                    # MCP tool events (server-side execution, no local handling needed)
                    case "response.mcp_list_tools.completed":
                        print(f"[MCP] Tool list completed")
                        if mcp_status:
                            mcp_status.update(label="🔥 Firecrawl ready", state="complete")
                            mcp_status = None
                        if mcp_placeholder:
                            mcp_placeholder.empty()
                            mcp_placeholder = None

                    case "response.mcp_list_tools.failed":
                        print(f"[MCP] Tool list failed")
                        if mcp_status:
                            mcp_status.update(label="🔥 Firecrawl: connection failed", state="error")
                            mcp_status = None

                    case "response.mcp_call.completed":
                        print(f"[MCP] Call completed")
                        if mcp_status:
                            tool_name = event.name if hasattr(event, 'name') else ""
                            label = f"🔥 Firecrawl: {tool_name} done" if tool_name else "🔥 Firecrawl: done"
                            mcp_status.update(label=label, state="complete")
                            mcp_status = None
                        if mcp_placeholder:
                            mcp_placeholder.empty()
                            mcp_placeholder = None

                    case "response.mcp_call.failed":
                        print(f"[MCP] Call failed")
                        if mcp_status:
                            mcp_status.update(label="🔥 Firecrawl: call failed", state="error")
                            mcp_status = None

                    case "response.mcp_call.in_progress":
                        print(f"[MCP] Call in progress")

                    case "response.mcp_call_arguments.delta":
                        # MCP 参数流增量（只用于日志）
                        pass

                    case "response.mcp_call_arguments.done":
                        # MCP 参数完成（服务端自动执行，无需本地处理）
                        print(f"[MCP] Call arguments done")

            # 检查是否有函数调用需要处理
            if function_calls:
                print(f"\n[Tool Call Loop] Found {len(function_calls)} function call(s) to process")

                # 执行所有函数调用
                function_outputs = {}
                for call_id, func_info in function_calls.items():
                    function_name = func_info["name"]
                    arguments_str = func_info["arguments"]

                    tool_display_name = self._get_tool_display_name(function_name)
                    print(f"[Tool Execution] Executing {function_name}...")

                    # 更新进度条
                    if function_call_placeholder and function_call_progress_bar:
                        function_call_progress_bar.progress(0.3, text=f"🔧 Executing {tool_display_name}...")

                    try:
                        arguments = json.loads(arguments_str) if arguments_str else {}

                        # 更新进度条
                        if function_call_progress_bar:
                            function_call_progress_bar.progress(0.6, text=f"⚙️ {tool_display_name} processing...")

                        # 执行工具
                        tool_result = self._execute_custom_tool(function_name, arguments)

                        print(f"[Tool Execution] Result: {tool_result[:200] if isinstance(tool_result, str) else tool_result}")

                        # 更新进度条完成
                        if function_call_progress_bar:
                            function_call_progress_bar.progress(1.0, text=f"✅ {tool_display_name} completed")

                        # 保存结果
                        function_outputs[call_id] = tool_result

                        # 清空进度条
                        if function_call_placeholder:
                            function_call_placeholder.empty()

                    except Exception as e:
                        error_msg = f"Tool execution failed: {str(e)}"
                        print(f"[Tool Execution] Error: {error_msg}")
                        import traceback
                        traceback.print_exc()

                        if function_call_placeholder:
                            function_call_placeholder.empty()
                            with st.chat_message("assistant"):
                                st.error(f"❌ {tool_display_name} failed: {error_msg}")

                        function_outputs[call_id] = json.dumps({"error": error_msg})

                # 构建第二次请求的输入
                # 注意：不要重新发送 API 的输出项，只需发送函数执行结果
                # API 会通过 previous_response_id 或 conversation_id 关联上下文

                # 添加函数执行结果
                for call_id, output in function_outputs.items():
                    input_list.append({
                        "type": "function_call_output",
                        "call_id": call_id,
                        "output": output
                    })

                print(f"[Tool Call Loop] Prepared second request with {len(function_outputs)} tool result(s)")
                # 继续下一轮循环，处理模型对工具结果的回复

            else:
                # 没有函数调用，保存所有输出项并结束
                # 注意：message 类型的项已经在流式处理时手动构建并添加了，这里只添加非 message 类型的项
                print(f"[Tool Call Loop] No function calls, processing final output")
                for item in response_output_items:
                    # 跳过 message 类型（已经手动构建）
                    if str(item.type) != "message":
                        assistant_content_items.append(item)
                break

        # 消化对话项并添加到历史
        result = self.digest_conversation_items(assistant_content_items)
        self._chat_history.extend(result)

    def _chat_history_remove_error_message(self):
        self._chat_history = [chat_item for chat_item in self._chat_history if chat_item.get('type', '') != 'error_message']

    def generate_content(
            self,
            prompt: str,
            files: list[UploadedFile] = None,
            instructions: str | None | Omit = omit,
            model: str | None = None,
            reasoning_effort: LITERAL_REASONING_EFFORT| NotGiven | None = None,
            service_tier: Literal["auto", "default", "flex", "scale", "priority"] | None | Omit = omit,
            enable_file_search: bool = False,
            enable_code_interpreter: bool = False,
            enable_web_search: bool = False,
            web_search_allow_domains: list[str] = None,
            enable_image_generation: bool = False,
            image_model: str = "gpt-image-1.5",
            size: LITERAL_SIZE = "auto",
            quality: LITERAL_QUALITY = "auto",
            enable_ppt_generation: bool = False,
            # Custom tools parameters
            enable_google_search: bool = False,
            enable_firecrawl: bool = False,
            enable_deep_research: bool = False,
            enable_file_search_pro: bool = False,
            enable_google_file_search: bool = False
    ):
        self.is_generating = True
        try:
            self._generate_content_inner(
                prompt=prompt, files=files, instructions=instructions, model=model,
                reasoning_effort=reasoning_effort, service_tier=service_tier,
                enable_file_search=enable_file_search, enable_code_interpreter=enable_code_interpreter,
                enable_web_search=enable_web_search, web_search_allow_domains=web_search_allow_domains,
                enable_image_generation=enable_image_generation, image_model=image_model, size=size, quality=quality,
                enable_ppt_generation=enable_ppt_generation,
                enable_google_search=enable_google_search, enable_firecrawl=enable_firecrawl,
                enable_deep_research=enable_deep_research,
                enable_file_search_pro=enable_file_search_pro,
                enable_google_file_search=enable_google_file_search
            )
        finally:
            self.is_generating = False

    def _generate_content_inner(
            self,
            prompt: str,
            files: list[UploadedFile] = None,
            instructions: str | None | Omit = omit,
            model: str | None = None,
            reasoning_effort: LITERAL_REASONING_EFFORT| NotGiven | None = None,
            service_tier: Literal["auto", "default", "flex", "scale", "priority"] | None | Omit = omit,
            enable_file_search: bool = False,
            enable_code_interpreter: bool = False,
            enable_web_search: bool = False,
            web_search_allow_domains: list[str] = None,
            enable_image_generation: bool = False,
            image_model: str = "gpt-image-1.5",
            size: LITERAL_SIZE = "auto",
            quality: LITERAL_QUALITY = "auto",
            enable_ppt_generation: bool = False,
            # Custom tools parameters
            enable_google_search: bool = False,
            enable_firecrawl: bool = False,
            enable_deep_research: bool = False,
            enable_file_search_pro: bool = False,
            enable_google_file_search: bool = False
    ):
        if model:
            self.model = model
        print(f"generate_content -> prompt: {prompt}, model: {self.model}, reasoning_effort: {reasoning_effort}, service_tier: {service_tier}, self.current_response_id: {self.current_response_id}, self.current_conversation_id: {self.current_conversation_id}")

        uploaded_ci_only_file_names = []
        has_file_search_eligible_upload = False
        if files:
            for uploaded_file in files:
                ext = str(uploaded_file.name).lower().split(".")[-1]
                if ext in CODE_INTERPRETER_FILES_TYPE_DIFF:
                    uploaded_ci_only_file_names.append(uploaded_file.name)
                elif uploaded_file.type.lower() == "application/pdf" or not uploaded_file.type.lower().startswith("image"):
                    has_file_search_eligible_upload = True

        self._chat_history_remove_error_message()

        if self.enable_conversation and self.prompt_id and not self.current_conversation_id:
            # identify conversation name
            # conversation_name = identify_conversation_name(message_text=prompt) if prompt else "Upload file(s)"
            message_text = prompt if prompt else "Upload file(s)"
            self.create_conversation(message_text=message_text)

        if not prompt and files:
            prompt = self.DEFAULT_PROMPT_FOR_FILE_PROCESSING

        tools = []
        # check container status, re-create if expire
        if enable_code_interpreter:
            need_create = False
            if self.current_container_id:
                if not self.OpenaiClient.validate_container(container_id=self.current_container_id):
                    need_create = True
            else:
                # code interpreter support most of the file
                # 合并 bot 级别 + thread 级别 + 新上传文件来判断是否需要创建 container
                combined_ci_file_ids = self.bot_code_interpreter_file_ids + self.thread_code_interpreter_file_ids
                if combined_ci_file_ids or self.code_interpreter_file_ids or files:
                    need_create = True

            if need_create:
                # recreate new container with combined bot + thread file IDs
                combined_file_ids = self.bot_code_interpreter_file_ids + self.thread_code_interpreter_file_ids
                # fallback: 兼容其他页面仍使用 code_interpreter_file_ids 的场景
                if not combined_file_ids and self.code_interpreter_file_ids:
                    combined_file_ids = self.code_interpreter_file_ids
                now_timestamp = datetime.now(UTC).timestamp()
                try:
                    created_container = self.OpenaiClient.create_container(name=f'{self.func_group}_container_{now_timestamp}', file_ids=combined_file_ids if combined_file_ids else omit)
                except Exception as container_error:
                    # If file_ids contain stale/deleted files, retry without them
                    if combined_file_ids and ('not found' in str(container_error).lower() or '404' in str(container_error)):
                        print(f"[Chat] Container creation failed with stale file IDs, retrying without file_ids: {container_error}")
                        combined_file_ids = []
                        created_container = self.OpenaiClient.create_container(name=f'{self.func_group}_container_{now_timestamp}', file_ids=omit)
                    else:
                        raise
                self.current_container_id = created_container.id

                # 获取文件名映射，供模型用真实文件名引用文件
                for fid in combined_file_ids:
                    if fid not in self._file_id_name_map:
                        try:
                            file_obj = self.OpenaiClient.retrieve_file(file_id=fid, _openai_client=self.client)
