        enable_ppt_generation: bool = False,
        # Custom tools parameters
        enable_google_search: bool = False,
        enable_firecrawl: bool = False,
        enable_deep_research: bool = False,
        enable_file_search_pro: bool = False,
        enable_google_file_search: bool = False
):
    if model:
        self.model = model
    print(f"generate_content -> prompt: {prompt}, model: {self.model}, reasoning_effort: {reasoning_effort}, service_tier: {service_tier}, self.current_response_id: {self.current_response_id}, self.current_conversation_id: {self.current_conversation_id}")

    uploaded_ci_only_file_names = []
    has_file_search_eligible_upload = False
    if files:
        for uploaded_file in files:
            ext = str(uploaded_file.name).lower().split(".")[-1]
            if ext in CODE_INTERPRETER_FILES_TYPE_DIFF:
                uploaded_ci_only_file_names.append(uploaded_file.name)
            elif uploaded_file.type.lower() == "application/pdf" or not uploaded_file.type.lower().startswith("image"):
                has_file_search_eligible_upload = True

    self._chat_history_remove_error_message()

    if self.enable_conversation and self.prompt_id and not self.current_conversation_id:
        # identify conversation name
        # conversation_name = identify_conversation_name(message_text=prompt) if prompt else "Upload file(s)"
        message_text = prompt if prompt else "Upload file(s)"
        self.create_conversation(message_text=message_text)

    if not prompt and files:
        prompt = self.DEFAULT_PROMPT_FOR_FILE_PROCESSING

    tools = []
    # check container status, re-create if expire
    if enable_code_interpreter:
        need_create = False
        if self.current_container_id:
            if not self.OpenaiClient.validate_container(container_id=self.current_container_id):
                need_create = True
        else:
            # code interpreter support most of the file
            # 合并 bot 级别 + thread 级别 + 新上传文件来判断是否需要创建 container
            combined_ci_file_ids = self.bot_code_interpreter_file_ids + self.thread_code_interpreter_file_ids
            if combined_ci_file_ids or self.code_interpreter_file_ids or files:
                need_create = True

        if need_create:
            # recreate new container with combined bot + thread file IDs
            combined_file_ids = self.bot_code_interpreter_file_ids + self.thread_code_interpreter_file_ids
            # fallback: 兼容其他页面仍使用 code_interpreter_file_ids 的场景
            if not combined_file_ids and self.code_interpreter_file_ids:
                combined_file_ids = self.code_interpreter_file_ids
            now_timestamp = datetime.now(UTC).timestamp()
            try:
                created_container = self.OpenaiClient.create_container(name=f'{self.func_group}_container_{now_timestamp}', file_ids=combined_file_ids if combined_file_ids else omit)
            except Exception as container_error:
                # If file_ids contain stale/deleted files, retry without them
                if combined_file_ids and ('not found' in str(container_error).lower() or '404' in str(container_error)):
                    print(f"[Chat] Container creation failed with stale file IDs, retrying without file_ids: {container_error}")
                    combined_file_ids = []
                    created_container = self.OpenaiClient.create_container(name=f'{self.func_group}_container_{now_timestamp}', file_ids=omit)
                else:
                    raise
            self.current_container_id = created_container.id

            # 获取文件名映射，供模型用真实文件名引用文件
            for fid in combined_file_ids:
                if fid not in self._file_id_name_map:
                    try:
                        file_obj = self.OpenaiClient.retrieve_file(file_id=fid, _openai_client=self.client)
                        if file_obj and hasattr(file_obj, 'filename'):
                            self._file_id_name_map[fid] = file_obj.filename
                    except Exception:
                        pass

        if self.current_container_id:
            tools.append(
                {
                    "type": "code_interpreter",
                    "container": self.current_container_id
                }
            )
        else:
            tools.append(
                {
                    "type": "code_interpreter",
                    "container": {
                        "type": "auto"
                    }
                }
            )

    input_user_content = self._append_user_content(prompt=prompt, files=files, enable_code_interpreter=enable_code_interpreter, enable_file_search=enable_file_search)

    if enable_file_search and not (uploaded_ci_only_file_names and not has_file_search_eligible_upload and enable_code_interpreter):
        vs_ids = []
        if self.bot_vector_store_id:
            vs_ids.append(self.bot_vector_store_id)
        if self.thread_vector_store_id:
            vs_ids.append(self.thread_vector_store_id)
        # fallback: 兼容其他页面仍使用 current_vector_store_id 的场景
        if not vs_ids and self.current_vector_store_id:
            vs_ids.append(self.current_vector_store_id)
        if vs_ids:
            tools.append(
                {
                    "type": "file_search",
                    "vector_store_ids": vs_ids
                }
            )

    # if enable_code_interpreter:
    #     tools.append(
    #         {
    #             "type": "code_interpreter",
    #             "container": {
    #                 "type": "auto",
    #                 "file_ids": self.code_interpreter_file_ids
    #             }
    #         }
    #     )
    if enable_web_search:
        tool_web_search = {
            "type": "web_search"
        }
        if web_search_allow_domains:
            tool_web_search["filters"] = {
                "allowed_domains": web_search_allow_domains
            }
        tools.append(tool_web_search)
        # {
        #       "type": "web_search",
        #       "filters": {
        #         "allowed_domains": [
        #           "pubmed.ncbi.nlm.nih.gov",
        #           "clinicaltrials.gov",
        #           "www.who.int",
        #           "www.cdc.gov",
        #           "www.fda.gov"
        #         ]
        #       }
        #     }

    if enable_image_generation:
        tools.append(
            {
                "type": "image_generation",
                "model": image_model,
                "action": "auto",
                "size": size,
                "quality": quality,
                "partial_images": 2
            }
        )

    # add ppt tool
    if enable_ppt_generation:
        print('')

    # ==================== Custom Tools (Responses API format with Strict Mode) ====================
    if enable_google_search:
        tools.append({
            "type": "function",
            "name": "google_search",
            "description": "Search Google for current information. Use this when you need up-to-date information or to find specific web pages.",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {
                        "type": "string",
                        "description": "The search query to send to Google"
                    }
                },
                "required": ["query"],
                "additionalProperties": False
            },
            "strict": True
        })

    if enable_firecrawl:
        firecrawl_api_key = os.environ.get("FIRECRAWL_API_KEY")
        if firecrawl_api_key:
            tools.append({
                "type": "mcp",
                "server_label": "firecrawl",
                "server_url": f"https://mcp.firecrawl.dev/{firecrawl_api_key}/v2/mcp",
                "require_approval": "never"
            })
        else:
            print("[Warning] FIRECRAWL_API_KEY not set — Firecrawl MCP tool will not be available")

    if enable_deep_research:
        tools.append({
            "type": "function",
            "name": "deep_research",
            "description": "Conduct deep research on a topic using multiple sources and synthesize findings.",
            "parameters": {
                "type": "object",
                "properties": {
                    "topic": {
                        "type": "string",
                        "description": "The research topic or question"
                    }
                },
                "required": ["topic"],
                "additionalProperties": False
            },
            "strict": True
        })

    if enable_file_search_pro:
        tools.append({
            "type": "function",
            "name": "file_search_pro",
            "description": "Search and retrieve content from the bot's knowledge base files (synced from SharePoint/cloud storage). Use this tool whenever the user asks about file content, requests information from documents, asks what files are available, or needs to find specific information. These files are NOT in the conversation - they are in a separate repository that only this tool can access.",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {
                        "type": "string",
                        "description": "Search query describing what information to find in the knowledge base files"
                    }
                },
                "required": ["query"],
                "additionalProperties": False
            },
            "strict": True
        })

    if enable_google_file_search:
        tools.append({
            "type": "function",
            "name": "google_file_search",
            "description": "Search the user's uploaded documents and knowledge base. This is the ONLY way to access the files that have been uploaded to this assistant. You MUST call this tool whenever the user asks about file content, document information, uploaded files, or any question that might be answered by the knowledge base. Do NOT claim you have no files — always search first.",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {
                        "type": "string",
                        "description": "Search query describing what information to find in the uploaded documents"
                    }
                },
                "required": ["query"],
                "additionalProperties": False
            },
            "strict": True
        })

    # if not thinking model, override reasoning to not_given
    # if not (str(self.model).startswith('gpt') or re.match(r'^o\d+', str(self.model))):
    #     reasoning = NOT_GIVEN
    reasoning = omit
    if self.model.startswith('gpt-5') or re.match(r'^o\d+', self.model):
        if reasoning_effort and isinstance(reasoning_effort, str):
            reasoning = {"effort": reasoning_effort, "summary": "auto"}
        else:
            reasoning = None
    # print(f'reasoning_effort: {reasoning_effort}, reasoning: {reasoning}')

    # 将文件名映射注入 instructions，帮助模型用真实文件名引用文件
    if self._file_id_name_map:
        file_lines = [f"  {fid} -> {fname}" for fid, fname in self._file_id_name_map.items()]
        file_mapping_note = "\n\n[File Reference - Always use the original filename when referring to files]\n" + "\n".join(file_lines)
        if instructions and instructions is not omit:
            instructions = str(instructions) + file_mapping_note
        elif self.system_instruction:
            instructions = str(self.system_instruction) + file_mapping_note
        else:
            instructions = file_mapping_note

    # 为自定义文件搜索工具注入使用引导
    if enable_google_file_search:
        fs_note = "\n\n[CRITICAL INSTRUCTION] This assistant has uploaded documents in its knowledge base. The ONLY way to access these documents is through the `google_file_search` tool. You MUST call `google_file_search` when:\n- The user asks about file content or uploaded documents\n- The user asks you to summarize, list, or search files\n- The user asks any question that could be answered by the knowledge base\n- The user mentions credentials, passwords, accounts, or any stored information\nNEVER say you cannot access files or that no files are detected. ALWAYS call `google_file_search` first to search the knowledge base."
        if instructions and instructions is not omit:
            instructions = str(instructions) + fs_note
        elif self.system_instruction:
            instructions = str(self.system_instruction) + fs_note
        else:
            instructions = fs_note

    if enable_file_search_pro:
        fs_pro_note = "\n\n[Important] You have a knowledge base with uploaded documents. When users ask about file content, uploaded documents, or need information from files, you MUST use the `file_search_pro` tool to search the knowledge base. Do not say you cannot access files — always search first."
        if instructions and instructions is not omit:
            instructions = str(instructions) + fs_pro_note
        elif self.system_instruction:
            instructions = str(self.system_instruction) + fs_pro_note
        else:
            instructions = fs_pro_note

    if uploaded_ci_only_file_names and enable_code_interpreter:
        ci_note = (
            "\n\n[Critical Tool Routing]\n"
            f"The user uploaded code-interpreter files in this turn: {', '.join(uploaded_ci_only_file_names)}.\n"
            "For questions about these uploaded files, you MUST use the code_interpreter tool with the current container.\n"
            "Do NOT use file_search to answer questions about these uploaded files."
        )
        if instructions and instructions is not omit:
            instructions = str(instructions) + ci_note
        elif self.system_instruction:
            instructions = str(self.system_instruction) + ci_note
        else:
            instructions = ci_note

    self._response_chat_stream(input_user_content, tools=tools, reasoning=reasoning, service_tier=service_tier, instructions=instructions)
    print(f'new_response_id: {self.current_response_id}')

