def digest_conversation_items(self, conversation_items):
    chat_items = []
    temp_container_set = set()
    have_code_interpreter_call = False
    for conversation_item in conversation_items:
        # skip system message
        match conversation_item.type:
            # digest user input text and assistant output text
            case "message":
                # print(conversation_item)
                if hasattr(conversation_item, "role") and conversation_item.role == "system":
                    continue
                if conversation_item.content:
                    message_item_content = []
                    for omic in conversation_item.content:
                        if hasattr(omic, "type"):
                            match omic.type:
                                case "input_text" | "error_message":
                                    if hasattr(omic, "text"):
                                        message_item_content.append(
                                            {
                                                "type": omic.type,
                                                "text": omic.text
                                            }
                                        )
                                case "output_text":
                                    if hasattr(omic, "text") and omic.text:
                                        message_item_content.append(
                                            {
                                                "type": omic.type,
                                                "annotations": omic.annotations if hasattr(omic,"annotations") else [],
                                                "logprobs": omic.logprobs if hasattr(omic, "logprobs") else [],
                                                "text": omic.text
                                            }
                                        )
                                case "input_image":
                                    if hasattr(omic, "file_id") or hasattr(omic, "image_url"):
                                        message_item_content.append(
                                            {
                                                "type": "input_image",
                                                "file_id": omic.file_id if hasattr(omic, "file_id") else None,
                                                "image_url": omic.image_url if hasattr(omic, "image_url") else None
                                            }
                                        )
                                case "input_file":
                                    if hasattr(omic, "file_id"):
                                        message_item_content.append(
                                            {
                                                "type": "input_file",
                                                "file_id": omic.file_id,
                                            }
                                        )

                    chat_items.append(
                        {
                            "id": conversation_item.id if hasattr(conversation_item, "id") else None,
                            "type": "message",
                            "content": message_item_content,
                            "role": conversation_item.role
                        }
                    )
            case "reasoning":
                print(conversation_item)
                # if conversation_item.summary or conversation_item.content:
                chat_items.append(
                    {
                        "id": conversation_item.id if hasattr(conversation_item, "id") else None,
                        "type": "reasoning",
                        "summary": [
                            {
                                "type": omic.type,
                                "text": omic.text
                            }
                            for omic in conversation_item.summary
                        ] if hasattr(conversation_item, "summary") and conversation_item.summary else [],
                        "content": [
                            {
                                "type": omic.type,
                                "text": omic.text
                            }
                            for omic in conversation_item.content
                        ] if hasattr(conversation_item, "content") and conversation_item.content else []
                    }
                )
            case "image_generation_call":
                # if conversation_item.result:
                chat_items.append(
                    {
                        "id": conversation_item.id if hasattr(conversation_item, "id") else None,
                        "type": "image_generation_call",
                        "result": conversation_item.result if hasattr(conversation_item,"result") and conversation_item.result else None,
                        "output_format": conversation_item.output_format if hasattr(conversation_item,"output_format") and conversation_item.output_format else None,
                        "revised_prompt": conversation_item.revised_prompt if hasattr(conversation_item,"revised_prompt") and conversation_item.revised_prompt else None,
                    }
                )

            case "code_interpreter_call":
                have_code_interpreter_call = True
                if hasattr(conversation_item,"container_id") and conversation_item.container_id:
                    chat_items.append(
                        {
                            "id": conversation_item.id if hasattr(conversation_item, "id") else None,
                            "type": "code_interpreter_call",
                            "code": conversation_item.code if hasattr(conversation_item, "code") else None,
                            "container_id": conversation_item.container_id,
                            "outputs": conversation_item.outputs if hasattr(conversation_item, "outputs") else None
                        }
                    )
                    if conversation_item.container_id and str(conversation_item.container_id).strip(' ') != '':
                        self.current_container_id = str(conversation_item.container_id)


            case "web_search_call":
                if hasattr(conversation_item, "action") and conversation_item.action and hasattr(conversation_item.action, "query") and conversation_item.action.query and str(conversation_item.action.query).strip(' ')!='':
                    # st.caption(f"Execute web search - Query '{conversation_item.action.query} '...")
                    chat_items.append(
                        {
                            "id": conversation_item.id if hasattr(conversation_item, "id") else None,
                            "type": "web_search_call",
                            "code": conversation_item.code if hasattr(conversation_item, "code") else None,
                            "action": {
                                "type": conversation_item.action.type if hasattr(conversation_item.action, 'type') else 'search',
                                "query": conversation_item.action.query
                            }
                        }
                    )

            # case "file_search_call":

            case "mcp_list_tools":
                # MCP 工具发现记录 — 跳过，无需在聊天记录中展示
                pass

            case "mcp_call":
                chat_items.append({
                    "id": conversation_item.id if hasattr(conversation_item, "id") else None,
                    "type": "mcp_call",
                    "server_label": conversation_item.server_label if hasattr(conversation_item, "server_label") else None,
                    "name": conversation_item.name if hasattr(conversation_item, "name") else None,
                    "arguments": conversation_item.arguments if hasattr(conversation_item, "arguments") else None,
                    "output": conversation_item.output if hasattr(conversation_item, "output") else None,
                    "error": conversation_item.error if hasattr(conversation_item, "error") else None,
                })

    # get_container_files if code interpreter run
    try:
        if have_code_interpreter_call:
            container_files = []
            if self.current_container_id:
                container_files = self.OpenaiClient.retrieve_container_files(container_id=self.current_container_id)
            self.current_container_files = container_files
            # self.current_container_files = [cf for cf in container_files if cf.source=="assistant" and cf.path and cf.path != ""]
    except Exception as get_container_files_error:
        print(traceback.format_exc())
    return chat_items

