    if self.current_vector_store_files:
        valid_vector_store_file_list = []
        for vsf in self.current_vector_store_files:
            retrieved_file = self.OpenaiClient.retrieve_file(file_id=vsf.id, _openai_client=self.client)
            if retrieved_file:
                valid_vector_store_file_list.append(
                    {
                        "file_id": vsf.id,
                        "vector_store_file": vsf,
                        "file": retrieved_file
                    }
                )
        if valid_vector_store_file_list:
            empty_vector_store_files = st.empty()
            # vector_store_files_container = empty_vector_store_files.container(border=True)
            vector_store_files_container = empty_vector_store_files.expander("Vector store files", expanded= False, icon='📋')
            with vector_store_files_container:
                for valid_vector_store_file_index, valid_vector_store_file in enumerate(valid_vector_store_file_list):
                    vector_store_file: VectorStoreFile = valid_vector_store_file.get("vector_store_file")
                    file: FileObject = valid_vector_store_file.get("file")
                    vector_store_file_cols = st.columns([3, 1])
                    with vector_store_file_cols[0]:
                        help_str = f"file_id: {vector_store_file.id}  \nstatus: {vector_store_file.status}  \nusage_bytes: {vector_store_file.usage_bytes}  \ncreated_at: {auth.localize_datetime(datetime.fromtimestamp(vector_store_file.created_at, tz=timezone.utc))}"
                        if str(vector_store_file.status) == 'completed':
                            st.markdown(f":green-background[{file.filename}] ✅", help=help_str)
                        else:
                            st.markdown(f":red-background[{file.filename}] ⚠️", help=help_str)
                    with vector_store_file_cols[1]:
                        if st.button("Delete", key=f"btn_vector_store_file_delete_{valid_vector_store_file_index}",type="primary"):
