                                print("skip deleting bot vector store file")
                            else:
                                try:
                                    if self.current_vector_store_id:
                                        self.OpenaiClient.delete_vector_store_file(vector_store_id=self.current_vector_store_id,file_id=vector_store_file.id)
                                    self.OpenaiClient.client_delete_file(file_id=vector_store_file.id)
