def js_override_st_button_onclick_v1(container_key: str, copied_text: str):
    html_js = '''
            <script>
            var xpath = "//div[contains(@class, '%s')]//button[div/p[contains(text(), 'Copy')]]";
            var copyText = %s;

            var copy;
            setTimeout(function() {
                copy = window.parent.document.evaluate(xpath, window.parent.document, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null).singleNodeValue;
                copy.style.display = "none";
                var copy_parent = copy.parentElement;
                var copy_clone = copy.cloneNode(true);
                copy_clone.style.display = "";
                copy_parent.appendChild(copy_clone);

                copy_clone.addEventListener("click", copyToClipboard);
                console.log('Clone succeeded!');

                // Function to sync classes
                function syncClasses() {
                    copy_clone.className = copy.className;
                }

                // Create a MutationObserver to watch for changes in copy's class
                const observer = new MutationObserver(syncClasses);
                // Configure the observer to listen for attribute changes
                observer.observe(copy, {
                    attributes: true, // Listen for attribute changes
                    attributeFilter: ['class'] // Specifically, listen for changes to the class attribute
                });
            }, 500); // Waiting for 0.5 second

            function copyToClipboard() {
                parent.navigator.clipboard.writeText(copyText).then(function() {
                    console.log('Copy succeeded!');
                }, function(err) {
                    console.error('Could not copy text: ', err);
                    alert(err);
                });
            }



            </script>
            ''' % (container_key, json.dumps(copied_text).replace('/', '\/'))
    # print(json.dumps(copied_text))
    return html_js

