class DifyClient:
    def __init__(self, api_key: str, user_id: str = 'system_user', user_name: str = 'system_user', user_email: str = None):
        """
        初始化Dify客户端

        Args:
            api_key: Dify平台的API密钥或者我们生成的唯一ID
            user_id: 用户ID
            user_name: 用户名
            user_email: 用户邮箱
        """
        # 检查是否需要获取真实的Dify API密钥
        from utils.dify_key_manager import is_dify_id, get_real_dify_key

        # 如果传入的是我们生成的唯一ID，则获取真实的Dify API密钥
        if is_dify_id(api_key):
            real_api_key = get_real_dify_key(api_key)
            if real_api_key:
                api_key = real_api_key

        self.api_key = api_key
        self.base_url = "https://api.dify.ai/v1"
        self.headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json"
        }
        self.user_id = user_id
        self.user_name = user_name
        self.user_email = user_email if user_email else f"{user_id}@example.com"
        self.conversation_id = ""
        self.files = []
        self.file_upload_config = None  # 缓存文件上传配置

    def upload_file(self, uploaded_file: UploadedFile) -> Dict[str, Any]:
        """
        上传文件到Dify平台

        Args:
            uploaded_file: 要上传的文件

        Returns:
            Dict[str, Any]: 上传结果，包含文件ID等信息
        """
        try:

            file_content = uploaded_file.getvalue()
            file_name = uploaded_file.name
            file_type = uploaded_file.type

            upload_url = f"{self.base_url}/files/upload"
            headers = {
                "Authorization": f"Bearer {self.api_key}"
            }

            files = {
                'file': (file_name, file_content, file_type)
            }

            data = {
                'user': self.user_id
            }
            response = requests.post(upload_url, headers=headers, files=files, data=data)

            # 接受 200 和 201 状态码作为成功响应
            if response.status_code in [200, 201]:
                result = response.json()

                file_id = result.get('id')
                if file_id:
                    db_file_id = insert_file(
                        file_id=file_id,
                        file_name=file_name,
                        file_bytes=len(file_content),
                        file_status="active",
                        file_purpose="dify_upload",
                        attached_to="Dify",
                        attached_to_id=self.user_id
                    )
                    self.files.append({
                        "id": file_id,
                        "name": file_name,
                        "type": file_type
                    })

                return result
            else:
                st.error(f"Failed to upload file: {response.status_code} - {response.text}")
                return {"error": f"Failed to upload file: {response.status_code} - {response.text}"}
        except Exception as e:
            st.error(f"Failed to upload file: {str(e)}")
            return {"error": str(e)}

    def create_conversation(self) -> str:
        """
        创建新的对话会话

        Returns:
            str: 会话ID
        """
        self.conversation_id = ""
        self.files = []
        return self.conversation_id

    def get_file_upload_config(self) -> Dict[str, Any]:
        """
        获取文件上传配置

        Returns:
            Dict[str, Any]: 文件上传配置，包含允许的文件类型等信息
        """
        try:
            # 如果已经缓存了文件上传配置，直接返回
            if self.file_upload_config is not None:
                return self.file_upload_config

            # 请求 Dify API 获取文件上传配置
            config_url = f"{self.base_url}/parameters"
            response = requests.get(config_url, headers=self.headers)

            if response.status_code == 200:
                result = response.json()
                # 提取文件上传相关配置
                file_config = {
                    "enable_chat_file": False,  # 默认不允许上传文件
                    "chat_accepted_files_type": []  # 默认不接受任何文件类型
                }

                # 解析 Dify 返回的配置
                if "file_upload" in result:
                    file_config["enable_chat_file"] = result["file_upload"].get("enabled", False)
                    file_config["chat_accepted_files_type"] = result["file_upload"].get("allowed_types", [])

                # 缓存配置
                self.file_upload_config = file_config
                return file_config
            else:
                error_msg = f"Failed to get file upload config: {response.status_code} - {response.text}"
                print(error_msg)
                return {
                    "enable_chat_file": False,
                    "chat_accepted_files_type": [],
                    "error": error_msg
                }
        except Exception as e:
            error_msg = f"Failed to get file upload config: {str(e)}"
            print(error_msg)
            return {
                "enable_chat_file": False,
                "chat_accepted_files_type": [],
                "error": error_msg
            }

    def get_conversation_history(self) -> Dict[str, Any]:
        """
        获取对话历史

        Returns:
            Dict[str, Any]: 对话历史列表
        """
        try:
            # 请求 Dify API 获取对话历史
            history_url = f"{self.base_url}/conversations"
            response = requests.get(history_url, headers=self.headers)

            if response.status_code == 200:
                return response.json()
            else:
                error_msg = f"Failed to get conversation history: {response.status_code} - {response.text}"
                print(error_msg)
                return {"data": [], "error": error_msg}
        except Exception as e:
            error_msg = f"Failed to get conversation history: {str(e)}"
            print(error_msg)
            return {"data": [], "error": error_msg}

    def send_message(self, query: str, files: List[Dict] = None, streaming: bool = True) -> Dict[str, Any]:
        """
        发送消息到Dify平台

        Args:
            query: 用户查询文本
            files: 要附加的文件列表，每个文件是包含id、type等信息的字典
            streaming: 是否使用流式响应

        Returns:
            Dict[str, Any]: 响应结果
        """
        try:
            # 构建请求URL和请求体
            chat_url = f"{self.base_url}/chat-messages"
            payload = {
                "inputs": {},
                "query": query,
                "response_mode": "blocking",  # 始终使用阻塞模式，更可靠
                "user": self.user_id,
                "files": []
            }

            # 处理会话 ID
            if self.conversation_id and not self.conversation_id.startswith("thread_"):
                payload["conversation_id"] = self.conversation_id
                print(f"Using conversation_id: {self.conversation_id}")

            # 处理文件上传
            if files and len(files) > 0:
                print(f"Processing {len(files)} files for Dify")
                file_list = []

                for file in files:
                    file_id = file.get("id")
                    if not file_id:
                        continue

                    file_type = file.get("type", "document")
                    if file_type == "file":
                        file_type = "document"

                    file_info = {
                        "type": file_type,
                        "transfer_method": "local_file",
                        "upload_file_id": file_id
                    }
                    file_list.append(file_info)

                # 添加文件到请求体
                payload["files"] = file_list

                # 如果有文件，添加第一个文件到inputs
                if len(file_list) > 0:
                    file_obj = file_list[0]
                    payload["inputs"]["file_1"] = file_obj

            # 发送请求
            print(f"Sending request to Dify: {chat_url}")
            response = requests.post(chat_url, headers=self.headers, json=payload, timeout=60)  # 增加超时时间

            # 处理响应
            if response.status_code == 200:
                try:
                    result = response.json()

                    # 如果没有会话 ID，但响应中有，则保存它
                    if (not self.conversation_id or self.conversation_id == "") and "conversation_id" in result:
                        self.conversation_id = result["conversation_id"]
                        print(f"Saved new conversation_id: {self.conversation_id}")

                    # 确保响应中有答案
                    if "answer" not in result:
                        result["answer"] = "I'm sorry, but I couldn't generate a response."

                    return result
                except ValueError as json_error:
                    error_msg = f"Failed to parse JSON response: {str(json_error)}"
                    print(error_msg)
                    return {"error": error_msg, "answer": "I'm sorry, but I couldn't generate a response."}
            else:
                error_msg = f"Failed to send message: {response.status_code} - {response.text}"
                print(error_msg)
                return {"error": error_msg, "answer": "I'm sorry, but I couldn't generate a response."}
        except Exception as e:
            error_msg = f"Failed to send message: {str(e)}"
            print(traceback.format_exc())
            return {"error": error_msg, "answer": "I'm sorry, but I couldn't generate a response."}

    def stream_chat_response(self, query: str, files: List[Dict] = None):
        """
        流式获取聊天响应

        Args:
            query: 用户查询文本
            files: 要附加的文件列表

        Yields:
            str: 响应文本片段
        """
        try:
            chat_url = f"{self.base_url}/chat-messages"

            payload = {
                "inputs": {},
                "query": query,
                "response_mode": "streaming",
                "user": self.user_id,
                "conversation_id": self.conversation_id if self.conversation_id else "",
                "files": []
            }

            if not self.conversation_id or self.conversation_id.startswith("thread_"):
                payload["conversation_id"] = ""
            else:
                payload["conversation_id"] = self.conversation_id

            if files:
                file_list = []
                for file in files:
                    file_type = file.get("type", "file")

                    if file_type == "file":
                        file_type = "document"
                    elif file_type == "image":
                        file_type = "image"

                    file_info = {
                        "type": file_type,
                        "transfer_method": "local_file",
                        "upload_file_id": file.get("id")
                    }

                    file_list.append(file_info)

                for file_info in file_list:
                    dify_file = {
                        "type": file_info["type"],
                        "transfer_method": "local_file",
                        "upload_file_id": file_info["upload_file_id"]
                    }
                    payload["files"].append(dify_file)

                if file_list and len(file_list) > 0:
                    file_obj = {
                        "type": file_list[0]["type"],
                        "transfer_method": "local_file",
                        "upload_file_id": file_list[0]["upload_file_id"]
                    }
                    payload["inputs"]["file_1"] = file_obj

            with requests.post(chat_url, headers=self.headers, json=payload, stream=True) as response:
                if response.status_code != 200:
                    error_msg = f"Failed to stream chat: {response.status_code} - {response.text}"
                    print(error_msg)
                    st.error(error_msg)
                    yield f"Error: {error_msg}"
                    return

                buffer = ""

                try:
                    for line in response.iter_lines():
                        if not line:
                            continue

                        try:
                            line_text = line.decode('utf-8')                            
                            if not line_text.startswith('data: '):
                                continue

                            data = json.loads(line_text.replace('data: ', ''))

                            if 'conversation_id' in data and (not self.conversation_id or self.conversation_id.startswith("thread_")):
                                self.conversation_id = data['conversation_id']

                            if 'event' in data and data['event'] == 'message':
                                if 'answer' in data:
                                    chunk = data['answer']

                                    if isinstance(chunk, bytes):
                                        try:
                                            chunk = chunk.decode('utf-8')
                                        except UnicodeDecodeError:
                                            try:
                                                chunk = chunk.decode('utf-8', errors='ignore')
                                            except:
                                                chunk = str(chunk)

                                    if isinstance(chunk, str):
                                        if chunk.startswith('\ufeff'):
                                            chunk = chunk[1:]
                                        chunk = ''.join(c for c in chunk if ord(c) >= 32 or c in '\n\r\t')

                                    buffer += chunk
                                    yield chunk
                        except Exception as e:
                            print(f"Error parsing stream line: {str(e)}")

                    # 如果没有内容返回，返回一个默认消息
                    if not buffer:
                        print("No content received from stream, yielding default message")
                        yield "I'm sorry, I couldn't generate a response at this time."
                except Exception as e:
                    error_msg = f"Error processing stream: {str(e)}"
                    print(error_msg)
                    st.error(error_msg)
                    yield f"Error: {error_msg}"
        except Exception as e:
            error_msg = f"Failed to stream chat: {str(e)}"
            st.error(error_msg)
            yield f"Error: {error_msg}"

    def get_parameters(self) -> Dict[str, Any]:
        """
        获取Dify应用的参数配置

        Returns:
            Dict[str, Any]: 包含应用参数的响应，包括文件上传设置等
        """
        try:
            parameters_url = f"{self.base_url}/parameters"

            response = requests.get(parameters_url, headers=self.headers)

            if response.status_code == 200:
                return response.json()
            else:
                st.error(f"Failed to get parameters: {response.status_code} - {response.text}")
                return {}
        except Exception as e:
            st.error(f"Failed to get parameters: {str(e)}")
            return {}

    def get_file_upload_config(self) -> Dict[str, Any]:
        """
        获取文件上传配置

        Returns:
            Dict[str, Any]: 包含文件上传是否启用和允许的文件类型
        """
        # 如果已经有缓存的配置，直接返回
        if self.file_upload_config is not None:
            return self.file_upload_config

        try:
            parameters = self.get_parameters()
            file_upload = parameters.get("file_upload", {})

            # 构建配置对象
            config = {
                "enable_chat_file": file_upload.get("enabled", False),
                "chat_accepted_files_type": file_upload.get("allowed_file_types", [])
            }

            # 缓存配置
            self.file_upload_config = config

            return config
        except Exception as e:
            st.error(f"Failed to obtain the configuration for uploading the Dify file: {str(e)}")
            # 出错时返回默认配置并缓存
            default_config = {"enable_chat_file": False, "chat_accepted_files_type": []}
            self.file_upload_config = default_config
            return default_config

    def get_conversation_history(self) -> Dict[str, Any]:
        """
        获取用户的所有对话会话列表

        Returns:
            Dict[str, Any]: 包含对话列表的响应，格式为 {"limit": int, "has_more": bool, "data": List[Dict]}
        """
        try:
            history_url = f"{self.base_url}/conversations"

            params = {
                "user": self.user_id,
                "last_id": "",
                "limit": 20
            }

            response = requests.get(history_url, headers=self.headers, params=params)

            if response.status_code == 200:
                return response.json()
            else:
                st.error(f"Failed to get session list: {response.status_code} - {response.text}")
                return {"limit": 0, "has_more": False, "data": []}
        except Exception as e:
            st.error(f"Failed to get session list: {str(e)}")
            return {"limit": 0, "has_more": False, "data": []}

    def get_conversation_messages(self, conversation_id: str) -> List[Dict[str, Any]]:
        """
        获取指定对话的详细消息列表

        Args:
            conversation_id: 对话ID

        Returns:
            List[Dict[str, Any]]: 消息列表，包含 query 和 answer 字段
        """
        if not conversation_id:
            return []

        try:
            messages_url = f"{self.base_url}/messages"

            params = {
                "user": self.user_id,
                "conversation_id": conversation_id
            }

            response = requests.get(messages_url, headers=self.headers, params=params)

            if response.status_code == 200:
                result = response.json()
                return result.get("data", [])
            else:
                st.error(f"Failed to get conversation messages: {response.status_code} - {response.text}")
                return []
        except Exception as e:
            st.error(f"Failed to get conversation messages: {str(e)}")
            return []

