def get_dify_file_upload_config(api_key: str) -> Dict[str, Any]:
    """
    获取Dify应用的文件上传配置

    Args:
        api_key: Dify平台的API密钥

    Returns:
        Dict[str, Any]: 包含文件上传是否启用和允许的文件类型的配置信息
    """
    try:
        headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json"
        }

        response = requests.get(
            "https://api.dify.ai/v1/parameters",
            headers=headers
        )

        if response.status_code == 200:
            result = response.json()
            file_upload = result.get("file_upload", {})

            return {
                "enabled": file_upload.get("enabled", False),
                "allowed_file_types": file_upload.get("allowed_file_types", [])
            }
        else:
            st.error(f"Failed to get file upload config: {response.status_code} - {response.text}")
            return {"enabled": False, "allowed_file_types": []}
    except Exception as e:
        st.error(f"Failed to get file upload config: {str(e)}")
        return {"enabled": False, "allowed_file_types": []}

