class E2BAgentClient:
    """
    将 Claude (claude-sonnet-4-6) 与 E2B sandbox 连接起来的 Agent。
    LLM 通过 tool call 在 sandbox 里执行命令、读写文件，
    直到任务完成后返回自然语言回复。
    """

    MODEL = "claude-sonnet-4-6"

    # ── Tool 定义（告诉 LLM 它有哪些能力）────────────────────────
    TOOLS: list[dict] = [
        {
            "name": "run_command",
            "description": (
                "Execute a shell command inside the E2B sandbox and return stdout/stderr. "
                "Use this to install packages, run scripts, generate files, etc."
            ),
            "input_schema": {
                "type": "object",
                "properties": {
                    "command": {
                        "type": "string",
                        "description": "The shell command to execute, e.g. 'python3 make_ppt.py'"
                    },
                    "timeout": {
                        "type": "integer",
                        "description": "Max seconds to wait. Default 600.",
                        "default": 600
                    }
                },
                "required": ["command"]
            }
        },
        {
            "name": "write_file",
            "description": "Write text content to a file path inside the sandbox.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "path": {
                        "type": "string",
                        "description": "Absolute file path, e.g. /home/user/script.py"
                    },
                    "content": {
                        "type": "string",
                        "description": "Text content to write into the file."
                    }
                },
                "required": ["path", "content"]
            }
        },
        {
            "name": "read_file",
            "description": "Read text content from a file path inside the sandbox.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "path": {
                        "type": "string",
                        "description": "Absolute file path to read."
                    }
                },
                "required": ["path"]
            }
        },
        {
            "name": "list_files",
            "description": "List files and directories at a given path inside the sandbox.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "path": {
                        "type": "string",
                        "description": "Directory path to list, e.g. /home/user",
                        "default": "/home/user"
                    }
                },
                "required": []
            }
        }
    ]

    _SYSTEM_PROMPT_TEMPLATE = """You are an AI agent with full access to an E2B cloud sandbox (Ubuntu Linux).
You can execute shell commands, write/read files, and install packages via pip or apt.

## CONVERSATION FILE DIRECTORY (CRITICAL):
This conversation's ID is: {conv_id}
Default directory for ALL files: /home/user/conversations/{conv_id}/

Before writing any file, ALWAYS ensure the directory exists by running:
  mkdir -p /home/user/conversations/{conv_id}

## FILE NAMING RULES (CRITICAL — always follow these):
1. NEVER check if a file already exists before creating it. Always proceed with the task.
2. ALL files you create MUST have a timestamp suffix in the filename:
   - Format: <name>_YYYYMMDD_HHMMSS.<ext>
   - Examples: generate_ppt_20260312_153045.py, report_20260312_153045.pptx, chart_20260312_153045.png
3. To get the current timestamp inside a Python script, use:
   from datetime import datetime
   ts = datetime.now().strftime("%Y%m%d_%H%M%S")
4. The timestamp must be embedded at script-write time (when you call write_file).
   Use the SAME timestamp for the script file name AND all output files it generates.
5. Never use generic names like output.pptx, chart.png, script.py — always include the timestamp.
6. If the user specifies a target directory, use it; otherwise default to /home/user/conversations/{conv_id}.

## FILE LOOKUP RULES:
- When the user refers to a file by name (e.g. "modify the PPT you just created"),
  FIRST look in /home/user/conversations/{conv_id}/ using list_files.
- If the file is not found there and the user has specified a path, use that path.
- Never assume a file path — always verify with list_files before reading or modifying.

Guidelines:
- Always think step-by-step before acting.
- For file generation tasks (PPT, PDF, scripts), write the necessary code to a .py file first, then run it.
- After completing a task, tell the user the exact file path(s) so they can download them.
- If a command fails, read the error and try to fix it automatically — do NOT stop.
- Prefer Python scripts over one-liners for complex tasks.
- python-pptx, pandas, matplotlib, requests are pre-installed. Use pip install for others.
- Working directory is /home/user/conversations/{conv_id}.
"""

    def _get_system_prompt(self, conv_id: str) -> str:
        """【FIX-CONV】将 conv_id 填入系统提示词模板"""
        return self._SYSTEM_PROMPT_TEMPLATE.format(conv_id=conv_id)

    def __init__(self, e2b_client: 'E2BClient'):
        self.e2b_client = e2b_client
        self._anthropic = _anthropic.Anthropic()  # 读取环境变量 ANTHROPIC_API_KEY
        if _OPENAI_AVAILABLE:
            self._openai = _OpenAI(
                api_key=_os.environ.get("OPENAI_API_PROJECT_KEY")
            )
        else:
            self._openai = None

    @staticmethod
    def _build_openai_tools() -> list[dict]:
        """
        将 Anthropic tool 定义转换为 OpenAI function calling 格式。
        Anthropic: {"name", "description", "input_schema": {...}}
        OpenAI:    {"type": "function", "function": {"name", "description", "parameters": {...}}}
        """
        openai_tools = []
        for tool in E2BAgentClient.TOOLS:
            openai_tools.append({
                "type": "function",
                "function": {
                    "name": tool["name"],
                    "description": tool["description"],
                    "parameters": tool["input_schema"],
                }
            })
        return openai_tools

    # ── Tool 执行路由 ────────────────────────────────────────────
    def _execute_tool(self, sandbox_id: str, tool_name: str, tool_input: dict) -> str:
        """把 LLM 的 tool call 路由到对应的 sandbox 操作，返回结果字符串。"""
        try:
            if tool_name == "run_command":
                cmd = tool_input["command"]
                timeout = tool_input.get("timeout", 600)
                sandbox = self.e2b_client.connect_sandbox(sandbox_id=sandbox_id, timeout=timeout)
                result = sandbox.commands.run(cmd=cmd, timeout=timeout)
                output = ""
                if result.stdout:
                    output += f"[stdout]\n{result.stdout}"
                if result.stderr:
                    output += f"\n[stderr]\n{result.stderr}"
                output += f"\n[exit_code] {result.exit_code}"
                return output.strip() or "(no output)"

            elif tool_name == "write_file":
                path = tool_input["path"]
                content = tool_input["content"]
                self.e2b_client.sandbox_files_write_text(
                    sandbox_id=sandbox_id, path=path, content=content, timeout=30)
                return f"File written successfully: {path}"

            elif tool_name == "read_file":
                path = tool_input["path"]
                raw = self.e2b_client.sandbox_files_read_bytes(
                    sandbox_id=sandbox_id, path=path, timeout=30)
                text = bytes(raw).decode('utf-8', errors='replace')
                # 截断超长文件，避免撑爆 context
                if len(text) > 8000:
                    text = text[:8000] + "\n...[truncated]"
                return text

            elif tool_name == "list_files":
                path = tool_input.get("path", "/home/user")
                entries = self.e2b_client.sandbox_files_list(
                    sandbox_id=sandbox_id, timeout=30, path=path)
                if not entries:
                    return "(empty directory)"
                lines = [f"{'DIR ' if str(e.type).lower() == 'dir' else 'FILE'} {e.name}" for e in entries]
                return "\n".join(lines)

            else:
                return f"Unknown tool: {tool_name}"

        except Exception as exc:
            return f"[Tool Error] {tool_name}: {exc}"

    # ── 核心 Agent 循环（streaming）────────────────────────────
    def _run_claude_turn(
        self,
        sandbox_id: str,
        messages: list[dict],
        model: str,
        system_prompt,
        on_text: callable,
        on_tool_start: callable,
        on_tool_result: callable,
    ) -> list[dict]:
        """
        执行一轮 agent loop（支持多次 tool call）。
        - messages: 完整对话历史（role/content 格式）
        - on_text(str): LLM 输出文字时的回调，用于 streaming 显示
        - on_tool_start(name, input): tool 开始执行时的回调
        - on_tool_result(name, result): tool 执行完后的回调
        返回更新后的 messages（含本轮所有 assistant/tool 消息）。
        """
        messages = list(messages)  # 浅拷贝，不修改原始列表

        while True:
            # 调用 Claude，开启 streaming
            full_text = ""
            tool_calls = []  # [{id, name, input_str}]

            with self._anthropic.messages.stream(
                model=model,
                max_tokens=64000,
                # system=self.SYSTEM_PROMPT,
                system=system_prompt,
                tools=self.TOOLS,
                messages=messages,
            ) as stream:
                current_tool = None

                for event in stream:
                    # 文字 token
                    if event.type == "content_block_delta":
                        if hasattr(event.delta, "text"):
                            chunk = event.delta.text
                            full_text += chunk
                            on_text(chunk)
                        elif hasattr(event.delta, "partial_json"):
                            # tool input 正在积累
                            if current_tool:
                                current_tool["input_str"] += event.delta.partial_json

                    elif event.type == "content_block_start":
                        if hasattr(event.content_block, "type"):
                            if event.content_block.type == "tool_use":
                                current_tool = {
                                    "id": event.content_block.id,
                                    "name": event.content_block.name,
                                    "input_str": ""
                                }

                    elif event.type == "content_block_stop":
                        if current_tool:
                            tool_calls.append(current_tool)
                            current_tool = None

                # 获取最终完整 message
                final_message = stream.get_final_message()

            # 把 assistant 回复加入历史
            messages.append({"role": "assistant", "content": final_message.content})

            # 如果没有 tool call，说明 LLM 认为任务完成，退出循环
            if not tool_calls or final_message.stop_reason != "tool_use":
                break

            # 执行所有 tool calls，收集结果
            tool_results = []
            for tc in tool_calls:
                try:
                    tool_input = _json.loads(tc["input_str"]) if tc["input_str"] else {}
                except _json.JSONDecodeError:
                    tool_input = {}

                on_tool_start(tc["name"], tool_input)
                result_str = self._execute_tool(sandbox_id, tc["name"], tool_input)
                on_tool_result(tc["name"], result_str)

                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": tc["id"],
                    "content": result_str
                })

            # 把 tool 结果喂回 LLM，继续下一轮
            messages.append({"role": "user", "content": tool_results})

        return messages

    def _run_openai_turn(
            self,
            sandbox_id: str,
            messages: list[dict],
            model: str,
            system_prompt: str,
            on_text: callable,
            on_tool_start: callable,
            on_tool_result: callable,
    ) -> list[dict]:
        """
        OpenAI GPT 的 streaming agent loop（支持多次 tool call）。

        消息格式差异（与 Anthropic 不同）：
          - system prompt 作为 {"role": "system", "content": "..."} 放在 messages[0]
          - tool results 用 {"role": "tool", "tool_call_id": ..., "content": ...}
          - assistant tool call 用 {"role": "assistant", "tool_calls": [...]}

        因此前端传入的 Anthropic 格式消息需要在此转换。
        """
        if not self._openai:
            raise RuntimeError("OpenAI package not installed or OPENAI_API_KEY not set.")

        openai_tools = self._build_openai_tools()

        # ── 转换消息格式：Anthropic → OpenAI ────────────────────────
        def _to_openai_messages(msgs: list[dict]) -> list[dict]:
            """
            将 Anthropic 风格的 messages 列表转为 OpenAI 风格。
            仅处理 user/assistant 的普通文本消息（tool_result 消息由循环内单独追加）。
            """
            # result = [{"role": "system", "content": self.SYSTEM_PROMPT}]
            result = [{"role": "system", "content": system_prompt}]
            for msg in msgs:
                role = msg["role"]
                content = msg["content"]

                if role == "user":
                    # content 可能是 str 或 list[dict]
                    if isinstance(content, str):
                        result.append({"role": "user", "content": content})
                    elif isinstance(content, list):
                        # 过滤掉 tool_result 类型（在循环中单独处理）
                        text_parts = [
                            c["text"] for c in content
                            if isinstance(c, dict) and c.get("type") == "text"
                        ]
                        tool_result_parts = [
                            c for c in content
                            if isinstance(c, dict) and c.get("type") == "tool_result"
                        ]
                        if text_parts:
                            result.append({"role": "user", "content": " ".join(text_parts)})
                        # for tr in tool_result_parts:
                        #     result.append({
                        #         "role": "tool",
                        #         "tool_call_id": tr.get("tool_use_id", ""),
                        #         "content": str(tr.get("content", "")),
                        #     })

                elif role == "assistant":
                    # content 可能是 Anthropic ContentBlock list 或 str
                    if isinstance(content, str):
                        result.append({"role": "assistant", "content": content})
                    elif isinstance(content, list):
                        text_parts = []
                        for c in content:
                            if hasattr(c, "type") and c.type == "text":
                                text_parts.append(c.text)
                            elif isinstance(c, dict) and c.get("type") == "text":
                                text_parts.append(c["text"])
                            # 有文本才追加；纯 tool_use 的 assistant 消息直接跳过
                        if text_parts:
                            result.append({"role": "assistant", "content": " ".join(text_parts)})
                        # tool_use_parts = []
                        # for c in content:
                        #     if hasattr(c, "type"):
                        #         if c.type == "text":
                        #             text_parts.append(c.text)
                        #         elif c.type == "tool_use":
                        #             tool_use_parts.append(c)
                        #     elif isinstance(c, dict):
                        #         if c.get("type") == "text":
                        #             text_parts.append(c["text"])
                        # # text_str = " ".join(text_parts) + f"tool call: {str(tool_use_parts)}" if text_parts else ""
                        # text_str = " ".join(text_parts) if text_parts else " "
                        # result.append({"role": "assistant", "content": text_str})
            return result

        # 初始转换
        oai_messages = _to_openai_messages(messages)

        while True:
            full_text = ""
            tool_calls_map: dict[int, dict] = {}  # index → {id, name, arguments}

            # Streaming 调用
            stream = self._openai.chat.completions.create(
                model=model,
                messages=oai_messages,
                tools=openai_tools,
                tool_choice="auto",
                stream=True,
                max_completion_tokens=64000,
            )

            finish_reason = None
            for chunk in stream:
                delta = chunk.choices[0].delta if chunk.choices else None
                if delta is None:
                    continue

                finish_reason = chunk.choices[0].finish_reason or finish_reason

                # 文字 token
                if delta.content:
                    full_text += delta.content
                    on_text(delta.content)

                # tool call 片段（streaming 下 arguments 分多个 chunk 到达）
                if delta.tool_calls:
                    for tc_chunk in delta.tool_calls:
                        idx = tc_chunk.index
                        if idx not in tool_calls_map:
                            tool_calls_map[idx] = {
                                "id": tc_chunk.id or "",
                                "name": (tc_chunk.function.name or "") if tc_chunk.function else "",
                                "arguments": "",
                            }
                        if tc_chunk.function and tc_chunk.function.arguments:
                            tool_calls_map[idx]["arguments"] += tc_chunk.function.arguments
                        # 补全 id / name（有时在首个 chunk 才有）
                        if tc_chunk.id:
                            tool_calls_map[idx]["id"] = tc_chunk.id
                        if tc_chunk.function and tc_chunk.function.name:
                            tool_calls_map[idx]["name"] = tc_chunk.function.name

            # 没有 tool call → 任务完成
            if finish_reason != "tool_calls" or not tool_calls_map:
                # 将 assistant 回复追加到 oai_messages（用于下一轮，若有的话）
                if full_text:
                    oai_messages.append({"role": "assistant", "content": full_text})
                # 同步回原始 messages（外层记录对话历史）
                if full_text:
                    messages = list(messages)
                    messages.append({
                        "role": "assistant",
                        "content": [{"type": "text", "text": full_text}]
                    })
                break

            # 构建 assistant 消息（含 tool_calls 字段）
            oai_tool_calls_field = [
                {
                    "id": tc["id"],
                    "type": "function",
                    "function": {
                        "name": tc["name"],
                        "arguments": tc["arguments"],
                    }
                }
                for tc in tool_calls_map.values()
            ]
            oai_messages.append({
                "role": "assistant",
                "content": full_text or None,
                "tool_calls": oai_tool_calls_field,
            })

            # 执行所有 tool calls
            for tc in tool_calls_map.values():
                try:
                    tool_input = _json.loads(tc["arguments"]) if tc["arguments"] else {}
                except _json.JSONDecodeError:
                    tool_input = {}

                on_tool_start(tc["name"], tool_input)
                result_str = self._execute_tool(sandbox_id, tc["name"], tool_input)
                on_tool_result(tc["name"], result_str)

                # OpenAI 需要 role=tool 消息
                oai_messages.append({
                    "role": "tool",
                    "tool_call_id": tc["id"],
                    "content": result_str,
                })

        return messages

    def run_agent_turn(
            self,
            sandbox_id: str,
            messages: list[dict],
            on_text: callable,
            on_tool_start: callable,
            on_tool_result: callable,
            model: str = "claude-sonnet-4-6",  # 【CHANGE 7】新增 model 参数，默认向后兼容
            conv_id: str = "default",
    ) -> list[dict]:
        """
        统一 Agent 入口。根据 model 参数路由到 Claude 或 GPT 的实现。

        参数：
          sandbox_id   : E2B sandbox ID
          messages     : 完整对话历史（role/content 格式）
          on_text      : LLM 输出文字时的流式回调 on_text(chunk: str)
          on_tool_start: 工具开始执行回调 on_tool_start(name, input_dict)
          on_tool_result: 工具执行完毕回调 on_tool_result(name, result_str)
          model        : 【NEW】模型 ID，如 'claude-sonnet-4-6' 或 'gpt-4.1'
                         不传则使用 DEFAULT_MODEL（向后兼容）

        返回：
          更新后的 messages 列表（含本轮所有 assistant/tool 消息）
        """
        resolved_model = model or self.DEFAULT_MODEL
        system_prompt = self._get_system_prompt(conv_id)

        # 【CHANGE 6】根据 model 前缀路由到不同实现
        if resolved_model.startswith("claude"):
            return self._run_claude_turn(
                sandbox_id=sandbox_id,
                messages=messages,
                model=resolved_model,
                system_prompt= system_prompt,
                on_text=on_text,
                on_tool_start=on_tool_start,
                on_tool_result=on_tool_result,
            )
        elif resolved_model.startswith("gpt") or resolved_model.startswith("o"):
            return self._run_openai_turn(
                sandbox_id=sandbox_id,
                messages=messages,
                model=resolved_model,
                system_prompt=system_prompt,
                on_text=on_text,
                on_tool_start=on_tool_start,
                on_tool_result=on_tool_result,
            )
        else:
            raise ValueError(
                f"Unsupported model: '{resolved_model}'. "
                f"Model must start with 'claude' (Anthropic) or 'gpt'/'o' (OpenAI)."
            )

