class GenericAgentClient:
    """
    Generic Agent API 客户端

    用于与 Generic Agent API 进行通信
    """

    def __init__(self, api_url: str, auth_header_name: str = None, auth_header_key: str = None, user_email: str = None):
        """
        初始化 Generic Agent 客户端

        Args:
            api_url: API 端点 URL
            auth_header_name: 认证头名称
            auth_header_key: 认证头值
            user_email: 用户邮箱
        """
        self.api_url = api_url
        self.auth_header_name = auth_header_name
        self.auth_header_key = auth_header_key
        self.user_email = user_email

        # 设置请求头
        self.headers = {
            "Content-Type": "application/json"
        }

        # 如果提供了认证信息，添加到请求头
        if auth_header_name and auth_header_key:
            self.headers[auth_header_name] = auth_header_key

    def test_connectivity(self) -> Dict[str, Any]:
        """
        测试与 Generic Agent API 的连接

        Returns:
            连接测试结果
        """
        try:
            # 发送一个简单的测试请求
            test_payload = {
                "message": "Hello, this is a connectivity test",
                "user_id": "test_user",
                "timestamp": datetime.utcnow().isoformat()
            }

            response = requests.post(
                self.api_url,
                headers=self.headers,
                json=test_payload,
                timeout=30
            )

            if response.status_code == 200:
                return {
                    "success": True,
                    "status_code": response.status_code,
                    "message": "Connection successful",
                    "response": response.json() if response.content else None
                }
            else:
                return {
                    "success": False,
                    "status_code": response.status_code,
                    "message": f"API returned status code {response.status_code}",
                    "response": response.text
                }

        except requests.exceptions.Timeout:
            return {
                "success": False,
                "status_code": None,
                "message": "Connection timeout",
                "response": None
            }
        except requests.exceptions.ConnectionError:
            return {
                "success": False,
                "status_code": None,
                "message": "Connection failed - unable to reach the API endpoint",
                "response": None
            }
        except Exception as e:
            return {
                "success": False,
                "status_code": None,
                "message": f"Unexpected error: {str(e)}",
                "response": None
            }

    def send_message(self, query: str, thread_id: str = None, files: List[Dict] = None, assistant_id: str = None, agent_nickname: str = None) -> Dict[str, Any]:
        """
        向 Generic Agent API 发送消息（使用与 N8n 相同的格式）

        Args:
            query: 用户查询文本
            thread_id: 会话ID（可选）
            files: 文件列表，每个文件包含filename、filetype、binary信息
            assistant_id: 助手ID（可选）
            agent_nickname: 助手昵称（可选）

        Returns:
            Dict[str, Any]: 响应结果
        """
        try:
            import os
            HOST = os.environ.get("LF_AI_PORTAL_HOST")
            if HOST and "aiportal.lfapps.net" in HOST:
                agent_environment = "prd"
            else:
                agent_environment = "uat"

            # 构建请求数据，使用与 N8n 完全相同的格式
            payload = {
                "agent_environment": agent_environment,
                "agent_id": assistant_id,  # 使用assistant_id作为agent_id
                "session_id": thread_id,
                "user_email": self.user_email or "unknown",
                "chat_input": query,
                "attachments": files or [],
                "agent_nickname": agent_nickname
            }

            response = requests.post(
                self.api_url,
                headers=self.headers,
                json=payload,
                timeout=300
            )

            if response.status_code == 200:
                try:
                    result = response.json()
                    answer_text = self._extract_answer_text(result, response.text)
                    if not answer_text:
                        answer_text = "I'm sorry, but I couldn't generate a response."
                    return {"status": "success", "data": result, "answer": answer_text}
                except ValueError as json_error:
                    # 如果响应不是JSON格式，尝试解析为文本
                    text_response = response.text
                    return {
                        "status": "success",
                        "data": {"text": text_response},
                        "answer": text_response
                    }
            else:
                error_msg = f"Failed to send message to Generic Agent API: {response.status_code} - {response.text}"
                print(error_msg)
                return {
                    "status": "error",
                    "error": error_msg,
                    "answer": "I'm sorry, but I couldn't generate a response."
                }

        except Exception as e:
            error_msg = f"Failed to send message to Generic Agent API: {str(e)}"
            print(error_msg)
            return {
                "status": "error",
                "error": error_msg,
                "answer": "I'm sorry, but I couldn't generate a response."
            }

    def stream_chat_response(self, query: str, thread_id: str = None, files: List[Dict] = None, assistant_id: str = None, agent_nickname: str = None):
        """
        流式获取 Generic Agent 聊天响应（使用与 N8n 相同的格式）

        Args:
            query: 用户查询文本
            thread_id: 会话ID（可选）
            files: 文件列表，每个文件包含filename、filetype、binary信息
            assistant_id: 助手ID（可选）
            agent_nickname: 助手昵称（可选）

        Yields:
            str: 响应文本片段
        """
        try:
            import os
            HOST = os.environ.get("LF_AI_PORTAL_HOST")
            if HOST and "aiportal.lfapps.net" in HOST:
                agent_environment = "prd"
            else:
                agent_environment = "uat"

            # 构建请求数据，使用与 N8n 完全相同的格式
            payload = {
                "agent_environment": agent_environment,
                "agent_id": assistant_id,  # 使用assistant_id作为agent_id
                "session_id": thread_id,
                "user_email": self.user_email or "unknown",
                "chat_input": query,
                "attachments": files or [],
                "agent_nickname": agent_nickname
            }

            # 发送请求到 Generic Agent API
            response = requests.post(
                self.api_url,
                headers=self.headers,
                json=payload,
                timeout=300
            )

            if response.status_code == 200:
                print(f"Generic Agent response: {response.text}")
                try:
                    result = response.json()
                    answer_text = self._extract_answer_text(result, response.text)
                    if answer_text:
                        yield answer_text
                    else:
                        yield "I'm sorry, I couldn't generate a response at this time."
                except ValueError:
                    # 如果响应不是JSON格式，直接返回文本
                    text_response = response.text
                    if text_response:
                        yield text_response
                    else:
                        yield "I'm sorry, I couldn't generate a response at this time."
            else:
                error_msg = f"Failed to get response from Generic Agent API: {response.status_code} - {response.text}"
                print(error_msg)
                yield f"Error: {error_msg}"
        except Exception as e:
            error_msg = f"Failed to get response from Generic Agent API: {str(e)}"
            print(error_msg)
            yield f"Error: {error_msg}"

    def _extract_answer_text(self, parsed_response: Any, raw_text_fallback: Optional[str] = None) -> str:
        """
        兼容多种 Generic Agent API 响应格式，提取可展示的文本（使用与 N8n 相同的逻辑）：
        - 单对象：{"output": "..."} 或使用 "response" / "answer" / "message" / "content" / "text"
        - 对象列表：[ {"output": "..."}, ... ]
        - 纯文本："..."
        其它类型返回 raw_text_fallback 或空字符串。
        """
        try:
            if isinstance(parsed_response, dict):
                for key in ("output", "response", "answer", "message", "content", "text"):
                    if key in parsed_response:
                        value = parsed_response.get(key)
                        if isinstance(value, (str, int, float, bool)):
                            return str(value)
                        # 若值为复杂结构，降级为 JSON 字符串
                        try:
                            return json.dumps(value, ensure_ascii=False)
                        except Exception:
                            return str(value)
                # 未找到常见字段，整体序列化展示
                try:
                    return json.dumps(parsed_response, ensure_ascii=False)
                except Exception:
                    return str(parsed_response)

            if isinstance(parsed_response, list):
                parts: List[str] = []
                for item in parsed_response:
                    if isinstance(item, dict):
                        value = item.get("output")
                        if value is None:
                            value = item.get("response", item.get("answer", item.get("message", item.get("content", item.get("text")))))
                        if value is not None:
                            if isinstance(value, (str, int, float, bool)):
                                parts.append(str(value))
                            else:
                                try:
                                    parts.append(json.dumps(value, ensure_ascii=False))
                                except Exception:
                                    parts.append(str(value))
                        else:
                            try:
                                parts.append(json.dumps(item, ensure_ascii=False))
                            except Exception:
                                parts.append(str(item))
                    else:
                        parts.append(str(item))
                return "\n".join([p for p in parts if p])

            if isinstance(parsed_response, (str, int, float, bool)):
                return str(parsed_response)

            return raw_text_fallback or ""
        except Exception:
            # 出现异常时，回退到原始文本
            return raw_text_fallback or ""

