def is_valid_email_list(email_list) -> bool:
    regex = r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,7}\b'
    emails = [email.strip() for email in re.split(';', email_list)]
    for email in emails:
        if not re.fullmatch(regex, email):
            return False
    return True

