def convert_list_of_dict_to_dict_nested_list(input_list: list[dict]) -> dict:
    """
    [
        {
            "col1",: "value_1_1",
            "col2": "value_1_2",
            "col3": "value_1_3",
        },
        {
            "col1",: "value_2_1",
            "col2": "value_2_2",
            "col3": "value_2_3",
        }
    ] ->
    {'column_name': ['col1','col2','col3'], 'value_row_1': ['value_1_1', 'value_1_2', 'value_1_3'],...}
    """
    output_dict = {
        # 'column_name': list(input_list[0].keys()),
        'column_name': list(dict_keys_remove_special_character(input_list[0]).keys()),
    }
    for i in range(0, len(input_list)):
        output_dict['value_row_'+str(i+1)] = list(input_list[i].values())
    return output_dict

