def convert_microsoft_file_format(file):
    from docx import Document
    from pptx import Presentation
    import pandas as pd
    """
    将 Microsoft Office 文件转换为 LLM 友好的文本格式（CSV/Markdown）。
    保留结构，支持多表 Excel。
    """
    file_extension = file.name.split('.')[-1].lower()

    # 1. Excel 处理 -> 转换为包含所有 Sheet 的 CSV
    if file_extension in ['xlsx', 'xls']:
        try:
            # 读取所有工作表
            dfs = pd.read_excel(file, sheet_name=None)
            output = io.StringIO()

            for sheet_name, df in dfs.items():
                output.write(f"\n\n--- SHEET: {sheet_name} ---\n")
                # 将数据写入 buffer
                df.to_csv(output, index=False)

            # 转为 bytes
            csv_data = output.getvalue().encode('utf-8')
            new_name = f"{file.name}.csv"
            return ConvertedFile(csv_data, new_name, "text/csv")
        except Exception as e:
            print(f"Error converting Excel: {e}")
            return file  # 如果转换失败，返回原文件让后续逻辑处理

    # 2. Word 处理 -> 转换为 Markdown (保留标题结构)
    elif file_extension in ['docx']:
        try:
            doc = Document(file)
            md_lines = []

            for para in doc.paragraphs:
                text = para.text.strip()
                if not text:
                    continue

                # 简单的结构保留：根据样式判断是否为标题
                style_name = para.style.name.lower()
                if 'heading 1' in style_name:
                    md_lines.append(f"# {text}")
                elif 'heading 2' in style_name:
                    md_lines.append(f"## {text}")
                elif 'heading 3' in style_name:
                    md_lines.append(f"### {text}")
                elif 'list' in style_name:
                    md_lines.append(f"- {text}")
                else:
                    md_lines.append(text)

            # 处理表格
            for table in doc.tables:
                md_lines.append("\n")
                # 简单转换为 Markdown 表格
                rows = []
                for row in table.rows:
                    cells = [cell.text.strip().replace('\n', ' ') for cell in row.cells]
                    rows.append("| " + " | ".join(cells) + " |")

                if rows:
                    md_lines.append(rows[0])  # Header
                    md_lines.append("| " + " | ".join(["---"] * len(table.rows[0].cells)) + " |")  # Separator
                    md_lines.extend(rows[1:])  # Body
                md_lines.append("\n")

            md_content = "\n\n".join(md_lines)
            new_name = f"{file.name}.md"
            return ConvertedFile(md_content.encode('utf-8'), new_name, "text/markdown")
        except Exception as e:
            print(f"Error converting Word: {e}")
            return file

    # 3. PPT 处理 -> 转换为 Markdown (按幻灯片分组)
    elif file_extension in ['pptx']:
        try:
            prs = Presentation(file)
            md_lines = []

            for i, slide in enumerate(prs.slides):
                md_lines.append(f"\n\n## Slide {i + 1}")

                # 提取标题
                if slide.shapes.title:
                    md_lines.append(f"### {slide.shapes.title.text}")

                # 提取文本内容
                for shape in slide.shapes:
                    if not shape.has_text_frame:
                        continue
                    if shape == slide.shapes.title:
                        continue  # 标题已处理

                    for paragraph in shape.text_frame.paragraphs:
                        text = paragraph.text.strip()
                        if text:
                            md_lines.append(f"- {text}")

            md_content = "\n".join(md_lines)
            new_name = f"{file.name}.md"
            return ConvertedFile(md_content.encode('utf-8'), new_name, "text/markdown")
        except Exception as e:
            print(f"Error converting PPT: {e}")
            return file

        # 其他文件直接返回
    return file

