def multi_turn_image_generation(input_prompt: str, input_images: list[UploadedFile] = [],  model="gpt-4.1", current_response_id: str = None, size:LITERAL_SIZE = "auto",quality: LITERAL_QUALITY="auto"):
    input_content = [{"type": "input_text", "text": input_prompt}]

    if input_images:
        for input_image in input_images:
            if not validate_streamlit_uploaded_file_size(input_image, 25):
                raise Exception("Uploaded image exceed 25 mb")
            input_content.append(
                {
                    "type": "input_image",
                    "image_url": f"data:{input_image.type};base64,{base64.b64encode(input_image.getvalue()).decode('utf-8')}",
                }
            )
    input_user_content = [
        {
            "role": "user",
            "content": input_content,
        }
    ]
    partial_images_count = 3
    out_img_str = None
    error = None
    revised_prompt = ""
    with st.spinner("GPT Processing", show_time=True):
        full_message = ""
        output_assistant_message = {}
        try:
            stream = client.responses.create(
                model=model,
                # input="Generate an image of gray tabby cat hugging an otter with an orange scarf",
                previous_response_id=current_response_id,
                input=input_user_content,
                stream=True,
                tools=[
                    {
                        "type": "image_generation",
                        "size": size,
                        "quality": quality,
                        "partial_images": partial_images_count
                    }
                ],
                user=st.session_state.userName if st.session_state.userName else NOT_GIVEN
            )
            message_placeholder = st.empty()
            # image_cols = st.columns(partial_images_count)
            image_cols = st.columns([2,1])
            image_placeholder = image_cols[0].empty()

            # f = open("image_generation_log.txt", "w")
            for event in stream:
                print(f"event.type: {event.type}")
                if event.type == "response.image_generation_call.partial_image":
                    idx = event.partial_image_index
                    image_base64 = event.partial_image_b64
                    image_bytes = base64.b64decode(image_base64)
                    img = Image.open(BytesIO(image_bytes))
                    # if idx < partial_images_count:
                        # with image_cols[idx]:
                    with image_placeholder:
                        st.image(img, use_container_width=True)
                    out_img_str = image_base64
                else:
                    # f.write(f'event - {event}\n')
                    if event.type == "response.created":
                        current_response_id = event.response.id
                    elif event.type == "response.output_item.done":

                        # get revised_prompt
                        if event.item and event.item.type == "image_generation_call":
                            image_gen_item: ImageGenerationCall = event.item
                            revised_prompt = image_gen_item.__getattr__("revised_prompt")

                    elif event.type == 'response.output_text.delta':
                        full_message += event.delta
                        message_placeholder.markdown(custom_markdown_text(full_message + "▌"))
                    # elif event.type == "response.completed":
                    #
                    #     # get revised prompt
                    #     for output in event.response.output:
                    #         if output.type == "image_generation_call":
                    #             output.content.
            # f.close()
            output_assistant_message = {"role": "assistant", "content": full_message, "image": out_img_str, "revised_prompt":revised_prompt}

        except Exception as e:
            error = e
            print(traceback.format_exc())
    return output_assistant_message, current_response_id, error

def reset_nano_banana_chat_session():
    """重置 nano-banana 对话会话（清除上下文）。"""
    if _NANO_BANANA_ST_KEY in st.session_state:
        del st.session_state[_NANO_BANANA_ST_KEY]

def nano_banana_image_generation(input_prompt: str, input_images: list[UploadedFile] = []) -> tuple[dict, None, Exception | None]:
    """使用 Gemini 2.5 Flash Image Preview（nano-banana）进行多轮对话生成图片，带上下文。

    返回 (output_message, None, error) 以与 multi_turn_image_generation 对齐。
    output_message: {"role": "assistant", "content": str, "image": base64_png_str|None, "revised_prompt": ""}
    """
    import base64 as _b64
    from google.genai import types as genai_types

    output_assistant_message = {"role": "assistant", "content": "", "image": None, "revised_prompt": ""}
    error = None

    try:
        with st.spinner("nano-banana Processing", show_time=True):
            client, chat = _get_nano_banana_chat_session()

            parts = []
            if input_images:
                for input_image in input_images:
                    if hasattr(input_image, "getvalue"):
                        bytes_data = input_image.getvalue()
                        mime_type = input_image.type if hasattr(input_image, "type") and input_image.type else "image/png"
                    elif isinstance(input_image, str):
                        bytes_data = _b64.b64decode(input_image)
                        mime_type = "image/png"
                    else:
                        continue
                    parts.append(
                        genai_types.Part.from_bytes(
                            data=bytes_data,
                            mime_type=mime_type
                        )
                    )
            if input_prompt:
                # Strongly hint image generation to the image-preview model
                parts.append(genai_types.Part.from_text(text=f"Generate an image:\n{input_prompt}"))

            # 多轮对话：流式返回文本与图片
            message_placeholder = st.empty()
            text_response = ""
            image_base64 = None

            responses = chat.send_message_stream(message=parts if parts else [genai_types.Part.from_text(text=f"Generate an image:\n{input_prompt or ''}")])
            for chunk in responses:
                if chunk.candidates:
                    for candidate in chunk.candidates:
                        if candidate.content and candidate.content.parts:
                            for part in candidate.content.parts:
                                if getattr(part, 'text', None):
                                    text_response += part.text
                                    message_placeholder.markdown(custom_markdown_text(text_response + "▌"))
                                if hasattr(part, 'inline_data') and part.inline_data and str(part.inline_data.mime_type).lower().startswith("image"):
                                    if image_base64 is None:
                                        image_base64 = base64.b64encode(part.inline_data.data).decode('utf-8')

            if not image_base64:
                # Fallback to non-stream generate_content if streaming did not yield an image
                contents = [
                    genai_types.Content(
                        role="user",
                        parts=parts if parts else [genai_types.Part.from_text(text=f"Generate an image:\n{input_prompt or ''}")]
                    )
                ]
                fallback_config = genai_types.GenerateContentConfig(
                    temperature=1,
                    top_p=0.95,
                    max_output_tokens=8192,
                    response_modalities=["TEXT", "IMAGE"],
                    safety_settings=[
                        genai_types.SafetySetting(category="HARM_CATEGORY_HATE_SPEECH", threshold="OFF"),
                        genai_types.SafetySetting(category="HARM_CATEGORY_DANGEROUS_CONTENT", threshold="OFF"),
                        genai_types.SafetySetting(category="HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold="OFF"),
                        genai_types.SafetySetting(category="HARM_CATEGORY_HARASSMENT", threshold="OFF"),
                    ],
                )
                resp = client.models.generate_content(
                    model="gemini-2.5-flash-image-preview",
                    contents=contents,
                    config=fallback_config,
                )
                if resp and resp.candidates:
                    cand = resp.candidates[0]
                    if cand.content and cand.content.parts:
                        for part in cand.content.parts:
                            if getattr(part, "text", None):
                                text_response += part.text
                            if hasattr(part, "inline_data") and part.inline_data and str(part.inline_data.mime_type).lower().startswith("image/"):
                                image_base64 = base64.b64encode(part.inline_data.data).decode("utf-8")
                                break

            if text_response:
                output_assistant_message["content"] = text_response
            if image_base64:
                output_assistant_message["image"] = image_base64

            # Ensure reply is not empty when image exists
            if image_base64 and not output_assistant_message["content"]:
                output_assistant_message["content"] = "Image generated."

    except Exception as e:
        try:
            msg = str(e)
            if "User location is not supported" in msg or "FAILED_PRECONDITION" in msg:
                error = Exception("nano-banana is not available in the current region. Switch the server egress IP to a supported region (e.g., US) or use GPT Image instead.")
            else:
                error = e
        except Exception:
            error = e
        print(traceback.format_exc())

    return output_assistant_message, None, error

