def get_available_n8n_hosts(app_env: str) -> List[str]:
    """
    根据应用环境获取可用的N8n host列表

    Args:
        app_env: 应用环境 ('prd' 或 'uat')

    Returns:
        List[str]: 可用的N8n host URL列表
        - prd环境: 只返回env='prd'的hosts
        - uat环境: 返回所有hosts (uat + prd)
    """
    try:
        config_list = get_n8n_hosts_config()

        if not config_list:
            print("No N8n hosts configured")
            return []

        host_urls = []

        if app_env == 'prd':
            # PRD环境只显示prd的N8n hosts
            for item in config_list:
                if isinstance(item, dict) and item.get('env') == 'prd' and 'host_url' in item:
                    host_urls.append(item['host_url'])
        else:
            # UAT环境显示所有N8n hosts (uat + prd)
            for item in config_list:
                if isinstance(item, dict) and 'host_url' in item:
                    host_urls.append(item['host_url'])

        return host_urls
    except Exception as e:
        print(f"Error in get_available_n8n_hosts: {str(e)}")
        import traceback
        print(traceback.format_exc())
        return []

