class N8nClient:
    def __init__(self, webhook_path: str, user_id: str = 'system_user', user_name: str = 'system_user',
                 user_email: str = None, auth_header_key: str = None, auth_header_name: str = "Authorization", host: str = None):
        """
        初始化N8n客户端

        Args:
            webhook_path: N8n webhook路径（从assistant的openai_api_key字段获取）
            user_id: 用户ID
            user_name: 用户名
            user_email: 用户邮箱
            auth_header_key: 认证头密钥（可选）
            auth_header_name: 认证头名称（默认为"Authorization"）
            host: N8n主机地址（如果提供则覆盖默认值）
        """
        self.webhook_path = webhook_path
        self.base_url = host 
        self.webhook_url = f"{self.base_url}/webhook/{webhook_path}"
        self.user_id = user_id
        self.user_name = user_name
        self.user_email = user_email
        self.headers = {
            "Content-Type": "application/json"
        }

        # 如果提供了auth header key，添加到headers中
        if auth_header_key:
            self.headers[auth_header_name] = auth_header_key

    def _extract_answer_text(self, parsed_response: Any, raw_text_fallback: Optional[str] = None) -> str:
        """
        兼容多种 N8n 响应格式，提取可展示的文本：
        - 单对象：{"output": "..."} 或使用 "response" / "answer"
        - 对象列表：[ {"output": "..."}, ... ]
        - 纯文本："..."
        其它类型返回 raw_text_fallback 或空字符串。
        """
        try:
            if isinstance(parsed_response, dict):
                for key in ("output", "response", "answer"):
                    if key in parsed_response:
                        value = parsed_response.get(key)
                        if isinstance(value, (str, int, float, bool)):
                            return str(value)
                        # 若值为复杂结构，降级为 JSON 字符串
                        try:
                            return json.dumps(value, ensure_ascii=False)
                        except Exception:
                            return str(value)
                # 未找到常见字段，整体序列化展示
                try:
                    return json.dumps(parsed_response, ensure_ascii=False)
                except Exception:
                    return str(parsed_response)

            if isinstance(parsed_response, list):
                parts: List[str] = []
                for item in parsed_response:
                    if isinstance(item, dict):
                        value = item.get("output")
                        if value is None:
                            value = item.get("response", item.get("answer"))
                        if value is not None:
                            if isinstance(value, (str, int, float, bool)):
                                parts.append(str(value))
                            else:
                                try:
                                    parts.append(json.dumps(value, ensure_ascii=False))
                                except Exception:
                                    parts.append(str(value))
                        else:
                            try:
                                parts.append(json.dumps(item, ensure_ascii=False))
                            except Exception:
                                parts.append(str(item))
                    else:
                        parts.append(str(item))
                return "\n".join([p for p in parts if p])

            if isinstance(parsed_response, (str, int, float, bool)):
                return str(parsed_response)

            return raw_text_fallback or ""
        except Exception:
            # 出现异常时，回退到原始文本
            return raw_text_fallback or ""

    def send_message(self, query: str, thread_id: str = None, files: List[Dict] = None, assistant_id: str = None, agent_nickname: str = None) -> Dict[str, Any]:
        """
        发送消息到N8n webhook

        Args:
            query: 用户查询文本
            thread_id: 会话ID（可选）
            files: 文件列表，每个文件包含filename、filetype、binary信息
            assistant_id: 助手ID（可选）
            agent_nickname: 助手昵称（可选）

        Returns:
            Dict[str, Any]: 响应结果
        """
        try:
            HOST = os.environ.get("LF_AI_PORTAL_HOST")
            if HOST and "aiportal.lfapps.net" in HOST:
                agent_environment = "prd"
            else:
                agent_environment = "uat"

            # 构建请求数据
            payload = {
                "agent_environment": agent_environment,
                "agent_id": assistant_id,  # 使用assistant_id作为agent_id，如果没有则使用webhook_path
                "session_id": thread_id ,
                "user_email": self.user_email,
                "chat_input": query,
                "attachments": files or [],
                "agent_nickname": agent_nickname
            }


            # 发送请求到N8n webhook
            response = requests.post(
                self.webhook_url,
                headers=self.headers,
                json=payload,
                timeout=300
            )

            if response.status_code == 200:
                try:
                    result = response.json()
                    answer_text = self._extract_answer_text(result, response.text)
                    if not answer_text:
                        answer_text = "I'm sorry, but I couldn't generate a response."
                    return {"status": "success", "data": result, "answer": answer_text}
                except ValueError as json_error:
                    # 如果响应不是JSON格式，尝试解析为文本
                    text_response = response.text
                    return {
                        "status": "success",
                        "data": {"text": text_response},
                        "answer": text_response
                    }
            else:
                error_msg = f"Failed to send message to N8n webhook: {response.status_code} - {response.text}"
                print(error_msg)
                return {
                    "status": "error",
                    "error": error_msg,
                    "answer": "I'm sorry, but I couldn't generate a response."
                }
        except Exception as e:
            error_msg = f"Failed to send message to N8n webhook: {str(e)}"
            print(error_msg)
            return {
                "status": "error",
                "error": error_msg,
                "answer": "I'm sorry, but I couldn't generate a response."
            }

    def stream_chat_response(self, query: str, thread_id: str = None, files: List[Dict] = None, assistant_id: str = None, agent_nickname: str = None):
        """
        流式获取N8n聊天响应

        Args:
            query: 用户查询文本
            thread_id: 会话ID（可选）
            files: 文件列表，每个文件包含filename、filetype、binary信息
            assistant_id: 助手ID（可选）
            agent_nickname: 助手昵称（可选）

        Yields:
            str: 响应文本片段
        """
        try:
            HOST = os.environ.get("LF_AI_PORTAL_HOST")
            if HOST and "aiportal.lfapps.net" in HOST:
                agent_environment = "prd"
            else:
                agent_environment = "uat"
            # 构建请求数据
            payload = {
                "agent_environment": agent_environment,
                "agent_id": assistant_id ,  # 使用assistant_id作为agent_id，如果没有则使用webhook_path
                "session_id": thread_id ,
                "user_email": self.user_email ,
                "chat_input": query,
                "attachments": files or [],
                "agent_nickname": agent_nickname
            }

            # 发送请求到N8n webhook
            response = requests.post(
                self.webhook_url,
                headers=self.headers,
                json=payload,
                timeout=300
            )

            if response.status_code == 200:
                print(f"N8n response: {response.text}")
                try:
                    result = response.json()
                    answer_text = self._extract_answer_text(result, response.text)
                    if answer_text:
                        yield answer_text
                    else:
                        yield "I'm sorry, I couldn't generate a response at this time."
                except ValueError:
                    # 如果响应不是JSON格式，直接返回文本
                    text_response = response.text
                    if text_response:
                        yield text_response
                    else:
                        yield "I'm sorry, I couldn't generate a response at this time."
            else:
                error_msg = f"Failed to get response from N8n webhook: {response.status_code} - {response.text}"
                print(error_msg)
                yield f"Error: {error_msg}"
        except Exception as e:
            error_msg = f"Failed to get response from N8n webhook: {str(e)}"
            print(error_msg)
            yield f"Error: {error_msg}"

