def message_text_annotations_handler(text: Text, _openai_client: OpenAI, hide_file_citation: bool = False):
    message_content = text.value
    if len(text.annotations) > 0:
        for annotation in text.annotations:
            if str(annotation.type) == "file_citation":
                try:
                    if not hide_file_citation:
                        file_citation_text = str(annotation.text)
                        file_citation_file_id = annotation.file_citation.file_id
                        new_file_citation_text = "【" + retrieve_file(file_citation_file_id,
                                                                     _openai_client=_openai_client).filename + " " + str(
                            annotation.start_index) + "-" + str(annotation.end_index) + "】"
                        message_content = message_content.replace(file_citation_text, new_file_citation_text)
                except Exception as file_citation_error:
                    print(file_citation_error)
                    continue
            elif str(annotation.type) == "file_path":
                file_id = annotation.file_path.file_id
                file_name = annotation.text
                href = get_binary_file_downloader_html(file_id=file_id, file_name=file_name,
                                                       _openai_client=_openai_client)
                # href = get_binary_file_downloader_link(file_id=file_id)
                message_content = message_content.replace(file_name, href)
        if hide_file_citation:
            message_content = re.sub(r'【\d+:\d+†.*】', '', message_content)
    return message_content

