class OpenaiClient:
    def __init__(self, api_key: str, funct_group: str = "GPT", user_id: str = 'system_user', user_name: str = 'system_user', user_email: str = st.session_state.get('userEmail', 'system_user')):
        self.openai_client = OpenAI(
            api_key=api_key
        )
        self.funct_group = funct_group
        self.user_id = user_id
        self.user_name = user_name
        self.user_email = user_email

    def create_assistant(self, name: str, model: str, instructions: str = "You are a helpful assistant",):
        assistant_created = self.openai_client.beta.assistants.create(
            name=name,
            instructions=instructions,
            description="",
            model=model,
            tools=[{"type": "file_search"}],
        )
        return assistant_created

    def delete_assistant(self, assistant_id: str):
        return self.openai_client.beta.assistants.delete(assistant_id=assistant_id)

    def create_thread(self) -> Thread:
        return self.openai_client.beta.threads.create()

    def create_thread_with_assistant_message(self) -> Thread:
        return self.openai_client.beta.threads.create(
            messages=[
                {
                    "role": "assistant",
                    "content": f"Current conversation start on {localize_datetime(datetime.utcnow()).strftime('%Y-%m-%d %H:%M:%S %Z')}",
                    "metadata": {
                        "user_id": "system_user",
                        "user_name": "system_user",
                        "message_action": "system prompt"
                    }
                }
            ]
        )

    def delete_thread(self, thread_id: str):
        try:
            self.openai_client.beta.threads.delete(thread_id)
        except NotFoundError:
            print("No thread found")

    def create_message(self, thread_id: str, prompt: str):
        # OpenAI API 期望收到一个对象而不是字符串
        message = self.openai_client.beta.threads.messages.create(
            thread_id=thread_id,
            role="user",
            content=[
                {
                    "type": "text",
                    "text": prompt
                }
            ],
            metadata={
                "user_id": self.user_id,
                "user_name": self.user_name,
                "message_action": "user prompt",
            }
        )

    def create_file(self, uploaded_file: UploadedFile, purpose: Literal["assistants", "batch", "fine-tune", "vision", "user_data"] = "assistants"):
        file_content = uploaded_file.read()
        print(f"[DEBUG] File name: {uploaded_file.name}, Content length: {len(file_content)} bytes")

        if len(file_content) == 0:
            raise ValueError(f"File '{uploaded_file.name}' is empty (0 bytes). Please check the file content.")

        new_filename = lowercase_file_extension(uploaded_file.name)
        new_file = io.BytesIO(file_content)
        new_file.name = new_filename
        new_file.seek(0)  # Reset file pointer to the beginning

        file =  self.openai_client.files.create(
            file=new_file,
            purpose=purpose
        )
        print(f"create openai file: {file}")
        return file

    @staticmethod
    @st.cache_data(show_spinner=False, ttl=60 * 60 * 24 * 1)
    def retrieve_file(file_id, _openai_client: OpenAI):
        file = None
        try:
            file = _openai_client.files.retrieve(file_id)
        except NotFoundError:
            print("No file found")
        return file

    @staticmethod
    @st.cache_data(show_spinner=False, ttl=60 * 60 * 1)
    def retrieve_file_content(file_id, _openai_client: OpenAI):
        return _openai_client.files.content(file_id).content

    def client_delete_file(self, file_id: str):
        try:
            self.openai_client.files.delete(file_id)
            print(f"client_delete_file - {file_id}")
        except NotFoundError:
