    def create_vector_store(self, file_ids: Sequence[str] | Omit = omit, expires_after_days: int|Omit = omit):
        """
        创建 Vector Store

        参数:
        - file_ids: 文件ID列表
        - expires_after_days: 过期天数，默认永不过期
          - omit: 永不过期（企业级应用推荐）
          - int: 指定天数后过期（基于 last_active_at）
        """
        expires_after = omit
        if isinstance(expires_after_days, int):
            expires_after = {
                "anchor": "last_active_at",
                "days": expires_after_days
            }
        return self.openai_client.vector_stores.create(
            file_ids=file_ids,
            expires_after=expires_after
        )

    def retrieve_vector_store(self, vector_store_id: str):
        retrieved_vector_store = None
        try:
            retrieved_vector_store = self.openai_client.vector_stores.retrieve(vector_store_id=vector_store_id)
        except NotFoundError:
            print("No vector store found")
        return retrieved_vector_store

    def create_vector_store_file_batch(self, vector_store_id: str, file_ids: Sequence[str], ui_markdown: bool = False, timeout_seconds: int = 300):
        """Add files to vector store one by one with polling.

        Uses individual vector_stores.files.create + poll instead of
        file_batches API because openai SDK 2.x has a bug where
        file_batches passes vector_store_id as batch_id, causing 400.
        """
        print(f"create_vector_store_file_batch -> vector_store_id: {vector_store_id}, file_ids: {file_ids}")
        if ui_markdown:
            st.caption(f"File search tool create_vector_store_file_batch -> vector_store_id: {vector_store_id}, file_ids: {file_ids}")

        for file_id in file_ids:
            vs_file = self.openai_client.vector_stores.files.create(
                vector_store_id=vector_store_id,
                file_id=file_id
            )
            print(f"create_vector_store_file_batch -> file created: {vs_file.id}, status: {vs_file.status}")

            poll_interval = 1.0
            elapsed = 0.0
            while vs_file.status == "in_progress" and elapsed < timeout_seconds:
                time.sleep(poll_interval)
                elapsed += poll_interval
                vs_file = self.openai_client.vector_stores.files.retrieve(
                    vector_store_id=vector_store_id,
                    file_id=vs_file.id
                )
                print(f"create_vector_store_file_batch poll [{elapsed:.0f}s] -> file {vs_file.id} status={vs_file.status}")

            if vs_file.status == "in_progress":
                print(f"create_vector_store_file_batch -> TIMEOUT after {timeout_seconds}s for file {vs_file.id}")

        print(f"create_vector_store_file_batch -> all {len(file_ids)} files processed")
        if ui_markdown:
            st.caption(f"create_vector_store_file_batch -> all {len(file_ids)} files processed")

    def delete_vector_store_file(self, vector_store_id: str, file_id: str):
        try:
            self.openai_client.vector_stores.files.delete(
                vector_store_id=vector_store_id,
                file_id=file_id
            )
            print(f"delete_vector_store_file -> vector_store_id: {vector_store_id}, file_id: {file_id}")
        except NotFoundError:
            print("No vector_store_file found")

    def delete_vector_store(self, vector_store_id: str):
        try:
            self.openai_client.vector_stores.delete(
                vector_store_id=vector_store_id
