    def retrieve_container_files(self, container_id: str):
        all_container_files = []
        result = []
        try:
            after = NOT_GIVEN
            while len(all_container_files) < 500:
                retrieved_container_files = self.openai_client.containers.files.list(
                    container_id=container_id,
                    order="desc",
                    limit=100,
                    after=after
                )
                container_files = retrieved_container_files.data
                if not container_files:
                    break
                all_container_files = all_container_files + container_files
                after = container_files[-1].id
                if not retrieved_container_files.has_next_page():
                    break
            result = all_container_files
        except Exception as list_container_files_error:
