    def list_completed_run_messages(self, thread_id: str, run_id: str):
        run_messages = []
        thread_messages = self.openai_client.beta.threads.messages.list(
            thread_id=thread_id,
            order="desc",
            limit=20
        )
        for thread_message in thread_messages.data:
            if thread_message.thread_id == thread_id and thread_message.run_id == run_id and thread_message.role == "assistant":
                if len(thread_message.content) > 0:
                    # run_messages.append({"role": "assistant", "content": thread_message.content})
                    run_messages.insert(0, {"role": "assistant", "content": thread_message.content})
        return run_messages

    def check_openai_run_with_progress_bar(self, thread_id: str, run_id: str, processing_statement: str, interval_second: int,
                                           process_time_estimated: int):
        print(f"thread_id:{thread_id}, run_id:{run_id}")
        progress_bar = st.progress(0, text=processing_statement)
        running_seconds = 0
        run_messages = []
        while True:
            if int(running_seconds) > 60 * 10:
                print(f"Run timeout exceed 10 minutes")
                break
            time.sleep(int(interval_second))
            running_seconds = running_seconds + int(interval_second)
            percent_complete = round(running_seconds / process_time_estimated, 2)
            if percent_complete >= 1:
                percent_complete = 0.99
            progress_bar.progress(percent_complete, text=processing_statement)
            print("check run info... running seconds " + str(running_seconds) + "s")
            run_info = self.openai_client.beta.threads.runs.retrieve(thread_id=thread_id, run_id=run_id)
            # print(str(run_info))
            if run_info.completed_at:
                print(f"Run completed")
                run_messages = self.list_completed_run_messages(thread_id, run_id)
                break
            elif run_info.failed_at:
                print(f"Run failed")
                break
            elif run_info.cancelled_at:
                print(f"Run cancelled")
                break
        progress_bar.progress(100, text=processing_statement)
        print("All done...")
        # messages = client.beta.threads.messages.list(thread_id)
        print(str(run_messages))
        return run_messages

