        print("run_steps_error_handler started")
        error_message = None
        for run_step in run_steps:
            if run_step.status == "failed":
                if run_step.last_error:
                    error_message = self.openai_client.beta.threads.messages.create(
                        thread_id=thread_id,
                        role="assistant",
                        content=str(run_step.last_error.code) + ", " + str(run_step.last_error.message),
