            if isinstance(content_item, dict):
                match str(content_item['type']):
                    case 'text':
                        message_content = content_item['text']
                    case 'image_file':
                        image_file_id = content_item['image_file']['file_id']
            else:
                if str(getattr(content_item, 'type')) == "image_file":
