            thread_messages_cursorpage = self.openai_client.beta.threads.messages.list(
                thread_id=thread_id,
                order="desc",
                limit=100,
                after=after
            )
            thread_messages = thread_messages_cursorpage.data
            if not thread_messages:
                break
            all_messages = all_messages + thread_messages
            after = thread_messages[-1].id
            if not thread_messages_cursorpage.has_next_page():
                break
        return self.custom_thread_messages(thread_messages=all_messages)

