    def write_chat_messages(self, messages, funct_name: str = "GPT Response", hide_file_citation: bool = False):
        from utils.chatbot_utils import st_chat_message_advanced_and_feedback
        # print(str(messages))
        log_input_text = ""
        for message_index, message in enumerate(messages):
            with st.chat_message(message["role"]):
                if message["role"] == "assistant":
                    self.load_message(message["content"], True, hide_file_citation=hide_file_citation)
                    copied_text = ""
                    for content_item in message["content"]:
                        # 处理字典格式的内容项（来自 Dify）
                        if isinstance(content_item, dict) and "type" in content_item:
                            if content_item["type"] == "text":
                                if isinstance(content_item.get("text"), str):
                                    copied_text = copied_text + content_item["text"] + "\n"
                                elif isinstance(content_item.get("text"), dict) and "value" in content_item["text"]:
                                    copied_text = copied_text + content_item["text"]["value"] + "\n"
                        # 处理对象格式的内容项（来自 OpenAI）
                        elif hasattr(content_item, "type"):
                            if str(content_item.type) == "text":
                                copied_text = copied_text + content_item.text.value + "\n"
                    if copied_text:
                        copied_text = re.sub(r'【\d+:\d+†.*】', '', copied_text)
                        st_chat_message_advanced_and_feedback(
                            key='chatbot_message_adv_' + str(message_index),
                            text=copied_text,
                            funct_group=self.funct_group,
                            funct_name=funct_name,
                            log_input=log_input_text
                        )
                else:
                    # st.markdown(message["content"])
                    if isinstance(message["content"], str):
                        st.markdown(custom_markdown_text(message["content"]))
                        log_input_text = str(custom_markdown_text(message["content"]))
                    else:
                        self.load_message(message["content"], True)
                        try:
                            log_input_text = ""
                            for content_item in message["content"]:
                                if isinstance(content_item, dict):
                                    if str(content_item['type']) == "image_file":
                                        image_file_id = content_item['image_file']['file_id']
                                        log_input_text = log_input_text + f"Image upload: {image_file_id}\n"
                                    elif str(content_item['type']) == "text":
                                        log_input_text = log_input_text + content_item['text'] + "\n"
                                else:
                                    if str(getattr(content_item, 'type')) == "text":
                                        log_input_text = log_input_text + content_item.text.value + "\n"
                                    elif str(getattr(content_item, 'type')) == "image_file":
                                        image_file_id = content_item.image_file.file_id
                                        log_input_text = log_input_text + f"Image upload: {image_file_id}\n"

                        except Exception as get_log_input_text_error:
                            print(get_log_input_text_error)

    def reset_thread_vector_store(self, thread_id):
        my_thread = self.openai_client.beta.threads.retrieve(thread_id)
        if my_thread.tool_resources is not None and my_thread.tool_resources.file_search is not None and my_thread.tool_resources.file_search.vector_store_ids is not None:
            new_vector_store = self.openai_client.vector_stores.create()
            vector_store_ids = my_thread.tool_resources.file_search.vector_store_ids
            for vs_id in vector_store_ids:
                vector_store_files = self.list_vector_store_files(vector_store_id=vs_id, limit=100)
                for file in vector_store_files:
                    self.openai_client.vector_stores.files.create(
                        vector_store_id=new_vector_store.id,
                        file_id=file.id
                    )
            self.openai_client.beta.threads.update(
                thread_id,
                tool_resources={
                    "file_search": {
                        "vector_store_ids": [new_vector_store.id]
                    },
                }
            )

