    def upload_vision_image_and_update_thread_metadata(self, thread_id: str, image_files: list[UploadedFile]):
        with st.spinner("Upload image..."):
            uploaded_vision_image_file_ids = []
            for image_file in image_files:
                if not image_file.type.lower().startswith('image/'):
                    continue
                openai_image_file = self.create_file(image_file, 'vision')
                st.markdown(f"Image file uploaded: {image_file.name}")
                uploaded_vision_image_file_ids.append(openai_image_file.id)
        thread = self.openai_client.beta.threads.retrieve(thread_id=thread_id)
        if thread.metadata and thread.metadata.get('vision_image_file_ids_str'):
            full_vision_image_file_ids_str = thread.metadata.get('vision_image_file_ids_str')
            full_vision_image_file_ids = full_vision_image_file_ids_str.strip(" ").split(",")
            full_vision_image_file_ids.extend(uploaded_vision_image_file_ids)
        else:
            full_vision_image_file_ids = uploaded_vision_image_file_ids
        self.openai_client.beta.threads.update(
            thread_id = thread_id,
            metadata= {
                'vision_image_file_ids_str': ','.join(full_vision_image_file_ids)
            }
        )
        print(f"Upload vision image files completed: {uploaded_vision_image_file_ids}")
        return uploaded_vision_image_file_ids

    def delete_thread_files(self, thread_id: str):
        try:
            print(f"starting delete_thread_files: {thread_id}")
            thread = self.openai_client.beta.threads.retrieve(thread_id=thread_id)
            thread_file_ids_hashset = set()
            tool_resources = thread.tool_resources
            if tool_resources:
                if tool_resources.file_search and tool_resources.file_search.vector_store_ids:
                    vector_store_id = tool_resources.file_search.vector_store_ids[0]
                    vector_store_files = self.list_vector_store_files(vector_store_id=vector_store_id, limit=100)
                    for file in vector_store_files:
                        thread_file_ids_hashset.add(file.id)
                if tool_resources.code_interpreter and tool_resources.code_interpreter.file_ids:
                    code_interpreter_file_ids = tool_resources.code_interpreter.file_ids
                    for code_interpreter_file_id in code_interpreter_file_ids:
                        thread_file_ids_hashset.add(code_interpreter_file_id)
            try:
                print(f"thread.metadata: {thread.metadata}")
                if thread.metadata and thread.metadata.get('vision_image_file_ids_str'):
                    vision_image_file_ids_str = thread.metadata['vision_image_file_ids_str']
                    vision_image_file_ids = vision_image_file_ids_str.strip(" ").split(",")
                    print(f"vision_image_file_ids_str: {vision_image_file_ids_str}, vision_image_file_ids: {vision_image_file_ids}")
                    for vision_image_file_id in vision_image_file_ids:
                        thread_file_ids_hashset.add(vision_image_file_id)
            except Exception:
                print("Delete thread file: get vision image files error")
            for thread_file_id in thread_file_ids_hashset:
                try:
                    self.client_delete_file(file_id=thread_file_id)
                except Exception:
                    print(f"Skip delete thread file - {thread_file_id}")
        except NotFoundError:
            print(f"Thread_id not found: {thread_id}")

