    def update_assistant_tools(self, tools: list):
        # 如果丝是openai类型，跳过OpenAI验话
        if hasattr(self, 'agent_type') and self.agent_type != 'openai':
            # 返回一个模拟的更新结果
            class MockAssistantUpdate:
                def __init__(self, assistant_id):
                    self.id = assistant_id
                    self.tools = tools

            return MockAssistantUpdate(self.assistant_id)

        tools_config = load_tools_config()
        tools_input_list = []
        tool_prompts = []

        for tool_input in tools:
            config = tools_config.get(tool_input)
            if not config or not config['enabled']:
                continue

            if config['type'] == 'function':
                tools_input_list.append({
                    "type": "function",
                    "function": config['function']
                })
            else:
                tools_input_list.append({"type": config['type']})

            # 如果工具有杝示话，添加到杝示话列表
            if 'prompt' in config:
                tool_prompts.append(f"〝{config['name']} tool usage instructions】\n{config['prompt']}\n")

        print(f"update_assistant_tools: {tools_input_list}")

        # 获坖当剝助手信杯
        assistant = self.openai_client.beta.assistants.retrieve(
            assistant_id=self.assistant_id
        )

        # 如果有工具杝示话，更新助手指令
        if tool_prompts:
            current_instructions = assistant.instructions
            tool_prompts_text = "\n".join(tool_prompts)
            new_instructions = f"{current_instructions}\n\n{tool_prompts_text}"

            # 更新助手，包坫工具和新指令
            return self.openai_client.beta.assistants.update(
                assistant_id=self.assistant_id,
                tools=tools_input_list,
                instructions=new_instructions
            )
        else:
            # 如果没有工具杝示话，坪更新工具
            return self.openai_client.beta.assistants.update(
                assistant_id=self.assistant_id,
                tools=tools_input_list
            )

