    def create_run_stream(self,
                          thread_id: str,
                          model: Union[str, ChatModel, None] | NotGiven = NOT_GIVEN,
                          additional_messages = None,
                          tools: Iterable[CodeInterpreterToolParam | FileSearchToolParam | FunctionToolParam] | None | NotGiven = NOT_GIVEN,
                          reasoning_effort: Literal["low", "medium", "high"] | None | NotGiven = NOT_GIVEN,
                          custombot_chat: CustomBotChat | None = None,
                          additional_instructions: str | None | NotGiven = NOT_GIVEN
                          ):
        # 如果丝是openai类型，返回一个错误信息
        if hasattr(self, 'agent_type') and self.agent_type != 'openai':
            raise NotImplementedError(f"create_run_stream is not supported for assistant type: {self.agent_type}")

        """
        thread_id: current thread id,
        model: override default model,
        additional_messages: add messages to thread before run e.g:
            [
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "text",
                            "text": "Identify the image"
                        },
                        {
                            "type": "image_file",
                            "image_file": {"file_id": "file-R7DFFVHamyTPRbJXRu4y3G"}
                        },
                        {
                            "type": "image_url",
                            "image_url": {
                            "url": "https://upload.wikimedia.org/wikipedia/commons/thumb/d/dd/Gfp-wisconsin-madison-the-nature-boardwalk.jpg/2560px-Gfp-wisconsin-madison-the-nature-boardwalk.jpg"
                            }
                        }
                    ]
                }

            ]
        """
        self.set_thread_id(thread_id)

        # 检查email工具是否启用
        email_enabled = False
        email_instruction = ""

        # 从Assistant配置中检查email_notification工具是否启用
        try:
            assistant = self._get_assistant()
            if assistant and hasattr(assistant, 'tools'):
                for tool in assistant.tools:
                    if hasattr(tool, 'type') and tool.type == 'function' and hasattr(tool, 'function') and hasattr(tool.function, 'name'):
                        if tool.function.name == 'email_notification':
                            email_enabled = True
                            # 添加email工具的使用说明
                            email_instruction = """
Email Notification Tool Guidelines:
1. The system automatically retrieves the user's email address, NEVER ask for user's email
2. Not every conversation requires an email, judge necessity based on content
3. IMPORTANT - Email Recipients (choose EXACTLY ONE option, based on priority):
   - Priority 1: If specific email addresses are mentioned in Introductions, extract and use ONLY those exact addresses
     * Look for email addresses in square brackets like [example1@domain.com;example2@domain.com]
     * Or look for explicit statements like "send to: example1@domain.com;example2@domain.com"
     * Copy the exact email addresses as they appear, preserving the semicolon separator
   - Priority 2: If user mentioned sending to the owner, use ONLY 'OWNER'
   - Priority 3: If the first two are not met, use ONLY 'USER' as default
   - DO NOT combine these options, select only one based on the priority above
   - Examples: 'example1@domain.com;example2@domain.com' OR 'OWNER' OR 'USER'
4. Email Subject (email_subject):
   - IMPORTANT: You must check if email_subject has a value before sending the email
   - If the user specified a subject, use that as the value for email_subject
   - IMPORTANT: If not specified, determine if you need to create a concise and descriptive email_subject to summarize the email content
   - For file attachments, consider adding "File Attachment:" at the beginning of the subject
   - Try to keep subject lines within 20 characters when possible
   - Although technically optional, providing a subject improves user experience
5. When generating and sending files:
   - IMPORTANT: Always explicitly mention the generated files and ensure they appear with download links in the chat
   - Use phrases like 'I have generated the following file for you' to trigger file display in the conversation
   - You MUST wait until files are fully generated AND download links are displayed in the chat dialog before sending emails
   - Confirm file download links are visible to the user before sending any email
   - After confirming files are ready and displayed in the chat, set attach_file=true
   - Sending email before files are displayed will result in failure
"""
                            break
        except Exception as e:
            print(f"检查email工具状态时出错: {str(e)}")

        # 如果email工具已启用，将相关指令添加到additional_instructions中
        if email_enabled:
            if additional_instructions is NOT_GIVEN or additional_instructions is None:
                additional_instructions = email_instruction
            else:
                additional_instructions = f"{additional_instructions}\n\n{email_instruction}"
        self.if_run_in_progress = True
        with self.openai_client.beta.threads.runs.stream(
                thread_id=thread_id,
                assistant_id=self.assistant_id,
                model=model,
                additional_messages=additional_messages,
                tools=tools,
                reasoning_effort=reasoning_effort,
                additional_instructions=additional_instructions if email_enabled else NOT_GIVEN,
                event_handler=LFAssistantEventHandler(self, custombot_chat=custombot_chat)
        ) as run_stream:
            run_stream.until_done()
            self.if_run_in_progress = False
            self.run_stream_advanced_handler(run_stream)
            error_message = None
            final_run = run_stream.get_final_run()
            if str(final_run.status) == "failed":
                final_run_steps = run_stream.get_final_run_steps()
                error_message = self.run_steps_error_handler(final_run_steps, thread_id)
            if error_message:
                run_stream.chat_messages.append({"role": error_message.role, "content": error_message.content})
        return run_stream

    def run_stream_advanced_handler(self, run_stream):
        try:
            run_stream: LFAssistantEventHandler
            print(f"run_stream.custombot_chat: {run_stream.custombot_chat}, run_stream.output_files: {run_stream.output_files}")
            if run_stream.custombot_chat:
                if run_stream.output_files and run_stream.custombot_chat.enable_sp_file_upload:
                    sharepoint_file_upload_tool = self.features.get('sharepoint_file_upload')
                    if sharepoint_file_upload_tool:
                        params = {
                            "user_id": self.user_id,
                            "thread_id": run_stream.current_run.thread_id,
                            "assistant_id": self.assistant_id,
                            "file_ids": run_stream.output_files
                        }
                        with st.chat_message("assistant"):
                            with st.spinner("Execute sharepoint file upload"):
                                result = sharepoint_file_upload_tool.execute(params)
                        last_message_id = run_stream.message_ids[-1] if run_stream.message_ids else None
                        if last_message_id:
                            self.openai_client.beta.threads.messages.update(
                                thread_id=run_stream.current_run.thread_id,
                                message_id=last_message_id,
                                metadata={
                                    "user_id": self.user_id,
                                    "user_name": self.user_name,
                                    "message_action": f"sharepoint upload file {'success' if result.get('success') else 'error'}",
                                }
                            )

        except Exception as error:
            print(f"ERROR run_stream_advanced_handler.")

    def check_if_run_in_progress(self, ss_messages_name: str):
        if_list_thread_messages = False
        if self.if_run_in_progress:
            if self.thread_id:
                with st.spinner("GPT Processing without stream..."):
                    try:
                        for check_count in range(1, 11):
                            time.sleep(8)
                            runs = self.openai_client.beta.threads.runs.list(thread_id=self.thread_id)
                            if runs and runs.data and runs.data[0]:
                                last_run = runs.data[0]
                                if last_run.status in ["cancelled", "failed", "completed", "incomplete", "expired"]:
                                    self.if_run_in_progress = False
                                    if_list_thread_messages = True
                                    print("GPT Processing without stream complete.")
                                    break
                                elif last_run.status == "requires_action":
                                    self.if_run_in_progress = False
                                    st.write("Cancel this run as function call not available in non-streaming mode. Please retry later after rerun.")
                                    run_cancel = self.openai_client.beta.threads.runs.cancel(
                                        thread_id=self.thread_id,
                                        run_id=last_run.id
                                    )
                                    time.sleep(5)
                                    break

                    except Exception as retrieve_runs_error:
                        st.error(f"retrieve_runs_error")
                        print(f"retrieve_runs_error - {retrieve_runs_error}")

                    if if_list_thread_messages:
                        st.session_state[ss_messages_name] = self.retrieve_thread_messages_all(self.thread_id)

            else:
                # set to false when have no thread_id
                self.if_run_in_progress = False


    def file_attach_to_assistant_file_search(self, file_id: str,
                                             if_markdown: bool = False) -> (bool, str):
        print("file_attach_to_assistant_file_search")
        assistant_retrieved = self.openai_client.beta.assistants.retrieve(
            assistant_id=self.assistant_id
        )
        tool_resources: ToolResources = assistant_retrieved.tool_resources
        # check if file extension support in file search
        file = self.openai_client.files.retrieve(file_id=file_id)
        extension = os.path.splitext(file.filename)[1]
        if extension and str(extension).lower().lstrip('.') in CODE_INTERPRETER_FILES_TYPE_DIFF:
            if if_markdown: st.warning(
                f"Files with extensions {CODE_INTERPRETER_FILES_TYPE_DIFF} are not supported for retrieval. - {file.filename}")
            return False, f"Files with extensions {CODE_INTERPRETER_FILES_TYPE_DIFF} are not supported for retrieval. - {file.filename}"

        # get vector store
        if tool_resources.file_search and tool_resources.file_search.vector_store_ids:
            vector_store_id = tool_resources.file_search.vector_store_ids[0]
        else:
            print("Creating vector store...")
            vector_store_created = self.openai_client.vector_stores.create(
                name="Vector store - " + str(assistant_retrieved.name)
            )
            vector_store_id = vector_store_created.id
            assistant_updated = self.openai_client.beta.assistants.update(
                assistant_id=self.assistant_id,
                tool_resources={"file_search": {"vector_store_ids": [vector_store_id]}}
            )
            if if_markdown: st.write(f"Create vectore store {vector_store_id} for assistant {self.assistant_id}")
            tool_resources = assistant_updated.tool_resources

        # Note: create_and_poll has a bug in openai SDK 2.x where it passes
        # vector_store_id as batch_id, causing 400 error
        vector_store_file = self.openai_client.vector_stores.files.create(
            vector_store_id=vector_store_id,
            file_id=file_id,
        )
        if if_markdown: st.write(f"Add file {file_id} to vector store {vector_store_id}")

        poll_timeout = 60
        poll_interval = 1.0
        elapsed = 0.0
        while elapsed < poll_timeout:
            file_status = self.openai_client.vector_stores.files.retrieve(
                vector_store_id=vector_store_id,
                file_id=file_id,
            )
            if file_status.status == "completed":
                break
            if file_status.status == "failed":
                if if_markdown: st.warning(f"File {file_id} indexing failed in vector store")
                return False, f"File indexing failed: {file_id}"
            time.sleep(poll_interval)
            elapsed += poll_interval

        return True, "Success"

    def file_unattach_to_assistant_file_search(self, file_id: str,
                                               if_markdown: bool = False) -> ToolResources:
        print("file_unattach_to_assistant_file_search")
