        self.tool_call_progress_bar_text = "🔄 GPT processing..."
        self.tool_call_progress_bar_processed = 0
        self.tool_call_progress_bar_estimated = 200
        self.email_notification_attempted = False  # 添加标记，跟踪是坦已绝尝试坑逝过邮件通知

    def on_message_created(self, message: Message) -> None:
        print("on_message_created: " + str(message), flush=True)
        self.chat_message_placeholder_image = None
        self.chat_message_placeholder_text = None
        # create chat_message
        if message.role:
            self.chat_message_container = st.chat_message(message.role)

    def on_image_file_done(self, image_file: ImageFile) -> None:
        print("on_image_file_done: " + str(image_file), flush=True)
        # display image using st.image in chat_message
        if self.chat_message_container:
            # image_placeholder -- to preload the image
            if not self.chat_message_placeholder_image:
                self.chat_message_placeholder_image = self.chat_message_container.empty()
            image_file_id = image_file.file_id
            if image_file_id:
                image_content = retrieve_image_file(image_file_id, _openai_client=self.openai_client_assistant.openai_client)
                if image_content:
                    image = Image.open(io.BytesIO(image_content))
                    self.chat_message_placeholder_image.image(image)
                    self.chat_message_placeholder_image = None

    def on_text_created(self, text: Text) -> None:
        print("on_text_created: " + str(text), flush=True)
        # create chat_message_placeholder in chat_message
        if self.chat_message_container:
            if not self.chat_message_placeholder_image:
                self.chat_message_placeholder_image = self.chat_message_container.empty()
            self.chat_message_placeholder_text = self.chat_message_container.empty()

    def on_text_delta(self, delta: TextDelta, snapshot: Text) -> None:
        # print("on_text_delta: " + str(delta), flush=True)
        # markdown snapshot
        if self.chat_message_placeholder_text:
            # self.chat_message_placeholder_text.markdown(snapshot.value + "▌")
            self.chat_message_placeholder_text.markdown(custom_markdown_text(snapshot.value + "▌"))

    def on_text_done(self, text: Text) -> None:
        print("on_text_done: " + str(text), flush=True)
        # remove "▌", replace
        has_file_paths = False
        # 收集所有文件ID
        for annotation in text.annotations:
            if annotation.type == 'file_path':
                file_id = annotation.file_path.file_id
                self.output_files.append(file_id)
                has_file_paths = True

        if self.chat_message_placeholder_text:
            message_content = message_text_annotations_handler(text, _openai_client=self.openai_client_assistant.openai_client,
                                                               hide_file_citation=True)
            # self.chat_message_placeholder_text.markdown(message_content, unsafe_allow_html=True)
            self.chat_message_placeholder_text.markdown(custom_markdown_text(message_content),
                                                        unsafe_allow_html=True)

            # 如果有文件路径，并且已经显示在对话框中，设置标志为True
            if has_file_paths:
                print("文件下载链接已显示在对话框中", flush=True)
                self.files_displayed_in_chat = True


    def on_message_done(self, message: Message) -> None:
        print("on_message_done: message.completed_at " + str(message.completed_at), flush=True)
        self.chat_message_container = None
        self.chat_messages.append({"role": "assistant", "content": message.content, "attachments":message.attachments})
        self.message_ids.append(message.id)

    def on_tool_call_created(self, tool_call: ToolCall) -> None:
        print("on_tool_call_created: " + str(tool_call), flush=True)
        self.tool_call_progress_bar_processed = 0
        self.tool_call_container = st.empty()
        with self.tool_call_container.container():
            chat_message = st.chat_message("assistant")
            self.tool_call_progress_bar = chat_message.progress(0, text=self.tool_call_progress_bar_text)

    def on_tool_call_delta(self, delta: ToolCallDelta, snapshot: ToolCall) -> None:
        # print("on_tool_call_delta: " + str(delta), flush=True)
        # Create progress bar if not exists
        if not self.tool_call_container:
            self.tool_call_progress_bar_processed = 0
            self.tool_call_container = st.empty()
            with self.tool_call_container.container():
                chat_message = st.chat_message("assistant")
                self.tool_call_progress_bar = chat_message.progress(0, text=self.tool_call_progress_bar_text)

        self.tool_call_progress_bar_processed += 1
        if self.tool_call_container and self.tool_call_progress_bar:
            percent_complete = round(
                int(self.tool_call_progress_bar_processed) / self.tool_call_progress_bar_estimated, 2)
            if percent_complete >= 1:
                percent_complete = 0.99
            elif percent_complete <= 0:
                percent_complete = 0
            self.tool_call_progress_bar.progress(percent_complete, text=self.tool_call_progress_bar_text)

    def on_tool_call_done(self, tool_call: ToolCall) -> None:
        print("on_tool_call_done: " + str(tool_call), flush=True)
        self.tool_call_progress_bar_processed = 0

        # Clean up progress bar if exists
        if self.tool_call_container:
            if self.tool_call_progress_bar:
                self.tool_call_progress_bar.progress(1, text=self.tool_call_progress_bar_text)
            self.tool_call_container.empty()
            self.tool_call_container = None

        # Handle function calls that require action
        if getattr(tool_call, 'function', None) and self.current_event.event == 'thread.run.requires_action':
            self.handle_tool_call_requires_action(tool_call)

