    def handle_tool_call_requires_action(self, tool_call: ToolCall):
        tool_outputs = []
        completed_tools = []  # 初始化completed_tools列表
        tools = self.openai_client_assistant.tools
        required_actions = self.current_run.required_action

        if required_actions and required_actions.submit_tool_outputs:
            required_tool_calls = required_actions.submit_tool_outputs.tool_calls

            # 创建一个映射来跟踪所有需覝的工具调用
            required_tool_ids = {tool_call.id: tool_call for tool_call in required_tool_calls}

            # 创建进度显示容器
            progress_container = st.empty()

            # 对工具调用进行分组和排庝
            search_tools = []
            summarize_tools = []
            deep_research_tools = []  # 新增deep_research工具组
            other_tools = []

            print("\nTool calls to process:")
            for required_tool_call in required_tool_calls:
                tool_name = required_tool_call.function.name
                print(f"Tool call: {tool_name} (ID: {required_tool_call.id})")
                print(f"Arguments: {required_tool_call.function.arguments}")

                # 检查是否是需要附件的邮件工具调用，且没有可用文件
                if tool_name == 'email_notification':
                    try:
                        params = json.loads(required_tool_call.function.arguments)
                        if params.get("attach_file") and not self.output_files:  # 使用output_files列表判断文件是否存在
                            print(f"检测到AI尝试调用带附件的邮件工具，但没有文件生成，跳过此工具调用")
                            error_message = "文件尚未显示在聊天框中，请先确保文件已生成并显示下载链接，然后再尝试发送邮件"
                            # 直接添加到输出中，不显示进度条
                            tool_outputs.append({
                                "tool_call_id": required_tool_call.id,
                                "output": json.dumps({
                                    'error': error_message,
                                    'status': 'no_files_available'
                                }, ensure_ascii=False)
                            })
                            # 从待处理列表中移除
                            required_tool_ids.pop(required_tool_call.id, None)
                            continue
                    except Exception as e:
                        print(f"An error occurred when parsing the parameters of the email tool: {str(e)}")

                # 将工具分类到相应的组中
                if tool_name == 'firecrawl_scrape_url':
                    print(f"Adding to summarize tools: {tool_name}")
                    summarize_tools.append(required_tool_call)
                elif tool_name in ['google_search']:
                    print(f"Adding to search tools: {tool_name}")
                    search_tools.append(required_tool_call)
                elif tool_name == 'deep_research':
                    print(f"Adding to deep research tools: {tool_name}")
                    deep_research_tools.append(required_tool_call)
                else:
                    print(f"Adding to other tools: {tool_name}")
                    other_tools.append(required_tool_call)


            # 首先执行杜索工具  
            search_results = []

            if search_tools:
                print("\nExecuting search tools...")
                with progress_container.container():
                    chat_message = st.chat_message("assistant")
                    status_cols = chat_message.columns(max(len(search_tools), 1))
                    status_dict = {}

                    # 执行所有杜索工具
                    for idx, required_tool_call in enumerate(search_tools):
                        try:
                            params = json.loads(required_tool_call.function.arguments)
                            status_dict[required_tool_call.id] = {
                                "progress": status_cols[idx].progress(0.0, text=f"🔄 {required_tool_call.function.name} processing...")
                            }

                            # 直接执行杜索，丝使用线程池
                            result = self._execute_tool_without_ui(
                                required_tool_call,
                                required_tool_call.function.name,
                                params
                            )

                            if result:
                                print(f"Search result: {result}")
                                tool_outputs.append({
                                    "tool_call_id": result["tool_call_id"],
                                    "output": result["output"]
                                })

                                if result["success"]:
                                    status_dict[required_tool_call.id]["progress"].progress(1.0, text=f"✅ {result['tool_name']} completed")
                                    completed_tools.append(result["tool_name"])
                                    # 将杜索结果添加到列表中
                                    try:
                                        output_data = json.loads(result["output"])
                                        if output_data.get("success"):
                                            search_results.append(output_data.get("data", {}))
                                            print(f"Added search result: {output_data.get('data', {})}")
                                    except Exception as e:
                                        print(f"Error parsing search result: {str(e)}")
                                else:
                                    status_dict[required_tool_call.id]["progress"].progress(1.0, text=f"❌ {result['tool_name']} failed")

                            required_tool_ids.pop(required_tool_call.id, None)

                        except Exception as e:
                            print(f"Error executing search tool: {str(e)}")
                            error_output = json.dumps({'error': str(e)})
                            tool_outputs.append({
                                "tool_call_id": required_tool_call.id,
                                "output": error_output
                            })
                            status_dict[required_tool_call.id]["progress"].progress(1.0, text=f"❌ error: {str(e)}")
                            required_tool_ids.pop(required_tool_call.id, None)

            # print(f"\nSearch results collected: {len(search_results)}")

            # 处睆deep_research工具
            if deep_research_tools:
                print("\nExecuting deep research tools...")
                with progress_container.container():
                    chat_message = st.chat_message("assistant")
                    status_cols = chat_message.columns(max(len(deep_research_tools), 1))
                    status_dict = {}

                    for idx, required_tool_call in enumerate(deep_research_tools):
                        try:
                            params = json.loads(required_tool_call.function.arguments)
                            status_dict[required_tool_call.id] = {
                                "progress": status_cols[idx].progress(0.0, text=f"🔝 Deep research is in progress, please wait (expected 2-3 minutes)...")
                            }

                            # 更新进度条到10%表示开始处睆
                            status_dict[required_tool_call.id]["progress"].progress(
                                0.1, 
                                text=f"🔝 Deep research is in progress, please wait (expected 2-3 minutes)..."
                            )

                            # 直接执行deep_research工具，丝等待结果
                            params["stream"] = True
                            result = self._execute_tool_without_ui(
                                required_tool_call,
                                'deep_research',
                                params
                            )

                            if result:
                                print(f"Deep research result: {result}")
                                tool_outputs.append({
                                    "tool_call_id": result["tool_call_id"],
                                    "output": result["output"]
                                })

                                if result["success"]:
                                    status_dict[required_tool_call.id]["progress"].progress(
                                        1.0, 
                                        text=f"✅ Deep research completed!"
                                    )
                                    completed_tools.append(result["tool_name"])
                                else:
                                    status_dict[required_tool_call.id]["progress"].progress(
                                        1.0, 
                                        text=f"❌ Deep research failed!"
                                    )
                            required_tool_ids.pop(required_tool_call.id, None)

                        except Exception as e:
                            print(f"Error executing deep research tool: {str(e)}")
                            error_output = json.dumps({'error': str(e)})
                            tool_outputs.append({
                                "tool_call_id": required_tool_call.id,
                                "output": error_output
                            })
                            status_dict[required_tool_call.id]["progress"].progress(
                                1.0, 
                                text=f"❌ Deep research error: {str(e)}"
                            )
                            required_tool_ids.pop(required_tool_call.id, None)

            # 执行总结工具
            if summarize_tools:
                if search_results:
                    urls = []
                    for result in search_results:
                        if isinstance(result, list):
                            urls.extend([item.get('link') for item in result if item.get('link')])
                        elif isinstance(result, dict):
                            urls.extend([item.get('link') for item in result.get('items', []) if item.get('link')])
                    urls = urls[:5]  # 陝制URL数針
                else:
                    urls = []
                    for tool_call in summarize_tools:
                        try:
                            params = json.loads(tool_call.function.arguments)
                            if 'url' in params:
                                urls.append(params['url'])
                                print(f"Added URL from tool call: {params['url']}")
                        except Exception as e:
                            print(f"Error parsing tool call arguments: {str(e)}")

                if not urls:
                    print("No valid URLs found to process")
                    error_output = json.dumps({'error': 'No valid URLs found to process'})
                    for tool_call in summarize_tools:
                        tool_outputs.append({
                            "tool_call_id": tool_call.id,
                            "output": error_output
                        })
                        required_tool_ids.pop(tool_call.id, None)
                else:
                    print(f"\nProcessing {len(urls)} URLs: {urls}")

                    with progress_container.container():
                        chat_message = st.chat_message("assistant")
                        status_cols = chat_message.columns(max(len(summarize_tools), 1))
                        status_dict = {}
                        # 先为每个 summarize 工具创建进度条占位，避免长时间无显示
                        for idx, pre_tool_call in enumerate(summarize_tools):
                            try:
                                status_dict[pre_tool_call.id] = {
                                    "progress": status_cols[idx].progress(0.0, text=f"🔄 {pre_tool_call.function.name} processing...")
                                }
                            except Exception:
                                pass

                        # 仅执行一次抓取，复用结果到所有相同工具调用
                        combined_result = None
                        combined_error_output = None
                        # 总进度条（firecrawl整体执行）
                        overall_progress = chat_message.progress(0.0, text="🔄 firecrawl_scrape_url running...")
                        overall_progress.progress(0.05, text="🔄 firecrawl_scrape_url running...")
                        try:
                            if summarize_tools:
                                combined_result = self._execute_tool_without_ui(
                                    summarize_tools[0],
                                    'firecrawl_scrape_url',
                                    {"urls": urls}
                                )
                                if combined_result:
                                    print(f"Firecrawl result: {combined_result}")
                                    overall_progress.progress(1.0, text="✅ firecrawl_scrape_url completed")
                        except Exception as e:
                            print(f"Error executing firecrawl_scrape_url: {str(e)}")
                            combined_error_output = json.dumps({'error': str(e)})
                            overall_progress.progress(1.0, text=f"❌ firecrawl_scrape_url error: {str(e)}")

                        for idx, required_tool_call in enumerate(summarize_tools):
                            try:
                                # 显示进度条
                                status_dict[required_tool_call.id] = {
                                    "progress": status_cols[idx].progress(0.0, text=f"🔄 {required_tool_call.function.name} processing...")
                                }

                                # 复用已计算结果，避免重复执行
                                result = combined_result

                                # 仅提交一次输出给当前 tool_call_id
                                tool_outputs.append({
                                    "tool_call_id": required_tool_call.id,
                                    "output": (result["output"] if result else (combined_error_output or json.dumps({"error": "Failed to process URLs"})))
                                })

                                # 更新进度状态
                                if result and result.get("success"):
                                    status_dict[required_tool_call.id]["progress"].progress(
                                        1.0,
                                        text=f"✅ {required_tool_call.function.name} completed"
                                    )
                                    if result.get("tool_name"):
                                        completed_tools.append(result["tool_name"])
                                else:
                                    status_dict[required_tool_call.id]["progress"].progress(
                                        1.0,
                                        text=f"❌ {required_tool_call.function.name} failed"
                                    )

                                # 从待处理列表中移除
                                required_tool_ids.pop(required_tool_call.id, None)

                            except Exception as e:
                                print(f"Error in summarize tool: {str(e)}")
                                error_output = json.dumps({'error': str(e)})
                                tool_outputs.append({
                                    "tool_call_id": required_tool_call.id,
                                    "output": error_output
                                })
                                status_dict[required_tool_call.id]["progress"].progress(
                                    1.0,
                                    text=f"❌ {required_tool_call.function.name} error: {str(e)}"
                                )
                                required_tool_ids.pop(required_tool_call.id, None)

            # 执行其他工具
            if other_tools:
                with progress_container.container():
                    chat_message = st.chat_message("assistant")
                    status_cols = chat_message.columns(max(len(other_tools), 1))
                    status_dict = {}

                    for idx, required_tool_call in enumerate(other_tools):
                        try:
                            params = json.loads(required_tool_call.function.arguments)
                            status_dict[required_tool_call.id] = {
                                "progress": status_cols[idx].progress(0.0, text=f"🔄 {required_tool_call.function.name} processing...")
                            }            
                            result = self._execute_tool_without_ui(
                                required_tool_call,
                                required_tool_call.function.name,
                                params
                            )

                            if result:
                                print(f"Tool result: {result}")
                                tool_outputs.append({
                                    "tool_call_id": result["tool_call_id"],
                                    "output": result["output"]
                                })

                                if result["success"]:
                                    status_dict[required_tool_call.id]["progress"].progress(
                                        1.0,
                                        text=f"✅ {result['tool_name']} completed"
                                    )
                                    completed_tools.append(result["tool_name"])
                                else:
                                    status_dict[required_tool_call.id]["progress"].progress(
                                        1.0,
                                        text=f"❌ {result['tool_name']} failed"
                                    )
                            required_tool_ids.pop(required_tool_call.id, None)

                        except Exception as e:
                            print(f"Error executing other tool: {str(e)}")
                            error_output = json.dumps({'error': str(e)})
                            tool_outputs.append({
                                "tool_call_id": required_tool_call.id,
                                "output": error_output
                            })
                            status_dict[required_tool_call.id]["progress"].progress(
                                1.0,
                                text=f"❌ {required_tool_call.function.name} error: {str(e)}"
                            )
                            required_tool_ids.pop(required_tool_call.id, None)

            # 处睆任何未执行的工具调用
            for tool_id, tool_call in required_tool_ids.items():
                tool_outputs.append({
                    "tool_call_id": tool_id,
                    "output": json.dumps({'error': 'Tool execution was skipped'})
                })

        # 杝交所有工具输出
        self.submit_tool_outputs(tool_outputs)

    def submit_tool_outputs(self, tool_outputs):
        # Use the submit_tool_outputs_stream helper
        print(f"submit_tool_outputs and run")
        with self.openai_client_assistant.openai_client.beta.threads.runs.submit_tool_outputs_stream(
                thread_id=self.current_run.thread_id,
                run_id=self.current_run.id,
                tool_outputs=tool_outputs,
                event_handler=LFAssistantEventHandler(self.openai_client_assistant, self.custombot_chat),
        ) as stream:
            for text in stream.text_deltas:
                print(text, end="", flush=True)
            print()
            stream.until_done()
            self.chat_messages.extend(stream.chat_messages)
            self.output_files.extend(stream.output_files)
            self.message_ids.extend(stream.message_ids)


    def on_exception(self, exception: Exception) -> None:
        print("on_exception: " + str(self.current_run), flush=True)
        print("on_exception: " + str(exception), flush=True)

    def _execute_email_notification_silently(self):
        """
        在有文件输出时丝让LLM决定是坦坑逝
        会自动坑逝邮件通知用户文件
        在对话结束坎执行邮件通知
        """
        try:            
            # 使用 EmailNotificationTool 坑逝邮件通知
            email_tool = self.openai_client_assistant.features.get('email_notification')
            if not email_tool:
                print("EmailNotificationTool 丝坯用")
                return

            # 准备邮件坂数
            params = {
                "role": "CustomBot Notification - testshare",
                "email_html_content": """
                <h2>Your file has been generated</h2>
                <p>Your AI assistant has generated a file, please check the email attachment.</p>
                <p>Generated file count: {}</p>
                <p>File list: {}</p>
                """.format(
                    len(self.output_files),
                    "<ul>" + "".join([f"<li>{file_id}</li>" for file_id in self.output_files]) + "</ul>"
                ),
                "attach_file": True  
            }

            print(f"静默执行邮件通知，坂数: {params}")

            # 创建一个模拟的ToolCall对象
            class MockToolCall:
                def __init__(self):
                    self.id = "email_notification_silent"

            mock_tool_call = MockToolCall()

            # 直接调用_execute_tool_without_ui方法执行邮件通知
            self._execute_tool_without_ui(mock_tool_call, 'email_notification', params)             
        except Exception as e:
            print(f"Error executing email notification silently: {str(e)}")

    def _execute_tool_without_ui(self, tool_call: ToolCall, tool_name: str, params: dict):
        tool = self.openai_client_assistant.tools.get(tool_name)
        if tool:
            try:
                if tool_name == 'user_info' and hasattr(tool, 'tool_data'):
                    from .tools.base import ToolData
                    tool_data = ToolData(
                        user_id=self.openai_client_assistant.user_id,
                        user_name=self.openai_client_assistant.user_name,
                        user_email=self.openai_client_assistant.user_email,
