def insert_file_identifier_in_json(json_object, file_name):
    updated_json_object = []
    for item in json_object:
        # If 'file_identifier' is already the first key, update its value. Otherwise, create a new key starting with 'file_identifier'.
        if 'file_identifier' in item:
            item['file_identifier'] = file_name
            updated_json_object.append(item)
        if 'data' in item:
            updated_json_object.append(item)

    # print(updated_json_object)
    return updated_json_object

def extract_preview_to_excel(data_doc_metadatas, data_doc_tables):
    print(f"data_doc_tables {data_doc_tables}")
    if not data_doc_metadatas and not data_doc_tables:
        raise Exception("No data found in both doc metadata & table")
    output = BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        # Convert the first set of JSON data to a DataFrame and write it to its sheet
        if data_doc_metadatas:
            for data_doc_metadata in data_doc_metadatas:
                df1 = pd.json_normalize(data_doc_metadata['document_metadata'])
                tmp_metadata_name = sanitize_worksheet_name(data_doc_metadata.get("tab_name"))
                df1.to_excel(writer, sheet_name=tmp_metadata_name, index=False)
        if data_doc_tables:
            sheet_name_set = set()
            for doc_table_index, doc_table_data in enumerate(data_doc_tables):
                if doc_table_data.get("tab_name") :
                    tmp_table_name = sanitize_worksheet_name(doc_table_data.get("tab_name"))
                    if tmp_table_name not in sheet_name_set:
                        sheet_name_set.add(tmp_table_name)
                    else:
                        tmp_table_name = f"document_table_{doc_table_index + 1}"
                else:
                    tmp_table_name = f"document_table_{doc_table_index + 1}"
                output_document_table_data = doc_table_data.get("document_table")
                output_table_df = pd.DataFrame(output_document_table_data, columns=output_document_table_data[0]).iloc[1:len(output_document_table_data)]
                output_table_df.to_excel(writer, sheet_name=tmp_table_name, index=False)
    output.seek(0)
    return output

