def verify_document_type(in_out_identity_data):
    # ensure doc_type unique
    doc_type_set = set()
    for doc_index, doc in enumerate(in_out_identity_data):
        if doc.get('document_type'):
            if doc['document_type'] in doc_type_set:
                doc_type_set.add(f"doc_type_{doc_index}_{str(doc['document_type'])}")
                doc['document_type'] = f"doc_type_{doc_index}_{str(doc['document_type'])}"
            else:
                doc_type_set.add(str(doc['document_type']))
        else:
            doc_type_set.add(f"doc_type_{doc_index}")
            doc['document_type'] = f"doc_type_{doc_index}"
    return in_out_identity_data

class DataSelection:
    def __init__(self, identity_data: [], file_name: str = ""):
        self.identity_data = verify_document_type(identity_data)
        # self.identity_data_selection = [
        #     {
        #         **doc_data,  # Keep all original document data
        #         "document_metadata_selected": True,
        #         "document_tables": [
        #             {
        #                 "table_name": table["table_name"],
        #                 "selected": False,  # Add this new field
        #                 "table_schema": convert_list_of_dict_to_dict_nested_list(table["table_schema"])
        #             }
        #             for table in doc_data["document_tables"]
        #         ]
        #     }
        #     for doc_data in identity_data
        # ]
        self.document_metadata_options = [
            {
                'document_type': doc['document_type'],
                'document_metadata':  dict_keys_remove_special_character(doc['document_metadata']) if doc.get('document_metadata') else None,
                'index': doc_index +1,
                'selected': True,
                'selection_label': f'Metadata of {doc["document_type"]}'
            }
            for doc_index, doc in enumerate(self.identity_data) if doc.get('document_metadata')
        ]
        self.document_tables_options = []
        self.init_document_tables_options()
        self.output_data = []
        self.file_name = file_name
        self.if_append_doc_tables_prompt = False

    def init_document_tables_options(self):
        index = 0
        for doc_index, doc in enumerate(self.identity_data):
            if doc.get('document_tables'):
                for table in doc['document_tables']:
                    index += 1
                    self.document_tables_options.append({
                        'document_type': doc['document_type'],
                        'table_name': table['table_name'],
                        "table_schema": convert_list_of_dict_to_dict_nested_list(table["table_schema"]),
                        'index': index,
                        'selected': False,
                        'selection_label': f"{index} - {doc['document_type']} - {table['table_name']}"
                    })

    # def update_output_data(self):
    #     self.output_data = [
    #         {
    #             "document_type": doc_data["document_type"],
    #             "document_metadata": reset_dict_value(doc_data["document_metadata"]),
    #             "document_tables": [
    #                 {
    #                     "table_name": table["table_name"],
    #                     "document_table": reset_nested_list_value(convert_dict_value_to_nested_list(table["table_schema"]))
    #                 }
    #                 for table in doc_data["document_tables"] if table["selected"]
    #             ],
    #             "file_identifier": ""
    #         }
    #         for doc_data in self.identity_data_selection
    #     ]

    def update_output_data(self):
        # print(f"document_metadata_options -> {self.document_metadata_options} \n document_tables_options -> {self.document_tables_options}")
        self.output_data = [
            {
                "document_type": d['document_type']
            }
            for d in self.identity_data
        ]
        # print(f"init self.output_data - {self.output_data}")
        for document_metadata_option in self.document_metadata_options:
            if document_metadata_option['selected']:
                matching_doc = next(
                    (doc for doc in self.output_data if doc.get('document_type') == document_metadata_option['document_type']),
                    None
                )
                if matching_doc:
                    matching_doc['document_metadata'] = reset_dict_value(document_metadata_option["document_metadata"])
                # else:
                #     matching_doc = {
                #         'document_type': document_metadata_option['document_type'],
                #         'document_metadata': reset_dict_value(document_metadata_option["document_metadata"])
                #     }
                #     self.output_data.append(matching_doc)

        self.if_append_doc_tables_prompt = False
        for document_table_option in self.document_tables_options:
            if document_table_option['selected']:
                matching_doc = next(
                    (doc for doc in self.output_data if doc.get('document_type') == document_table_option['document_type']),
                    None
                )
                if matching_doc:
                    if not matching_doc.get('document_tables'):
                        matching_doc['document_tables'] = []
                    document_tables: list = matching_doc['document_tables']
                    document_tables.append(
                        {
                            'table_name': document_table_option['table_name'],
                            'document_table': reset_nested_list_value(
                                convert_dict_value_to_nested_list(document_table_option["table_schema"]))
                        }
                    )
                    self.if_append_doc_tables_prompt = True
        self.output_data = [doc_data for doc_data in self.output_data if doc_data.get('document_metadata') or doc_data.get('document_tables')]


    def get_output_json(self):
        return json.dumps(self.output_data, separators=(',', ':'))

    def get_output_prompt_with_json(self):
        return self.get_output_json() + str(PROMPT_CUSTOMIZE_FOOTER_DOC_TABLES_V0 if self.if_append_doc_tables_prompt else "")

