class EmailNotificationTool:
    def __init__(self):
        self.url = CUSTOM_BOT_NOTIFICATION_API

    def execute(self, params):
        """
        执行邮件通知请求
        params: {
            "email_recipients": str 或 list, # USER,OWNER,或指定邮件地址列表
            或者
            "role": str, # OpenAI Assistant可能使用role参数代替email_recipients
            "email_html_content": str,
            "email_subject": str (可选),
            "attach_file": bool (可选)
        }

        注意：assistant_id, request_by_id 和 thread_id 将从当前 OpenAI 会话中获取
        """

        # 验证必需的参数都存在且不为空
        if not params.get("email_recipients"):
            raise ValueError("Missing required parameter: email_recipients")

        if not params.get("email_html_content"):
            raise ValueError("Missing required parameter: email_html_content")



        # 简化处理，如果 attach_file 不存在或为 None，设置为 False
        if "attach_file" not in params or params["attach_file"] is None:
            params["attach_file"] = False   

        # 从调用栈中获取 LFAssistantEventHandler 实例
        handler = self._get_event_handler_from_stack()
        if not handler:
            raise ValueError("Could not find LFAssistantEventHandler in the call stack")

        # 从 handler 中获取 OpenaiClientAssistant 实例
        try:
            openai_client_assistant = handler.openai_client_assistant
            if not openai_client_assistant:
                raise ValueError("handler.openai_client_assistant is empty")

            assistant_id = openai_client_assistant.assistant_id
            if not assistant_id:
                print(f"\n[error] assistant_id is empty")

            thread_id = openai_client_assistant.thread_id
            if not thread_id:
                print(f"\n[warning] thread_id is empty")
        except AttributeError as e:
            print(f"\n[error] An error occurred when obtaining information about OpenAI Assistant: {str(e)}")
            raise ValueError(f"An error occurred when obtaining information about OpenAI Assistant: {str(e)}")

        # 获取用户ID
        try:
            user_id = self._get_user_id_from_handler(handler)
            if not user_id:
                raise ValueError("The user ID cannot be obtained")
            else:
                print(f"\n[Information] Obtained the user ID: {user_id}")
        except Exception as e:
            print(f"\n[Error] An exception occurred when obtaining the user ID: {str(e)}")
            raise

        if not assistant_id:
            print("\n[Error] assistant_id cannot be obtained in the current OpenAI session")
            raise ValueError("assistant_id cannot be obtained in the current OpenAI session")

        print(f'Email Notification Tool - Sending email notification, assistant_id: {assistant_id}, thread_id: {thread_id}, user_id: {user_id}')

        # 准备表单数据
        form_data = {
            "assistant_id": assistant_id,
            "request_by_id": user_id,
            "email_recipients": params["email_recipients"],
            "email_html_content": params["email_html_content"],
            "thread_id": thread_id,
            # 确保 attach_file 始终存在于请求中，始终使用字符串 'true' 或 'false'
            "attach_file": "true" if params["attach_file"] else "false"
        }

        # 添加可选参数
        if thread_id:
            form_data["thread_id"] = thread_id

        if params.get("email_subject"):
            form_data["email_subject"] = params["email_subject"]

        print(f'表单数据: {json.dumps(form_data, ensure_ascii=False, indent=2)}')

        # 设置请求头
        headers = {
            'Ocp-Apim-Subscription-Key': "eb4e8f7e6e24450aa333701367833040"
        }
        print(f'Request headers: {json.dumps(headers, ensure_ascii=False, indent=2)}')
        print(f'Request URL: {self.url}')

        # 发送请求使用表单数据
        try:
                # 普通请求，无文件上传
            response = requests.post(
                self.url,
                data=form_data,  # 使用 data 而不是 json
                headers=headers,
                timeout=40,
                verify=False  # 禁用SSL验证，避免证书问题
            )
        except requests.exceptions.RequestException as e:
            print(f"Error sending request: {str(e)}")
            raise
        print(f'Response status code: {response.status_code}')
        print(f'Response content: {response.text}')
        response.raise_for_status()

        return {
            "success": True,
            "status_code": response.status_code,
            "response": response.json() if response.text else None
        }

    def _get_event_handler_from_stack(self):
        """
        从调用栈中获取 LFAssistantEventHandler 实例
        """
        frame = None
        try:
            # 获取当前调用栈
            for frame_info in inspect.stack():
                frame = frame_info.frame
                # 检查局部变量中是否有 self
                if 'self' in frame.f_locals:
                    instance = frame.f_locals['self']
                    # 检查实例的类名是否为 LFAssistantEventHandler
                    if instance.__class__.__name__ == 'LFAssistantEventHandler':
                        return instance
        finally:
            del frame
        return None

    def _get_user_id_from_handler(self, handler):
        """
        从 LFAssistantEventHandler 实例中获取用户ID
        """
        try:
            # 尝试从 session_state 中获取用户ID
            import streamlit as st
            if 'userId' in st.session_state:
                return st.session_state.userId

            # 如果 handler 中有用户信息，也可以从那里获取
            if hasattr(handler, 'user_id') and handler.user_id:
                return handler.user_id

            # 如果 handler 有 openai_client_assistant，尝试从那里获取
            if hasattr(handler, 'openai_client_assistant'):
                client = handler.openai_client_assistant
                if hasattr(client, 'user_id') and client.user_id:
                    return client.user_id
            # 如果都没有，返回一个默认值
            return "default_user_id"
        except Exception as e:
            return "default_user_id"

