class FirecrawlSearchTool(BaseTool):
    """Firecrawl搜索工具 - 可以搜索网络并可选择性地抓取搜索结果内容"""

    def __init__(self):
        self.firecrawl_api_key = FIRECRAWL_API_KEY
        if not self.firecrawl_api_key:
            print("Warning: FIRECRAWL_API_KEY not set in environment variables")
        self.app = None  # 延迟初始化

    def execute(self, params: Dict[str, Any]) -> Dict[str, Any]:
        """执行网络搜索
        Args:
            params: 包含搜索参数的字典
                - query: 搜索查询词（必需）
                - limit: 返回结果数量限制（默认5）
                - scrape_content: 是否抓取搜索结果内容（默认False）
                - formats: 内容格式列表，当scrape_content为True时生效（默认["markdown"]）
                - lang: 搜索语言（如"zh", "en", "de"等）
                - country: 搜索国家（如"cn", "us", "de"等）
                - tbs: 时间过滤（如"qdr:w"表示过去一周）
                - timeout: 超时时间，毫秒（默认30000）
        Returns:
            搜索结果字典
        """
        if not self.firecrawl_api_key:
            return {
                "error": "FIRECRAWL_API_KEY not set. Please configure the API key in environment variables.",
                "success": False
            }

        try:
            # 获取必需参数
            query = params.get("query")
            if not query:
                return {
                    "error": "Search query is required",
                    "success": False
                }

            # 延迟初始化FirecrawlApp
            if self.app is None:
                try:
                    self.app = FirecrawlApp(api_key=self.firecrawl_api_key)
                except Exception as e:
                    return {
                        "error": f"Failed to initialize FirecrawlApp: {str(e)}",
                        "success": False
                    }

            # 获取可选参数
            limit = params.get("limit", 5)
            scrape_content = params.get("scrape_content", False)
            formats = params.get("formats", ["markdown"])
            lang = params.get("lang")
            country = params.get("country")
            tbs = params.get("tbs")
            timeout = params.get("timeout", 30000)

            print(f"FirecrawlSearchTool - searching for: {query}")
            print(f"Parameters: limit={limit}, scrape_content={scrape_content}, formats={formats}")

            # 构建搜索参数 - 使用params字典方式
            search_params = {
                "limit": limit
            }

            # 添加可选参数
            if lang:
                search_params["lang"] = lang
            if country:
                search_params["country"] = country
            if tbs:
                search_params["tbs"] = tbs
            if timeout:
                search_params["timeout"] = timeout

            # 如果需要抓取内容，添加抓取选项
            if scrape_content:
                if HAS_SCRAPE_OPTIONS:
                    search_params["scrape_options"] = ScrapeOptions(formats=formats)
                else:
                    # 使用字典方式传递抓取选项
                    search_params["scrape_options"] = {"formats": formats}

            # 执行搜索 - 使用params参数
            search_result = self.app.search(query, params=search_params)

            # 添加调试信息
            # print(f"Raw search result type: {type(search_result)}")
            # print(f"Raw search result: {search_result}")

            # 处理结果 - 改进检查逻辑
            if not search_result:
                return {
                    "error": "No search results returned (search_result is None)",
                    "success": False
                }

            # 检查不同的数据结构
            data = None
            if hasattr(search_result, 'data'):
                data = search_result.data
            elif isinstance(search_result, dict) and 'data' in search_result:
                data = search_result['data']
            elif isinstance(search_result, list):
                data = search_result
            else:
                return {
                    "error": f"Unexpected search result format: {type(search_result)}",
                    "success": False,
                    "raw_result": str(search_result)
                }

            if not data:
                return {
                    "error": "No data in search results",
                    "success": False,
                    "raw_result": str(search_result)
                }

            results = []
            for result in data:
                processed_result = {
                    "title": result.get("title", ""),
                    "url": result.get("url", ""),
                    "description": result.get("description", "")
                }

                # 如果抓取了内容，添加内容字段
                if scrape_content:
                    if "markdown" in formats and "markdown" in result:
                        processed_result["markdown"] = result["markdown"]
                    if "html" in formats and "html" in result:
                        processed_result["html"] = result["html"]
                    if "rawHtml" in formats and "rawHtml" in result:
                        processed_result["rawHtml"] = result["rawHtml"]
                    if "links" in formats and "links" in result:
                        processed_result["links"] = result["links"]
                    if "screenshot" in formats and "screenshot" in result:
                        processed_result["screenshot"] = result["screenshot"]
                    if "screenshot@fullPage" in formats and "screenshot@fullPage" in result:
                        processed_result["screenshot@fullPage"] = result["screenshot@fullPage"]
                    if "extract" in formats and "extract" in result:
                        processed_result["extract"] = result["extract"]

                    # 添加元数据
                    if "metadata" in result:
                        processed_result["metadata"] = result["metadata"]

                results.append(processed_result)

            print(f"Found {len(results)} search results")

            # 构建最终响应
            final_response = {
                "success": True,
                "query": query,
                "total_results": len(results),
                "results": results,
                "scrape_content": scrape_content,
                "formats": formats if scrape_content else None
            }

            print(f"Search completed successfully: {len(results)} results")
            return final_response

        except Exception as e:
            print(f"Error in FirecrawlSearchTool: {str(e)}")
            return {
                "error": f"Search failed: {str(e)}",
                "success": False
            }

