class FirecrawlTool(BaseTool):
    def __init__(self):
        self.firecrawl_api_key = FIRECRAWL_API_KEY
        if not self.firecrawl_api_key:
            print("Warning: FIRECRAWL_API_KEY not set in environment variables")
        self.app = None  # 延迟初始化

    def execute(self, params: Dict[str, Any]) -> Dict[str, Any]:
        """执行网页内容抓取
        Args:
            params: 包含参数的字典
                - url: 要抓取的单个网页URL
                - urls: 要抓取的多个网页URL列表（优先于url参数）
        Returns:
            抓取结果字典
        """
        if not self.firecrawl_api_key:
            return {
                "error": "FIRECRAWL_API_KEY not set. Please configure the API key in environment variables.",
                "success": False
            }

        try:
            urls = params.get("urls", [])
            if not urls:
                url = params.get("url")
                if url:
                    urls = [url]
                else:
                    return {
                        "error": "Either 'url' or 'urls' parameter is required",
                        "success": False
                    }

            # 延迟初始化FirecrawlApp
            if self.app is None:
                try:
                    self.app = FirecrawlApp(api_key=self.firecrawl_api_key)
                except Exception as e:
                    return {
                        "error": f"Failed to initialize FirecrawlApp: {str(e)}",
                        "success": False
                    }

            print(f"FirecrawlTool - scrape_urls {urls}")

            all_results = []
            for url in urls:
                try:
                    # 配置抓取选项
                    data = self.app.scrape_url(url, {
                        'formats': ['json'],
                        'jsonOptions': {
                            'schema': {
                                "type": "object",
                                "properties": {
                                    "title": {"type": "string", "description": "The title of the webpage"},
                                    "content": {"type": "string", "description": "The main content of the webpage"},
                                    "author": {"type": "string", "description": "Author of the article if available"},
                                    "date": {"type": "string", "description": "Publication date if available"}
                                },
                                "required": ["title", "content"]
                            }
                        }
                    })

                    if "json" not in data:
                        print(f"Warning: No content could be extracted from URL: {url}")
                        continue

                    # 提取结构化数据
                    extracted_data = data["json"]

                    # 构建单个URL的响应
                    response = {
                        "url": url,
                        "title": extracted_data.get("title", "No title found"),
                        "content": extracted_data.get("content", "No content found"),
                        "author": extracted_data.get("author", "Author not found"),
                        "date": extracted_data.get("date", "Date not found")
                    }

                    print(f"\n=== Raw Data for {url} ===")
                    print(f"Original JSON data: {data['json']}")
                    print(f"\n=== Processed Response for {url} ===")
                    print(f"Title: {response['title']}")
                    print(f"Author: {response['author']}")
                    print(f"Date: {response['date']}")
                    print(f"Content: {response['content'][:2000]}..." if len(response['content']) > 2000 else f"Content: {response['content']}")

                    all_results.append(response)

                except Exception as e:
                    print(f"Error processing URL {url}: {str(e)}")
                    all_results.append({
                        "url": url,
                        "error": str(e),
                        "success": False
                    })

            # 构建最终响应
            final_response = {
                "results": all_results,
                "success": len(all_results) > 0,
                "total_urls": len(urls),
                "successful_urls": len([r for r in all_results if "error" not in r])
            }

            print("\n=== Final Response ===")
            print(f"Total URLs: {final_response['total_urls']}")
            print(f"Successful URLs: {final_response['successful_urls']}")
            print("Success:", final_response['success'])

            return final_response

        except Exception as e:
            return {
                "error": f"Failed to extract content: {str(e)}",
                "success": False
            }

