class GoogleFileSearchTool(BaseTool):
    """Google File Search — native File Search Store integration.

    Uses Google File Search Store API for semantic retrieval:
    - Files are pre-uploaded and indexed in a File Search Store
    - Queries are answered by Gemini using native FileSearch tool
    """

    MODEL = "gemini-2.5-flash-lite"

    def __init__(self):
        self.client = genai.Client(api_key=os.environ.get("GEMINI_API_KEY"))

    # ── Store lifecycle helpers ──────────────────────────────────

    def create_store(self, display_name: str) -> str:
        """Create a new File Search Store and return its resource name."""
        store = self.client.file_search_stores.create(
            config={"display_name": display_name}
        )
        print(f"[GoogleFileSearch] Created store: {store.name}")
        return store.name

    def upload_file(self, store_name: str, file_path: str, display_name: str = None):
        """Upload a file to the File Search Store (blocks until indexing completes)."""
        config = {}
        if display_name:
            config["display_name"] = display_name

        operation = self.client.file_search_stores.upload_to_file_search_store(
            file=file_path,
            file_search_store_name=store_name,
            config=config,
        )
        # Poll until the upload + indexing operation completes
        while not operation.done:
            time.sleep(2)
            operation = self.client.operations.get(operation)

        print(f"[GoogleFileSearch] Uploaded file to {store_name}: {display_name or file_path}")
        return operation

    def upload_file_bytes(self, store_name: str, file_bytes, file_name: str):
        """Upload in-memory file bytes to the File Search Store.

        Writes to a temp file first since the SDK expects a file path.
        """
        import os
        import tempfile

        suffix = os.path.splitext(file_name)[1] if file_name else ""
        with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
            if hasattr(file_bytes, "getvalue"):
                # Streamlit UploadedFile — always returns full content
                tmp.write(file_bytes.getvalue())
            elif hasattr(file_bytes, "read"):
                # Reset position first in case another reader consumed it
                if hasattr(file_bytes, "seek"):
                    file_bytes.seek(0)
                tmp.write(file_bytes.read())
            else:
                tmp.write(file_bytes)
            tmp_path = tmp.name

        try:
            return self.upload_file(store_name, tmp_path, display_name=file_name)
        finally:
            try:
                os.unlink(tmp_path)
            except OSError:
                pass

    def delete_document(self, document_name: str):
        """Delete a document from its File Search Store."""
        self.client.file_search_stores.documents.delete(
            name=document_name,
            config={"force": True}
        )
        print(f"[GoogleFileSearch] Deleted document: {document_name}")

    def list_documents(self, store_name: str):
        """List all documents in a File Search Store."""
        return list(self.client.file_search_stores.documents.list(parent=store_name))

    def delete_store(self, store_name: str):
        """Delete a File Search Store (force=True to delete even with documents)."""
        self.client.file_search_stores.delete(name=store_name, config={"force": True})
        print(f"[GoogleFileSearch] Deleted store: {store_name}")

    # ── Main execute (called from OpenAI function tool) ──────────

    def execute(self, params: Dict[str, Any]) -> Dict[str, Any]:
        query = (params or {}).get("query")
        if not query:
            return {"success": False, "message": "query cannot be empty"}

        store_name = (params or {}).get("google_file_search_store_name")
        if not store_name:
            # Fallback: look up from DB via assistant_id
            assistant_id = (params or {}).get("assistant_id")
            if assistant_id:
                store_name = self._get_store_name_from_db(assistant_id)

        if not store_name:
            return {
                "success": False,
                "message": "No Google File Search Store configured for this bot. "
                           "Please upload files in the Config page first."
            }

        try:
            # 包装 query 为明确的指令，帮助 Gemini 更好地利用 File Search Store
            prompt = (
                f"Based on the documents in the knowledge base, answer the following question:\n\n"
                f"{query}\n\n"
                f"If the question asks to list, summarize, or describe all files/documents, "
                f"search broadly and provide a comprehensive summary of all available content. "
                f"Always include specific details, data, and key information found in the documents."
            )
            response = self.client.models.generate_content(
                model=self.MODEL,
                contents=prompt,
                config=types.GenerateContentConfig(
                    tools=[
                        types.Tool(
                            file_search=types.FileSearch(
                                file_search_store_names=[store_name]
                            )
                        )
                    ],
                    safety_settings=SAFETY_SETTINGS,
                    temperature=0.3,
                ),
            )
            answer = getattr(response, "text", "") or ""
            if not answer:
                answer = ("No relevant information found in the uploaded files. "
                          "Please try rephrasing your question.")
            return {"success": True, "answer": answer}
        except Exception as e:
            print(f"[GoogleFileSearch] query error: {e}")
            return {
                "success": False,
                "message": f"Error during Google File Search: {e}"
            }

    def _get_store_name_from_db(self, assistant_id: str) -> str | None:
        try:
            from database.repository.custom_bot import retrieve_assistant_by_id
            bot = retrieve_assistant_by_id(assistant_id)
            if bot:
                return getattr(bot, "google_file_search_store_name", None)
        except Exception as e:
            print(f"[GoogleFileSearch] DB lookup error: {e}")
        return None

