class GoogleSearchTool(BaseTool):
    """使用Gemini 2.5 Flash模型的Google搜索工具"""

    def __init__(self):
        """初始化Google搜索工具"""
        # genai.configure(api_key=GEMINI_API_KEY)
        self.GEMINI_MODEL = "gemini-2.5-flash"

    def execute(self, params: Dict[str, Any]) -> Dict[str, Any]:
        """执行Google搜索，使用Gemini 2.5 Flash模型

        Args:
            params: 包含搜索参数的字典
                - query: 搜索查询

        Returns:
            搜索结果字典，包含以下字段：
            - success: 布尔值，表示请求是否成功
            - results: 成功时返回的结果
            - error: 失败时的错误信息
        """
        try:
            # 获取查询内容
            query = params.get("query")
            if not query:
                return {
                    "success": False,
                    "error": "Search query cannot be empty"
                }


            response = generate_content(prompt=query, model=self.GEMINI_MODEL, google_search=True)

            # generate_content returns a string directly
            if response and isinstance(response, str):
                result = {
                    "content": response,
                    "model": self.GEMINI_MODEL,
                    "query": query
                }

                return {
                    "success": True,
                    "results": result
                }
            else:
                return {
                    "success": False,
                    "error": "The model did not return a valid response"
                }

        except Exception as e:
            # 捕获错误
            print(f"Error in google_search tool (Gemini): {str(e)}")

            return {
                "success": False,
                "error": f"Error fetching data from Gemini API: {str(e)}"
            }

