class SharepointUploadFile:
    # from utils.openai_utils import OpenaiClientAssistant
    def __init__(self):
        self.url = CUSTOM_BOT_SHAREPOINT_UPLOAD_API

    def execute(self, params):
        """
        执行Sharepoint文件上传请求
        params: {
            "user_id": str,
            "thread_id": str,
            "assistant_id": str,
            "file_ids": list[str]
        }
        """
        # 验证所有必需的参数都存在且不为空
        required_params = ["user_id", "thread_id", "assistant_id", "file_ids"]
        for param in required_params:
            if not params.get(param):
                raise ValueError(f"Missing required parameter: {param}")

        # 验证file_ids是列表类型
        if not isinstance(params["file_ids"], list):
            raise ValueError("file_ids must be a list")

        print(f'Sharepoint Tool - File(s) {params["file_ids"]} upload, request by: {params["user_id"]}, assistant_id: {params["assistant_id"]}, thread_id: {params["thread_id"]}')

        response = requests.post(
            self.url,
            json={  # POST body参数
                "user_id": params["user_id"],
                "thread_id": params["thread_id"],
                "assistant_id": params["assistant_id"],
                "file_ids": params["file_ids"]
            },
            timeout=20
        )
        response.raise_for_status()

        return {
            "success": True,
            "status_code": response.status_code,
            "response": response.json() if response.text else None
        }

